import React, { useState, useEffect, useMemo } from 'react';
import { SeasonSettings, Race, DriverStanding, ConstructorStanding, RaceResult, Driver, Team, QualifyingResult, RaceState, TyreCompound, WeatherCondition, NewsArticle, QualifyingData, SeasonHistory, EngineSupplier, Country } from '../types';
import StandingsTable from './StandingsTable';
import RaceResultModal from './RaceResultModal';
import LiveRaceView from './LiveRaceView';
import PreRaceStrategyScreen from './PreRaceStrategyScreen';
import StopwatchIcon from './icons/StopwatchIcon';
import HomeIcon from './icons/HomeIcon';
import CalendarIcon from './icons/CalendarIcon';
import SpeedControl from './SpeedControl';
import Podium from './Podium';
import FloppyDiskIcon from './icons/FloppyDiskIcon';
import ChartsView from './ChartsView';
import ChampionCelebration from './ChampionCelebration';
import { useI18n } from '../i18n';
import ProfileModal from './ProfileModal';
import QualifyingInProgressScreen from './QualifyingInProgressScreen';
import SpinnerIcon from './icons/SpinnerIcon';
import PlayIcon from './icons/PlayIcon';
import ForwardIcon from './icons/ForwardIcon';
import HistoryScreen from './HistoryScreen';
import TeamManagementPanel from './TeamManagementPanel';
import UserIcon from './icons/UserIcon';
import CountryFlag from './CountryFlag';


const NewsPanel: React.FC<{ news: NewsArticle[], drivers: Driver[], teams: Team[] }> = ({ news, drivers, teams }) => {
    const { t } = useI18n();
    const [expandedArticleId, setExpandedArticleId] = useState<string | null>(null);

    useEffect(() => {
        if (news.length > 0) {
            setExpandedArticleId(news[news.length - 1].id);
        }
    }, [news]);

    const toggleArticle = (id: string) => {
        setExpandedArticleId(prevId => (prevId === id ? null : id));
    };

    const sortedNews = [...news].reverse();

    const entities = useMemo(() => {
        const allEntities = [
            ...drivers.map(d => {
                const team = teams.find(t => t.id === d.teamId);
                return { name: d.name, color: team?.primaryColor || '#FFFFFF', accent: team?.accentColor || '#FFFFFF' };
            }),
            ...teams.map(t => ({ name: t.name, color: t.primaryColor, accent: t.accentColor }))
        ];
        allEntities.sort((a, b) => b.name.length - a.name.length);
        return allEntities;
    }, [drivers, teams]);

    const renderHighlightedBody = (text: string) => {
        if (!text) return '';
        const regex = new RegExp(`(${entities.map(e => e.name.replace(/[-\/\\^$*+?.()|[\]{}]/g, '\\$&')).join('|')})`, 'g');
        const parts = text.split(regex);

        return parts.map((part, index) => {
            const entity = entities.find(e => e.name === part);
            if (entity) {
                const hex = entity.color.replace('#', '');
                if (hex.length < 6) return <span key={index}>{part}</span>;
                const r = parseInt(hex.substring(0, 2), 16);
                const g = parseInt(hex.substring(2, 4), 16);
                const b = parseInt(hex.substring(4, 6), 16);
                const brightness = (r * 299 + g * 587 + b * 114) / 1000;

                const style: React.CSSProperties = {
                    color: entity.color,
                    fontWeight: 'bold',
                    textShadow: brightness < 70 ? `0 0 8px ${entity.accent === '#000000' ? '#FFFFFF' : entity.accent}` : 'none',
                };
                return <span key={index} style={style}>{part}</span>;
            }
            return <React.Fragment key={index}>{part}</React.Fragment>;
        });
    };

    if (news.length === 0) {
        return (
            <div className="text-center py-10">
                <p className="text-slate-400">{t('news_noNews')}</p>
            </div>
        )
    }

    const TRUNCATE_LENGTH = 250;

    return (
        <div className="space-y-4">
            {sortedNews.map(article => {
                const isExpanded = expandedArticleId === article.id;
                const isLong = article.body.length > TRUNCATE_LENGTH;

                const bodyContent = isLong && !isExpanded
                    ? `${article.body.substring(0, TRUNCATE_LENGTH)}...`
                    : article.body;

                return (
                    <div key={article.id} className="bg-slate-500/10 rounded-lg overflow-hidden p-4 animate-fade-in">
                        <p className="text-xs text-slate-400 uppercase">{article.date}</p>
                        <h4 className="font-bold text-lg text-slate-200 mb-2">{article.headline}</h4>
                        <p className="text-slate-300 whitespace-pre-line">
                            {renderHighlightedBody(bodyContent)}
                        </p>
                        {isLong && (
                            <button
                                onClick={() => toggleArticle(article.id)}
                                className="text-sm font-bold mt-2 text-[#00e051] hover:text-green-300 transition-colors"
                            >
                                {isExpanded ? t('readLess') : t('readMore')}
                            </button>
                        )}
                    </div>
                );
            })}
        </div>
    );
};


interface SimulationScreenProps {
  settings: SeasonSettings;
  currentRaceIndex: number;
  calendar: Race[];
  drivers: Driver[];
  teams: Team[];
  engineSuppliers: EngineSupplier[];
  customCountries: Country[];
  setTeams: React.Dispatch<React.SetStateAction<Team[]>>;
  driverStandings: DriverStanding[];
  constructorStandings: ConstructorStanding[];
  lastRaceResults: RaceResult[] | null;
  allRaceResults: RaceResult[][];
  allQualifyingResults: QualifyingResult[][];
  qualifyingResults: QualifyingResult[] | null;
  qualifyingData: QualifyingData | null;
  news: NewsArticle[];
  history: SeasonHistory[];
  onSimulateQualifying: () => void;
  onSimulateWeekend: () => void;
  onSimulateSeason: () => void;
  onStopSeasonSim: () => void;
  isSeasonSimRunning: boolean;
  onStartRace: (strategies: { driverId: number; startingTyre: TyreCompound }[], startingWeather: WeatherCondition) => void;
  isLoading: boolean;
  error: string | null;
  onBackToMenu: () => void;
  onEndSeason: () => void;
  simulationStatus: 'idle' | 'qualifying' | 'pre-race' | 'race' | 'finished';
  raceState: RaceState | null;
  raceHistory: RaceState[];
  simulationSpeed: number;
  onSetSimulationSpeed: (speed: number) => void;
  isPaused: boolean;
  onPauseToggle: () => void;
  commentary: string;
  onSaveSimulation: () => void;
  determinedWeather: WeatherCondition | null;
}

const SimulationScreen: React.FC<SimulationScreenProps> = ({
  settings,
  currentRaceIndex,
  calendar,
  drivers,
  teams,
  engineSuppliers,
  customCountries,
  setTeams,
  driverStandings,
  constructorStandings,
  lastRaceResults,
  allRaceResults,
  allQualifyingResults,
  qualifyingResults,
  qualifyingData,
  news,
  history,
  onSimulateQualifying,
  onSimulateWeekend,
  onSimulateSeason,
  onStopSeasonSim,
  isSeasonSimRunning,
  onStartRace,
  isLoading,
  error,
  onBackToMenu,
  onEndSeason,
  simulationStatus,
  raceState,
  raceHistory,
  simulationSpeed,
  onSetSimulationSpeed,
  isPaused,
  onPauseToggle,
  commentary,
  onSaveSimulation,
  determinedWeather,
}) => {
  const { t } = useI18n();
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [activeContentKey, setActiveContentKey] = useState(simulationStatus);
  const [isFading, setIsFading] = useState(false);
  const [podiumData, setPodiumData] = useState<RaceResult[] | null>(null);
  const [activeView, setActiveView] = useState<'standings' | 'myTeam' | 'news' | 'charts' | 'history'>('standings');
  const [championData, setChampionData] = useState<{ driverChampion: { driver: Driver, team: Team }, constructorChampion: Team } | null>(null);
  const [selectedProfile, setSelectedProfile] = useState<{ id: number; type: 'driver' | 'constructor' } | null>(null);

  const seasonOver = currentRaceIndex >= calendar.length;
  const currentRace = calendar[currentRaceIndex];
  const isOwnerMode = settings.mode === 'owner';
  const playerTeam = teams.find(t => t.id === settings.playerTeamId);

    const handleOpenProfile = (id: number, type: 'driver' | 'constructor') => {
        setSelectedProfile({ id, type });
    };

    const handleCloseProfile = () => {
        setSelectedProfile(null);
    };

    const handleUpgradeFacility = (facility: keyof Team['facilities']) => {
        if (!playerTeam) return;

        const level = playerTeam.facilities[facility];
        const cost = (level + 1) * 2; // Example cost formula

        if (playerTeam.budget >= cost) {
            if (window.confirm(t('confirm_upgrade_facility', { name: t(`facility_${facility}`), cost, level: level + 1 }))) {
                setTeams(prevTeams => prevTeams.map(t => {
                    if (t.id === playerTeam.id) {
                        return {
                            ...t,
                            budget: t.budget - cost,
                            facilities: {
                                ...t.facilities,
                                [facility]: t.facilities[facility] + 1
                            }
                        };
                    }
                    return t;
                }));
            }
        } else {
            alert(t('error_insufficient_funds'));
        }
    };


  useEffect(() => {
    if (lastRaceResults && simulationStatus === 'finished') {
      setIsModalOpen(true);
      const topThree = lastRaceResults
        .filter(r => r.position > 0 && r.position <= 3)
        .sort((a, b) => a.position - b.position);
      setPodiumData(topThree);
    }
  }, [lastRaceResults, simulationStatus]);

    useEffect(() => {
        if (seasonOver && simulationStatus === 'finished' && !isModalOpen && !podiumData && !championData && driverStandings.length > 0) {
            const driverChampId = driverStandings[0].driverId;
            const driver = drivers.find(d => d.id === driverChampId)!;
            const team = teams.find(t => t.id === driver.teamId)!;
            const constructorChamp = teams.find(t => t.id === constructorStandings[0].teamId)!;

            setChampionData({
                driverChampion: { driver, team },
                constructorChampion: constructorChamp,
            });
        }
    }, [seasonOver, simulationStatus, isModalOpen, podiumData, driverStandings, constructorStandings, drivers, teams, championData]);


  useEffect(() => {
    if (simulationStatus !== activeContentKey) {
        setIsFading(true);
        const timer = setTimeout(() => {
            setActiveContentKey(simulationStatus);
            setIsFading(false);
        }, 300);
        return () => clearTimeout(timer);
    }
  }, [simulationStatus, activeContentKey]);

  const handlePodiumContinue = () => {
    setPodiumData(null);
  };

  const handleBackFromStrategy = () => {
      onSetSimulationSpeed(1);
      setActiveContentKey(lastRaceResults ? 'finished' : 'idle');
  };

  const renderIdleContent = () => {
      if (podiumData || championData) return null; 
      return (
        <>
            <div className="flex border-b border-slate-700 mb-4">
                <button onClick={() => setActiveView('standings')} className={`px-4 py-2 font-bold uppercase text-sm ${activeView === 'standings' ? 'border-b-2 border-[#00e051] text-white' : 'text-slate-400'}`}>{t('standings')}</button>
                {isOwnerMode && <button onClick={() => setActiveView('myTeam')} className={`px-4 py-2 font-bold uppercase text-sm flex items-center gap-2 ${activeView === 'myTeam' ? 'border-b-2 border-[#00e051] text-white' : 'text-slate-400'}`}><UserIcon className="w-5 h-5" />{t('myTeam')}</button>}
                <button onClick={() => setActiveView('news')} className={`px-4 py-2 font-bold uppercase text-sm ${activeView === 'news' ? 'border-b-2 border-[#00e051] text-white' : 'text-slate-400'}`}>{t('news')}</button>
                <button onClick={() => setActiveView('charts')} className={`px-4 py-2 font-bold uppercase text-sm ${activeView === 'charts' ? 'border-b-2 border-[#00e051] text-white' : 'text-slate-400'}`}>{t('charts')}</button>
                {history.length > 0 && <button onClick={() => setActiveView('history')} className={`px-4 py-2 font-bold uppercase text-sm ${activeView === 'history' ? 'border-b-2 border-[#00e051] text-white' : 'text-slate-400'}`}>{t('history_title')}</button>}
            </div>
            {activeView === 'standings' ? (
                 <div className="grid grid-cols-1 lg:grid-cols-2 gap-8">
                  <StandingsTable title={t('driversChampionship')} standings={driverStandings} type="driver" seasonOver={seasonOver} drivers={drivers} teams={teams} customCountries={customCountries} onRowClick={handleOpenProfile} />
                  <StandingsTable title={t('constructorsChampionship')} standings={constructorStandings} type="constructor" seasonOver={seasonOver} drivers={drivers} teams={teams} customCountries={customCountries} onRowClick={handleOpenProfile} />
                </div>
            ) : activeView === 'myTeam' && isOwnerMode && playerTeam ? (
                <TeamManagementPanel 
                    team={playerTeam}
                    drivers={drivers.filter(d => d.teamId === playerTeam.id)}
                    engineSupplier={engineSuppliers.find(e => e.name === playerTeam.engineSupplier)!}
                    onUpgradeFacility={handleUpgradeFacility}
                />
            ) : activeView === 'news' ? (
                <NewsPanel news={news} drivers={drivers} teams={teams} />
            ) : activeView === 'charts' ? (
                <ChartsView
                    raceHistory={raceHistory}
                    drivers={drivers}
                    teams={teams}
                    allRaceResults={allRaceResults}
                    allQualifyingResults={allQualifyingResults}
                    settings={settings}
                    calendar={calendar}
                    driverStandings={driverStandings}
                    customCountries={customCountries}
                />
            ) : activeView === 'history' ? (
                <HistoryScreen history={history} customCountries={customCountries} />
            ) : null}
        </>
      )
  };

  const renderContent = () => {
    if (simulationStatus === 'finished' && !isModalOpen && podiumData && podiumData.length > 0) {
      return (
        <Podium 
          results={podiumData}
          drivers={drivers}
          teams={teams}
          raceName={calendar[currentRaceIndex - 1]?.name || t('grandPrix')}
          onContinue={handlePodiumContinue}
        />
      );
    }

    if (seasonOver && championData) {
        return (
            <ChampionCelebration
                driverChampion={championData.driverChampion}
                constructorChampion={championData.constructorChampion}
                year={settings.startYear}
                onContinue={onEndSeason}
            />
        );
    }

    switch(activeContentKey) {
        case 'race':
            if (raceState) return <LiveRaceView race={currentRace} raceState={raceState} drivers={drivers} teams={teams} commentary={commentary} isPaused={isPaused} settings={settings} customCountries={customCountries} />;
            return null;
        case 'pre-race':
            return <PreRaceStrategyScreen
                qualifyingResults={qualifyingResults!}
                drivers={drivers}
                teams={teams}
                race={currentRace}
                onStartRace={onStartRace}
                weather={determinedWeather!}
                onBack={handleBackFromStrategy}
            />;
        case 'qualifying':
            return <QualifyingInProgressScreen
                qualifyingData={qualifyingData}
                drivers={drivers}
                teams={teams}
            />;
        case 'idle':
        case 'finished':
        default:
             return renderIdleContent();
    }
  }

  return (
    <div className="space-y-8">
      {lastRaceResults && qualifyingResults && simulationStatus === 'finished' && (
        <RaceResultModal
          isOpen={isModalOpen}
          onClose={() => setIsModalOpen(false)}
          raceResults={lastRaceResults}
          qualifyingResults={qualifyingResults}
          race={calendar[currentRaceIndex - 1]}
          drivers={drivers}
          teams={teams}
          settings={settings}
          customCountries={customCountries}
        />
      )}

      <ProfileModal
          isOpen={!!selectedProfile}
          onClose={handleCloseProfile}
          profileId={selectedProfile?.id}
          profileType={selectedProfile?.type}
          drivers={drivers}
          teams={teams}
          onSelectProfile={handleOpenProfile}
          allRaceResults={allRaceResults}
          allQualifyingResults={allQualifyingResults}
          customCountries={customCountries}
      />

      <div className="p-6 bg-[#1e1e2b]/80 border border-slate-700 rounded-2xl backdrop-blur-sm shadow-lg flex flex-col sm:flex-row justify-between items-center gap-4">
        <div>
            <h2 className="text-2xl font-bold text-slate-200 uppercase flex items-center gap-3">
               {!seasonOver && <CalendarIcon className="w-6 h-6" />}
               <span>{seasonOver ? t('seasonFinished') : t('nextRace')}</span>
            </h2>
            <p className="text-xl font-semibold text-white">
                {seasonOver ? t('congratsChampions', { year: settings.startYear }) : currentRace?.name}
            </p>
           {currentRace && !seasonOver && (
             <div className="flex items-center gap-2 text-slate-400 mt-1">
               <CountryFlag countryCode={currentRace.countryCode} customCountries={customCountries} className="w-5 h-auto rounded-sm" />
               <span>{t('raceInfo', { round: currentRaceIndex + 1, total: calendar.length, country: currentRace.country })}</span>
             </div>
           )}
        </div>
        <div className="flex flex-col sm:flex-row items-center gap-4">
            {['qualifying', 'race'].includes(simulationStatus) && !isSeasonSimRunning && (
              <SpeedControl currentSpeed={simulationSpeed} onSpeedChange={onSetSimulationSpeed} isPaused={isPaused} onPauseToggle={onPauseToggle} />
            )}
            {['idle', 'finished'].includes(simulationStatus) && !podiumData && !championData && (
                <div className="flex flex-col sm:flex-row items-center gap-4 w-full">
                    <button onClick={onBackToMenu} className="w-full sm:w-auto flex items-center justify-center gap-2 px-6 py-3 bg-slate-600/50 text-slate-200 font-bold uppercase rounded-lg shadow-md hover:bg-slate-500/50 transition-colors duration-300">
                        <HomeIcon className="w-5 h-5" /><span>{t('backToMenu')}</span>
                    </button>
                    {!seasonOver && (
                      <div className="w-full flex flex-col sm:flex-row gap-4">
                        <button onClick={onSaveSimulation} className="w-full sm:w-auto flex items-center justify-center gap-2 px-6 py-3 bg-blue-600/80 text-white font-bold uppercase rounded-lg shadow-md hover:bg-blue-600 transition-colors duration-300">
                            <FloppyDiskIcon className="w-5 h-5" /><span>{t('save')}</span>
                        </button>
                        <div className="flex-grow grid grid-cols-1 sm:grid-cols-2 gap-2">
                            <button onClick={onSimulateQualifying} disabled={isLoading} className="w-full flex items-center justify-center gap-2 px-4 py-3 bg-[#e00601] text-white font-bold uppercase rounded-lg shadow-md hover:bg-opacity-90 disabled:bg-slate-500/50 disabled:cursor-not-allowed transition-all duration-300">
                                <StopwatchIcon className="w-5 h-5" /><span>{t('simulateQualifying')}</span>
                            </button>
                             <div className="grid grid-cols-2 gap-2">
                                <button onClick={onSimulateWeekend} disabled={isLoading} className="w-full flex items-center justify-center gap-2 px-4 py-3 bg-slate-700 text-white font-bold uppercase rounded-lg shadow-md hover:bg-slate-600 disabled:bg-slate-500/50 disabled:cursor-not-allowed transition-all duration-300">
                                    <PlayIcon className="w-5 h-5" /><span>{t('simulateRaceWeek')}</span>
                                </button>
                                <button onClick={onSimulateSeason} disabled={isLoading} className="w-full flex items-center justify-center gap-2 px-4 py-3 bg-slate-700 text-white font-bold uppercase rounded-lg shadow-md hover:bg-slate-600 disabled:bg-slate-500/50 disabled:cursor-not-allowed transition-all duration-300">
                                    <ForwardIcon className="w-5 h-5" /><span>{t('simulateSeason')}</span>
                                </button>
                            </div>
                        </div>
                      </div>
                    )}
                </div>
            )}
        </div>
      </div>

       {isSeasonSimRunning && (
        <div className="p-4 bg-slate-900/80 border border-slate-700 text-slate-200 rounded-lg flex items-center justify-between animate-fade-in">
          <div className="flex items-center gap-3">
            <SpinnerIcon />
            <span className="font-bold">{t('simulatingSeason_progress', { round: currentRaceIndex + 1, total: calendar.length, raceName: currentRace?.name })}</span>
          </div>
          <button onClick={onStopSeasonSim} className="px-4 py-2 bg-red-600 text-white font-bold text-sm uppercase rounded-lg shadow-md hover:bg-red-500 transition-colors">{t('stop')}</button>
        </div>
       )}

       {error && (
        <div className="p-4 bg-[#e00601]/20 border border-[#e00601]/50 text-red-200 rounded-lg">
          <p><span className="font-bold">{t('error')}:</span> {error}</p>
        </div>
      )}

      <div className={`transition-all duration-300 ease-in-out ${isFading ? 'opacity-0 transform -translate-y-4' : 'opacity-100'}`}>
        {renderContent()}
      </div>

    </div>
  );
};

export default SimulationScreen;

import React from 'react';
import { DriverStanding, ConstructorStanding, Driver, Team, Country } from '../types';
import TrophyIcon from './icons/TrophyIcon';
import { getCountryByCode, getInitials } from '../utils';
import { useI18n } from '../i18n';
import ImageWithFallback from './ImageWithFallback';
import CountryFlag from './CountryFlag';

interface StandingsTableProps {
  title: string;
  standings: (DriverStanding[] | ConstructorStanding[]);
  type: 'driver' | 'constructor';
  seasonOver: boolean;
  drivers: Driver[];
  teams: Team[];
  customCountries?: Country[];
  onRowClick: (id: number, type: 'driver' | 'constructor') => void;
}

const StandingsTable: React.FC<StandingsTableProps> = ({ title, standings, type, seasonOver, drivers, teams, customCountries = [], onRowClick }) => {
  const { t } = useI18n();
  const isDriver = type === 'driver';

  return (
    <div className="bg-[#1e1e2b]/80 border border-slate-700 rounded-2xl backdrop-blur-sm shadow-lg p-6">
      <h3 className="text-xl font-bold mb-4 text-slate-200">{title}</h3>
      <div className="overflow-x-auto">
        <table className="w-full text-left">
          <thead>
            <tr className="border-b border-slate-700">
              <th className="p-3 text-sm font-semibold uppercase text-slate-400">{t('pos')}</th>
              <th className="p-3 text-sm font-semibold uppercase text-slate-400">{isDriver ? t('driver') : t('team')}</th>
              <th className="p-3 text-sm font-semibold uppercase text-slate-400 text-right">{t('points')}</th>
            </tr>
          </thead>
          <tbody>
            {standings.map((standing, index) => {
              const pos = index + 1;
              let name: string = '';
              let teamName: string | undefined = undefined;
              let teamPrimaryColor: string = '#4B5563'; // gray-600 default
              let teamAccentColor: string = '#FFFFFF';
              let imageUrl: string | undefined = undefined;
              let nationalityCode: string | undefined = undefined;
              let item: Driver | Team | undefined;

              if (isDriver) {
                const driver = drivers.find(d => d.id === (standing as DriverStanding).driverId);
                const team = teams.find(t => t.id === driver?.teamId);
                item = driver;
                name = driver?.name || t('unknownDriver');
                teamName = team?.name;
                teamPrimaryColor = team?.primaryColor || '#4B5563';
                teamAccentColor = team?.accentColor || '#FFFFFF';
                imageUrl = driver?.photoUrl;
                nationalityCode = driver?.nationality;
              } else {
                const team = teams.find(t => t.id === (standing as ConstructorStanding).teamId);
                item = team;
                name = team?.name || t('unknownTeam');
                teamPrimaryColor = team?.primaryColor || '#4B5563';
                teamAccentColor = team?.accentColor || '#FFFFFF';
                imageUrl = team?.logoUrl;
              }

              const isChampion = seasonOver && index === 0;
              if (!item) return null;
              const id = item.id;

              return (
                <tr 
                  key={id} 
                  className={`border-b border-slate-800 last:border-0 transition-colors duration-200 cursor-pointer hover:bg-slate-500/20 ${isChampion ? 'bg-[#00e051]/10' : ''}`}
                  onClick={() => onRowClick(id, type)}
                >
                  <td className="p-3 font-bold w-12 text-center relative">
                    {pos}
                    {isChampion && <TrophyIcon className="absolute -left-2 top-1/2 -translate-y-1/2 w-5 h-5 text-[#00e051]" />}
                  </td>
                  <td className="p-3 flex items-center space-x-3" style={{ borderLeft: `4px solid ${teamPrimaryColor}` }}>
                    <ImageWithFallback
                      src={imageUrl}
                      alt={name}
                      primaryColor={teamPrimaryColor}
                      accentColor={teamAccentColor}
                      initials={getInitials(name)}
                      // FIX: Map 'constructor' type to 'team' for ImageWithFallback component prop compatibility.
                      type={type === 'constructor' ? 'team' : type}
                      className={`h-10 w-10 ${isDriver ? 'rounded-full object-cover' : 'object-contain'}`}
                    />
                    <div>
                      <div className="font-semibold flex items-center gap-2">
                         {nationalityCode && (
                          <CountryFlag 
                            countryCode={nationalityCode}
                            customCountries={customCountries}
                            alt={getCountryByCode(nationalityCode)?.name} 
                            title={getCountryByCode(nationalityCode)?.name}
                            className="w-5 h-auto rounded-sm"
                          />
                        )}
                        <span>{name}</span>
                      </div>
                      {teamName && <div className="text-xs text-slate-400">{teamName}</div>}
                    </div>
                  </td>
                  <td className="p-3 font-bold text-lg text-right">{standing.points}</td>
                </tr>
              );
            })}
          </tbody>
        </table>
      </div>
    </div>
  );
};

export default StandingsTable;

import React, { useState, useMemo, useEffect } from 'react';
import { Driver, Team, RaceResult, QualifyingResult, Country } from '../types';
import { useI18n } from '../i18n';
import { getCountryByCode, getInitials } from '../utils';
import CloseIcon from './icons/CloseIcon';
import UserIcon from './icons/UserIcon';
import StatBar from './StatBar';
import ImageWithFallback from './ImageWithFallback';
import CountryFlag from './CountryFlag';

interface ProfileModalProps {
    isOpen: boolean;
    onClose: () => void;
    profileId?: number;
    profileType?: 'driver' | 'constructor';
    drivers: Driver[];
    teams: Team[];
    onSelectProfile: (id: number, type: 'driver' | 'constructor') => void;
    allRaceResults: RaceResult[][];
    allQualifyingResults: QualifyingResult[][];
    customCountries?: Country[];
}

const StatBox = ({ label, value }: { label: string, value: string | number }) => (
    <div className="bg-slate-900/50 p-4 rounded-lg text-center transform transition-transform hover:scale-105">
        <p className="text-sm text-slate-400 uppercase font-semibold">{label}</p>
        <p className="text-3xl font-bold text-white tracking-tight">{value}</p>
    </div>
);

const ProfileModal: React.FC<ProfileModalProps> = ({ isOpen, onClose, profileId, profileType, drivers, teams, onSelectProfile, allRaceResults, allQualifyingResults, customCountries = [] }) => {
    const { t } = useI18n();
    const [activeTab, setActiveTab] = useState<'details' | 'stats'>('details');

    useEffect(() => {
        if (isOpen) {
            setActiveTab('details');
        }
    }, [isOpen, profileId, profileType]);

    if (!isOpen || !profileId || !profileType) return null;

    const profileData = profileType === 'driver' 
        ? drivers.find(d => d.id === profileId) 
        : teams.find(t => t.id === profileId);

    if (!profileData) return null;

    const handleClose = () => {
        setActiveTab('details');
        onClose();
    };

    const TabButton: React.FC<{ tab: 'details' | 'stats', label: string }> = ({ tab, label }) => (
        <button
            onClick={() => setActiveTab(tab)}
            className={`px-4 py-2 font-bold uppercase text-sm rounded-t-lg transition-colors border-b-2 ${
                activeTab === tab ? 'text-[#00e051] border-[#00e051]' : 'text-slate-400 border-transparent hover:text-slate-200'
            }`}
        >
            {label}
        </button>
    );

    const renderDriverStats = (driver: Driver) => {
        const allDriverResults = allRaceResults.flat().filter(r => r.driverId === driver.id);
        const allDriverQualis = allQualifyingResults.flat().filter(q => q.driverId === driver.id);

        if (allDriverResults.length === 0) {
            return <p className="text-center text-slate-400 py-10">{t('stats_noData')}</p>;
        }

        const finishedRaces = allDriverResults.filter(r => r.position > 0);

        const stats = {
            races: allDriverResults.length,
            wins: allDriverResults.filter(r => r.position === 1).length,
            podiums: allDriverResults.filter(r => r.position > 0 && r.position <= 3).length,
            poles: allDriverQualis.filter(q => q.position === 1).length,
            points: allDriverResults.reduce((sum, r) => sum + r.points, 0),
            dnfs: allDriverResults.filter(r => r.position === 0).length,
            bestFinish: finishedRaces.length ? Math.min(...finishedRaces.map(r => r.position)) : 'N/A',
            avgFinish: finishedRaces.length ? (finishedRaces.reduce((sum, r) => sum + r.position, 0) / finishedRaces.length).toFixed(1) : 'N/A',
            bestGrid: allDriverQualis.length ? Math.min(...allDriverQualis.map(q => q.position)) : 'N/A',
            avgGrid: allDriverQualis.length ? (allDriverQualis.reduce((sum, q) => sum + q.position, 0) / allDriverQualis.length).toFixed(1) : 'N/A',
        };

        return (
             <div className="grid grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-4 animate-fade-in">
                <StatBox label={t('stats_races')} value={stats.races} />
                <StatBox label={t('stats_wins')} value={stats.wins} />
                <StatBox label={t('stats_podiums')} value={stats.podiums} />
                <StatBox label={t('stats_poles')} value={stats.poles} />
                <StatBox label={t('stats_points')} value={stats.points} />
                <StatBox label={t('stats_dnfs')} value={stats.dnfs} />
                <StatBox label={t('stats_bestFinish')} value={stats.bestFinish} />
                <StatBox label={t('stats_avgFinish')} value={stats.avgFinish} />
                <StatBox label={t('stats_bestGrid')} value={stats.bestGrid} />
                <StatBox label={t('stats_avgGrid')} value={stats.avgGrid} />
            </div>
        )
    };

    const renderTeamStats = (team: Team) => {
        const driverIds = drivers.filter(d => d.teamId === team.id).map(d => d.id);
        const allTeamResults = allRaceResults.flat().filter(r => driverIds.includes(r.driverId));
        const allTeamQualis = allQualifyingResults.flat().filter(q => driverIds.includes(q.driverId));

        if (allTeamResults.length === 0) {
            return <p className="text-center text-slate-400 py-10">{t('stats_noData')}</p>;
        }

        const finishedRaces = allTeamResults.filter(r => r.position > 0);

        const stats = {
            races: allTeamResults.length,
            wins: allTeamResults.filter(r => r.position === 1).length,
            podiums: allTeamResults.filter(r => r.position > 0 && r.position <= 3).length,
            poles: allTeamQualis.filter(q => q.position === 1).length,
            points: allTeamResults.reduce((sum, r) => sum + r.points, 0),
            dnfs: allTeamResults.filter(r => r.position === 0).length,
        };

        return (
            <div className="grid grid-cols-2 md:grid-cols-3 gap-4 animate-fade-in">
                <StatBox label={t('stats_races')} value={stats.races} />
                <StatBox label={t('stats_wins')} value={stats.wins} />
                <StatBox label={t('stats_podiums')} value={stats.podiums} />
                <StatBox label={t('stats_poles')} value={stats.poles} />
                <StatBox label={t('stats_points')} value={stats.points} />
                <StatBox label={t('stats_dnfs')} value={stats.dnfs} />
            </div>
        )
    };


    const renderDriverProfile = (driver: Driver) => {
        const team = teams.find(t => t.id === driver.teamId);
        const country = getCountryByCode(driver.nationality);
        // Fallback for custom country name if not found in standard list
        const customCountry = customCountries.find(c => c.code === driver.nationality);

        return (
            <div className="animate-fade-in">
                <div className="flex flex-col sm:flex-row items-center gap-6 mb-6">
                    <ImageWithFallback 
                        src={driver.photoUrl} 
                        alt={driver.name} 
                        primaryColor={team?.primaryColor || '#334155'}
                        accentColor={team?.accentColor || '#FFFFFF'}
                        initials={getInitials(driver.name)}
                        type="driver"
                        className="w-32 h-32 rounded-full object-cover border-4" 
                        style={{ borderColor: team?.primaryColor || 'var(--border-color)' }}
                    />
                    <div className="flex-grow text-center sm:text-left">
                         <h2 className="text-3xl font-bold text-slate-200">{driver.name}</h2>
                         <div className="flex items-center justify-center sm:justify-start gap-4 text-slate-400 mt-2">
                             <span className="flex items-center gap-2">
                                <CountryFlag countryCode={driver.nationality} customCountries={customCountries} className="w-5 h-auto rounded-sm" />
                                {customCountry?.name || country?.name || driver.nationality}
                             </span>
                             <span>•</span>
                             <span>{t('age')}: {driver.age}</span>
                         </div>
                         {team && (
                            <button onClick={() => onSelectProfile(team.id, 'constructor')} className="flex items-center gap-2 mt-2 bg-slate-500/20 hover:bg-slate-500/40 p-2 rounded-lg transition-colors mx-auto sm:mx-0">
                                <ImageWithFallback
                                    src={team.logoUrl}
                                    alt={team.name}
                                    primaryColor={team.primaryColor}
                                    accentColor={team.accentColor}
                                    initials={getInitials(team.name)}
                                    type="team"
                                    className="w-8 h-8 object-contain"
                                />
                                <span className="font-semibold text-slate-300">{team.name}</span>
                            </button>
                         )}
                    </div>
                </div>

                <div>
                    <h3 className="text-xl font-bold text-slate-300 mb-4 border-b border-slate-700 pb-2">{t('profile_skills')}</h3>
                    <div className="grid grid-cols-1 md:grid-cols-2 gap-x-8 gap-y-4">
                        <StatBar label={t('skill_speed')} value={driver.speed} max={10} />
                        <StatBar label={t('skill_overtaking')} value={driver.overtaking} max={10} />
                        <StatBar label={t('skill_concentration')} value={driver.concentration} max={10} />
                        <StatBar label={t('skill_start')} value={driver.startSkill} max={10} />
                        <StatBar label={t('skill_rain')} value={driver.rainSkill} max={10} />
                        <StatBar label={t('skill_setup')} value={driver.setupSkill} max={10} />
                        <StatBar label={t('skill_experience')} value={driver.experience} max={10} />
                        <StatBar label={t('skill_physical')} value={driver.physical} max={10} />
                        <StatBar label={t('skill_potential')} value={driver.potential} max={10} color='var(--accent-red)'/>
                    </div>
                </div>
            </div>
        );
    };

    const renderTeamProfile = (team: Team) => {
        const teamDrivers = drivers.filter(d => d.teamId === team.id);
        return (
            <div className="animate-fade-in">
                <div className="flex flex-col sm:flex-row items-center gap-6 mb-6">
                     <ImageWithFallback 
                        src={team.logoUrl} 
                        alt={team.name} 
                        primaryColor={team.primaryColor}
                        accentColor={team.accentColor}
                        initials={getInitials(team.name)}
                        type="team"
                        className="w-32 h-32 object-contain"
                    />
                    <div className="flex-grow text-center sm:text-left">
                         <h2 className="text-3xl font-bold" style={{color: team.primaryColor, textShadow: `0 0 8px ${team.accentColor}`}}>{team.name}</h2>
                         <p className="text-slate-400 mt-2">{t('profile_engineSupplier')}: <span className="font-semibold text-slate-300">{team.engineSupplier}</span></p>
                    </div>
                </div>

                <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                    <div>
                        <h3 className="text-xl font-bold text-slate-300 mb-4 border-b border-slate-700 pb-2">{t('profile_carStats')}</h3>
                         <div className="space-y-4">
                            <StatBar label={t('stat_aero')} value={team.aerodynamics} max={100} />
                            <StatBar label={t('stat_gearbox')} value={team.gearbox} max={100} />
                            <StatBar label={t('stat_brakes')} value={team.brakes} max={100} />
                            <StatBar label={t('stat_electrical')} value={team.electricalSystem} max={100} />
                            <StatBar label={t('stat_steering')} value={team.steering} max={100} />
                            <StatBar label={t('stat_reliability')} value={team.reliability} max={100} color='var(--accent-red)' />
                         </div>
                    </div>
                    <div>
                        <h3 className="text-xl font-bold text-slate-300 mb-4 border-b border-slate-700 pb-2">{t('profile_teamDrivers')}</h3>
                        <div className="space-y-3">
                            {teamDrivers.map(driver => (
                                <button 
                                    key={driver.id}
                                    onClick={() => onSelectProfile(driver.id, 'driver')}
                                    className="w-full flex items-center gap-4 p-2 bg-slate-500/10 hover:bg-slate-500/20 rounded-lg transition-colors"
                                >
                                    <ImageWithFallback
                                        src={driver.photoUrl} 
                                        alt={driver.name} 
                                        primaryColor={team.primaryColor}
                                        accentColor={team.accentColor}
                                        initials={getInitials(driver.name)}
                                        type="driver"
                                        className="w-12 h-12 rounded-full object-cover"
                                    />
                                    <div>
                                        <p className="font-bold text-slate-200 text-left">{driver.name}</p>
                                        <p className="text-sm text-slate-400 text-left">{t('age')}: {driver.age}</p>
                                    </div>
                                </button>
                            ))}
                        </div>
                    </div>
                </div>
            </div>
        );
    };

    return (
        <div 
            className="fixed inset-0 bg-black bg-opacity-80 flex items-center justify-center z-50 p-4 backdrop-blur-sm animate-fade-in"
            onClick={handleClose}
        >
            <div 
                className="bg-[#1e1e2b] border border-slate-700 rounded-2xl shadow-2xl w-full max-w-4xl max-h-[90vh] overflow-y-auto flex flex-col"
                onClick={(e) => e.stopPropagation()}
            >
                <div className="sticky top-0 bg-[#1e1e2b]/80 backdrop-blur-sm z-10 p-4 border-b border-slate-700 flex justify-between items-center">
                    <h2 className="text-xl font-bold text-slate-300 flex items-center gap-3">
                        {profileType === 'driver' ? <UserIcon className="w-6 h-6"/> : <UserIcon className="w-6 h-6"/>}
                        <span>{profileType === 'driver' ? t('profile_driverTitle') : t('profile_teamTitle')}</span>
                    </h2>
                    <button onClick={handleClose} className="text-slate-400 hover:text-white">
                        <CloseIcon className="w-6 h-6" />
                    </button>
                </div>

                <div className="border-b border-slate-700 px-4">
                    <TabButton tab="details" label={t('profile_details')} />
                    <TabButton tab="stats" label={t('profile_stats')} />
                </div>

                <div className="p-6">
                    {activeTab === 'details' && (
                        profileType === 'driver' ? renderDriverProfile(profileData as Driver) : renderTeamProfile(profileData as Team)
                    )}
                    {activeTab === 'stats' && (
                        profileType === 'driver' ? renderDriverStats(profileData as Driver) : renderTeamStats(profileData as Team)
                    )}
                </div>
            </div>
        </div>
    );
};

export default ProfileModal;

import React from 'react';
import { RaceResult, Race, Driver, Team, QualifyingResult, SeasonSettings, Country } from '../types';
import { getCountryFlagUrl, getInitials } from '../utils';
import CloseIcon from './icons/CloseIcon';
import StopwatchIcon from './icons/StopwatchIcon';
import { useI18n } from '../i18n';
import ImageWithFallback from './ImageWithFallback';
import { SCORING_SYSTEMS } from '../constants';
import CountryFlag from './CountryFlag';

interface RaceResultModalProps {
  isOpen: boolean;
  onClose: () => void;
  raceResults: RaceResult[];
  qualifyingResults: QualifyingResult[];
  race: Race;
  drivers: Driver[];
  teams: Team[];
  settings: SeasonSettings;
  customCountries?: Country[];
}

const RaceResultModal: React.FC<RaceResultModalProps> = ({ isOpen, onClose, raceResults, qualifyingResults, race, drivers, teams, settings, customCountries = [] }) => {
  const { t } = useI18n();
  if (!isOpen) return null;

  const scoringSystem = SCORING_SYSTEMS.find(s => s.id === settings.scoringSystemId);
  const pointsPositions = scoringSystem ? scoringSystem.points.length : 10;

  const combinedResults = raceResults.map(raceResult => {
    const qualifying = qualifyingResults.find(q => q.driverId === raceResult.driverId);
    return {
      ...raceResult,
      gridPosition: qualifying?.position || 0,
      eliminatedIn: qualifying?.eliminatedIn,
    };
  }).sort((a, b) => {
    if (a.position === 0) return 1;
    if (b.position === 0) return -1;
    return a.position - b.position;
  });

  const PositionChange: React.FC<{ change: number }> = ({ change }) => {
    if (change > 0) return <span className="text-[#00e051] font-bold">▲{change}</span>;
    if (change < 0) return <span className="text-[#e00601] font-bold">▼{Math.abs(change)}</span>;
    return <span className="text-slate-500 font-bold">-</span>;
  };

  const ResultHeader = () => (
    <div className="grid grid-cols-12 gap-2 p-2 text-xs font-bold text-slate-400 uppercase border-b border-slate-700">
        <div className="col-span-1 text-center">{t('pos')}</div>
        <div className="col-span-1 text-center">{t('grid')}</div>
        <div className="col-span-1 text-center hidden sm:block">+/-</div>
        <div className="col-span-5 sm:col-span-4">{t('driver')}</div>
        <div className="col-span-2 text-right hidden md:block">{t('bestLap')}</div>
        <div className="col-span-1 text-center hidden sm:block">{t('pits')}</div>
        <div className="col-span-2 text-right">{t('points')}</div>
    </div>
  );

  return (
    <div 
      className="fixed inset-0 bg-black bg-opacity-80 flex items-center justify-center z-50 p-4 backdrop-blur-sm"
      onClick={onClose}
    >
      <div 
        className="bg-[#1e1e2b] border border-slate-700 rounded-2xl shadow-2xl w-full max-w-4xl max-h-[90vh] overflow-y-auto flex flex-col"
        onClick={(e) => e.stopPropagation()}
      >
        <div className="sticky top-0 bg-[#1e1e2b]/80 backdrop-blur-sm z-10 p-6 border-b border-slate-700 flex justify-between items-center">
          <h2 className="text-2xl font-bold text-slate-200 flex items-center gap-3">
            <CountryFlag countryCode={race.countryCode} customCountries={customCountries} className="w-8 h-auto rounded-sm" />
            <span>{t('resultsFor', { raceName: race.name })}</span>
          </h2>
          <button onClick={onClose} className="text-slate-400 hover:text-white">
            <CloseIcon className="w-6 h-6" />
          </button>
        </div>

        <div className="p-4 sm:p-6 flex-grow">
          <ResultHeader />
          <ul className="space-y-1 mt-1">
            {combinedResults.map((result) => {
              const driver = drivers.find(d => d.id === result.driverId);
              const team = teams.find(t => t.id === driver?.teamId);
              if (!driver || !team) return null;

              const isDNF = result.position === 0;
              const isInPoints = !isDNF && result.position > 0 && result.position <= pointsPositions;
              const positionChange = !isDNF && result.gridPosition ? result.gridPosition - result.position : 0;

              return (
                <li key={driver.id} className={`grid grid-cols-12 gap-2 items-center p-2 rounded-md ${isDNF ? 'bg-[#e00601]/20 opacity-80' : isInPoints ? 'bg-green-900/20' : 'bg-slate-500/10'}`}>
                  {/* Pos */}
                  <div className="col-span-1 text-center font-black text-lg">{isDNF ? 'DNF' : result.position}</div>

                  {/* Grid */}
                  <div className="col-span-1 text-center text-slate-400 text-sm">({result.gridPosition || 'N/A'})</div>

                  {/* +/- */}
                  <div className="col-span-1 text-center hidden sm:block">
                    <PositionChange change={positionChange} />
                  </div>

                  {/* Piloto */}
                  <div className="col-span-5 sm:col-span-4 flex items-center gap-3 border-l-4" style={{ borderColor: team.primaryColor }}>
                     <ImageWithFallback
                        src={driver.photoUrl}
                        alt={driver.name}
                        primaryColor={team.primaryColor}
                        accentColor={team.accentColor}
                        initials={getInitials(driver.name)}
                        type="driver"
                        className="w-10 h-10 rounded-full object-cover ml-2"
                     />
                     <div>
                        <p className="font-semibold text-sm sm:text-base">{driver.name}</p>
                        <p className="text-xs text-slate-400 hidden sm:block">{team.name} {result.eliminatedIn ? <span className="font-bold">({result.eliminatedIn})</span> : ''}</p>
                        {isDNF && result.dnfReason && (
                          <p className="text-xs text-red-400/90 font-semibold italic mt-1 sm:block">{result.dnfReason}</p>
                        )}
                     </div>
                  </div>

                  {/* Best Lap */}
                  <div className="col-span-2 text-right font-mono text-sm hidden md:block">{result.bestLapTime}</div>

                  {/* Pits */}
                  <div className="col-span-1 text-center font-bold hidden sm:block">{result.pitStops}</div>

                  {/* Pontos */}
                  <div className="col-span-2 text-right flex items-center justify-end gap-2">
                    {result.fastestLap && <StopwatchIcon title={t('fastestLap')} className="w-4 h-4 text-purple-400" />}
                    <span className="font-bold text-lg text-white w-10">{result.points > 0 ? `+${result.points}` : '0'}</span>
                  </div>
                </li>
              );
            })}
          </ul>
        </div>

        <div className="sticky bottom-0 bg-[#1e1e2b]/80 backdrop-blur-sm z-10 p-4 border-t border-slate-700 flex justify-end">
            <button
                onClick={onClose}
                className="px-6 py-2 bg-[#e00601] text-white font-bold uppercase rounded-lg shadow-md hover:bg-opacity-90 flex items-center justify-center gap-2 transition-colors"
            >
                <CloseIcon className="w-5 h-5" />
                <span>{t('close')}</span>
            </button>
        </div>
      </div>
    </div>
  );
};

export default RaceResultModal;

import React, { useState, useEffect } from 'react';
import { Race, Driver, Team, RaceState, SeasonSettings, Country } from '../types';
import { getCountryFlagUrl, formatTime, getInitials } from '../utils';
import TyreCompoundIcon from './TyreCompoundIcon';
import LiveIcon from './icons/LiveIcon';
import MicrophoneIcon from './icons/MicrophoneIcon';
import PauseIcon from './icons/PauseIcon';
import RaceFlagOverlay from './RaceFlagOverlay';
import { useI18n } from '../i18n';
import ImageWithFallback from './ImageWithFallback';
import { SCORING_SYSTEMS } from '../constants';
import ExclamationTriangleIcon from './icons/ExclamationTriangleIcon';

interface LiveRaceViewProps {
    race: Race;
    raceState: RaceState;
    drivers: Driver[];
    teams: Team[];
    commentary: string;
    isPaused: boolean;
    settings: SeasonSettings;
    customCountries?: Country[];
}

const LiveRaceView: React.FC<LiveRaceViewProps> = ({ race, raceState, drivers, teams, commentary, isPaused, settings, customCountries = [] }) => {
    const { t } = useI18n();
    const [pulse, setPulse] = useState(false);
    const [trackedDriverId, setTrackedDriverId] = useState<number | null>(null);

    const scoringSystem = SCORING_SYSTEMS.find(s => s.id === settings.scoringSystemId);
    const pointsPositions = scoringSystem ? scoringSystem.points.length : 10;

    useEffect(() => {
        if (commentary) {
            setPulse(true);
            const timer = setTimeout(() => setPulse(false), 750);
            return () => clearTimeout(timer);
        }
    }, [commentary]);

    const colorizeCommentary = (comment: string): React.ReactNode => {
        if (!comment) {
            return <span className="text-slate-400">{t('commentary_waiting')}</span>;
        }

        const lapInfoMatch = comment.match(/^(\[.*?\])/);
        const lapInfo = lapInfoMatch ? lapInfoMatch[1] : '';
        const commentText = comment.replace(lapInfo, '').trim();

        const entities = [
            ...drivers.map(d => {
                const team = teams.find(t => t.id === d.teamId);
                return { name: d.name, color: team?.primaryColor || '#FFFFFF', accent: team?.accentColor || '#FFFFFF' };
            }),
            ...teams.map(t => ({ name: t.name, color: t.primaryColor, accent: t.accentColor }))
        ];

        entities.sort((a, b) => b.name.length - a.name.length);

        const regex = new RegExp(`(${entities.map(e => e.name.replace(/[-\/\\^$*+?.()|[\]{}]/g, '\\$&')).join('|')})`, 'g');

        const parts = commentText.split(regex);

        const renderedText = parts.map((part, index) => {
            const entity = entities.find(e => e.name === part);
            if (entity) {
                const hex = entity.color.replace('#', '');
                const r = parseInt(hex.substring(0, 2), 16);
                const g = parseInt(hex.substring(2, 4), 16);
                const b = parseInt(hex.substring(4, 6), 16);
                const brightness = (r * 299 + g * 587 + b * 114) / 1000;

                const style: React.CSSProperties = {
                    color: entity.color,
                    fontWeight: 'bold',
                    textShadow: brightness < 70 ? `0 0 8px ${entity.accent === '#000000' ? '#FFFFFF' : entity.accent}` : 'none',
                };
                return <span key={index} style={style}>{part}</span>;
            }
            return part;
        });

        return (
            <>
                <span className="text-xs text-slate-500 mr-2">{lapInfo}</span>
                <span>{renderedText}</span>
            </>
        );
    };

    const sortedDrivers = [...raceState.drivers].sort((a, b) => {
        if (a.status === 'DNF' && b.status !== 'DNF') return 1;
        if (a.status !== 'DNF' && b.status === 'DNF') return -1;
        if (a.status === 'DNF' && b.status === 'DNF') return 0;
        return a.position - b.position;
    });

    const remainingLaps = raceState.totalLaps - raceState.currentLap;
    const remainingLapsText = remainingLaps === 1
        ? t('remaining_laps_singular')
        : t('remaining_laps_plural', { count: remainingLaps });

    const driverToTrackId = trackedDriverId ?? raceState.drivers.find(d => d.position === 1)?.driverId;
    const driverToTrackState = driverToTrackId ? raceState.drivers.find(d => d.driverId === driverToTrackId) : null;
    const driverToTrack = driverToTrackId ? drivers.find(d => d.id === driverToTrackId) : null;
    const teamOfTracked = driverToTrack ? teams.find(t => t.id === driverToTrack.teamId) : null;

    return (
        <div className="space-y-4 animate-fade-in">
            <RaceFlagOverlay flagStatus={raceState.flag} isSafetyCarDeployed={!!raceState.isSafetyCarDeployed} />
            <div className="grid grid-cols-1 lg:grid-cols-3 gap-4">
                {/* Left Panel: Standings */}
                <div className="lg:col-span-2 bg-slate-500/10 p-2 rounded-lg max-h-[80vh] overflow-y-auto">
                    {/* Header */}
                    <div className="sticky top-0 bg-[#1e1e2b]/80 backdrop-blur-sm z-10 grid grid-cols-12 gap-2 p-2 text-xs font-bold text-slate-400 uppercase">
                        <div className="col-span-1 text-center">{t('pos')}</div>
                        <div className="col-span-4">{t('driver')}</div>
                        <div className="col-span-1 text-center hidden sm:block">{t('pits')}</div>
                        <div className="col-span-2 text-right hidden sm:block">{t('lastLap')}</div>
                        <div className="col-span-2 text-right hidden sm:block">{t('gapAhead')}</div>
                        <div className="col-span-2 text-right">{t('gapLeader')}</div>
                    </div>
                    {/* Body */}
                    <div className="space-y-1 mt-1">
                        {sortedDrivers.map(ds => {
                            const driver = drivers.find(d => d.id === ds.driverId)!;
                            const team = teams.find(t => t.id === driver.teamId)!;
                            const isDNF = ds.status === 'DNF';
                            const isTracked = ds.driverId === driverToTrackId;
                            const isInPoints = !isDNF && ds.position > 0 && ds.position <= pointsPositions;

                            return (
                                <div 
                                    key={driver.id} 
                                    onClick={() => setTrackedDriverId(ds.driverId)}
                                    className={`grid grid-cols-12 gap-2 items-center p-1.5 rounded-md text-sm cursor-pointer transition-colors duration-200 ${
                                        isDNF ? 'bg-red-900/40 opacity-70' : 
                                        isTracked ? 'bg-slate-700/80' : 
                                        isInPoints ? 'bg-green-900/20 hover:bg-green-900/40' :
                                        'bg-slate-800/30 hover:bg-slate-700/50'
                                    }`}
                                >
                                    <div className="col-span-1 text-center font-bold text-lg">{isDNF ? 'DNF' : ds.position}</div>
                                    <div className="col-span-5 sm:col-span-4 flex items-center gap-2 border-l-4" style={{borderColor: team.primaryColor}}>
                                        <ImageWithFallback src={driver.photoUrl} alt={driver.name} primaryColor={team.primaryColor} accentColor={team.accentColor} initials={getInitials(driver.name)} type="driver" className="w-8 h-8 rounded-full object-cover ml-2"/>
                                        <span className="font-semibold text-slate-200 truncate">{driver.name}</span>
                                        {ds.activeIncident && (
                                            <ExclamationTriangleIcon 
                                                className="w-4 h-4 text-yellow-400 flex-shrink-0" 
                                                title={t(`incident_${ds.activeIncident.type}`)} 
                                            />
                                        )}
                                        <TyreCompoundIcon compound={ds.currentTyres.compound} />
                                        {isDNF && <span className="text-xs text-red-300 italic">({t('retired')})</span>}
                                    </div>
                                    <div className="col-span-1 text-center font-mono hidden sm:block">{ds.pitStops}</div>
                                    <div className="col-span-2 text-right font-mono hidden sm:block">
                                        {isDNF ? '-' : ds.status === 'PITTING' ? <span className="font-bold text-blue-400 animate-pulse">{t('inPit')}</span> : formatTime(ds.lastLapTime)}
                                    </div>
                                    <div className="col-span-2 text-right font-mono text-slate-400 hidden sm:block">{isDNF ? '-' : ds.gapToAhead}</div>
                                    <div className="col-span-4 sm:col-span-2 text-right font-mono text-slate-300">{isDNF ? '-' : ds.gapToLeader}</div>
                                </div>
                            );
                        })}
                    </div>
                </div>

                {/* Right Panel: Race Info & Commentary */}
                <div className="lg:col-span-1 bg-slate-500/10 p-4 rounded-lg space-y-4 flex flex-col max-h-[80vh]">
                    <div className="border-b border-slate-700 pb-4 text-center">
                        <p className="text-lg font-bold text-slate-200">{race.name}</p>
                        <div className="flex items-baseline justify-center gap-2 mt-2">
                            <span className="text-5xl font-black text-white tracking-tighter">{raceState.currentLap}</span>
                            <span className="text-2xl font-bold text-slate-400">/ {raceState.totalLaps} {t('laps')}</span>
                        </div>
                        {remainingLaps > 0 && (
                            <p className="text-sm text-yellow-300 mt-1 font-semibold">
                                {remainingLapsText}
                            </p>
                        )}
                        <LiveIcon className="h-6 w-auto mx-auto mt-2"/>
                    </div>

                    {driverToTrack && driverToTrackState && teamOfTracked && (
                        <div className="bg-[#15141f]/50 p-3 rounded-md">
                            <h4 className="font-bold text-slate-300 mb-3 uppercase text-sm">{t('driverTracker')}</h4>
                            <div className="flex items-center gap-3 mb-4">
                                <ImageWithFallback src={driverToTrack.photoUrl} alt={driverToTrack.name} primaryColor={teamOfTracked.primaryColor} accentColor={teamOfTracked.accentColor} initials={getInitials(driverToTrack.name)} type="driver" className="w-16 h-16 rounded-full object-cover border-2" style={{borderColor: teamOfTracked.primaryColor}}/>
                                <div>
                                    <p className="font-bold text-lg text-white">{driverToTrack.name}</p>
                                    <p className="text-sm text-slate-400">{teamOfTracked.name}</p>
                                </div>
                            </div>

                            <div className="grid grid-cols-2 gap-4 text-sm mb-4">
                                <div className="text-center">
                                    <p className="text-xs uppercase text-slate-400">{t('pos')}</p>
                                    <p className="text-2xl font-bold">{driverToTrackState.status === 'DNF' ? 'DNF' : driverToTrackState.position}</p>
                                </div>
                                <div className="text-center">
                                    <p className="text-xs uppercase text-slate-400">{t('pits')}</p>
                                    <p className="text-2xl font-bold">{driverToTrackState.pitStops}</p>
                                </div>
                            </div>

                            <div className="bg-slate-900/50 p-2 rounded-lg mb-4">
                                <p className="text-xs uppercase text-slate-400 text-center mb-2">{t('tyreInfo')}</p>
                                <div className="flex items-center justify-around">
                                    <TyreCompoundIcon compound={driverToTrackState.currentTyres.compound} size={32}/>
                                    <div>
                                        <p className="text-xs text-slate-400">{t('tyreAge')}</p>
                                        <p className="font-bold">{driverToTrackState.currentTyres.age} <span className="text-xs text-slate-400">{t('laps')}</span></p>
                                    </div>
                                    <div>
                                        <p className="text-xs text-slate-400">{t('tyreWear')}</p>
                                        <p className="font-bold">{driverToTrackState.currentTyres.wear.toFixed(1)}%</p>
                                    </div>
                                </div>
                            </div>

                             <div className="bg-slate-900/50 p-2 rounded-lg">
                                <p className="text-xs uppercase text-slate-400 text-center mb-2">{t('timings')}</p>
                                <div className="space-y-1 text-xs">
                                    <div className="flex justify-between"><span>{t('lastLap')}:</span> <span className="font-mono">{formatTime(driverToTrackState.lastLapTime)}</span></div>
                                    <div className="flex justify-between"><span>{t('bestLap')}:</span> <span className="font-mono">{formatTime(driverToTrackState.bestLapTime)}</span></div>
                                    <div className="flex justify-between"><span>{t('gapLeader')}:</span> <span className="font-mono">{driverToTrackState.gapToLeader}</span></div>
                                    <div className="flex justify-between"><span>{t('gapAhead')}:</span> <span className="font-mono">{driverToTrackState.gapToAhead}</span></div>
                                </div>
                            </div>
                        </div>
                    )}

                    <div className="bg-[#15141f]/50 p-3 rounded-md flex-grow overflow-y-auto">
                        <div className="flex items-center gap-2 mb-2">
                           <MicrophoneIcon className={`w-5 h-5 transition-transform duration-150 ${pulse ? 'scale-125 text-white' : 'text-slate-400'}`} />
                            <h4 className="font-bold text-slate-300">{t('liveCommentary')}</h4>
                        </div>
                        <p className="text-sm text-slate-300 leading-relaxed">
                            {colorizeCommentary(commentary)}
                        </p>
                    </div>
                     {isPaused && (
                        <div className="flex items-center justify-center gap-2 p-3 bg-yellow-400/20 border border-yellow-400/50 rounded-md text-yellow-200 font-bold">
                            <PauseIcon className="w-5 h-5"/>
                            <span>{t('paused')}</span>
                        </div>
                    )}
                </div>

            </div>
        </div>
    );
};

export default LiveRaceView;

import React, { useState } from 'react';
import { SeasonHistory, Driver, Team, Race, RaceResult, QualifyingResult, SeasonSettings, Country } from '../types';
import { useI18n } from '../i18n';
import TrophyIcon from './icons/TrophyIcon';
import ImageWithFallback from './ImageWithFallback';
import { getInitials } from '../utils';
import RaceResultModal from './RaceResultModal';
import StandingsTable from './StandingsTable';
import CountryFlag from './CountryFlag';

interface HistoryScreenProps {
    history: SeasonHistory[];
    customCountries?: Country[];
}

const HistoryScreen: React.FC<HistoryScreenProps> = ({ history, customCountries = [] }) => {
    const { t } = useI18n();
    const [selectedYear, setSelectedYear] = useState<number | null>(history.length > 0 ? history[0].year : null);
    const [modalData, setModalData] = useState<{ race: Race, results: RaceResult[], quali: QualifyingResult[] } | null>(null);
    const [activeTab, setActiveTab] = useState<'standings' | 'calendar'>('standings');

    const selectedSeason = history.find(h => h.year === selectedYear);

    const driverChampion = selectedSeason ? selectedSeason.drivers.find(d => d.id === selectedSeason.driverChampionId) : null;
    const driverChampionTeam = driverChampion ? selectedSeason.teams.find(t => t.id === driverChampion.teamId) : null;
    const constructorChampion = selectedSeason ? selectedSeason.teams.find(t => t.id === selectedSeason.constructorChampionId) : null;

    const handleViewResults = (raceIndex: number) => {
        if (!selectedSeason) return;
        setModalData({
            race: selectedSeason.calendar[raceIndex],
            results: selectedSeason.allRaceResults[raceIndex],
            quali: selectedSeason.allQualifyingResults[raceIndex],
        });
    };

    const handleYearChange = (year: number) => {
        setSelectedYear(year);
        setActiveTab('standings');
    }

    // FIX: Added missing `mode` and `playerTeamId` properties to the fallback settings object.
    const fallbackSettings: SeasonSettings = { startYear: selectedSeason?.year || 2024, scoringSystemId: 1, mode: 'spectator', playerTeamId: null };

    return (
        <>
            <RaceResultModal
                isOpen={!!modalData}
                onClose={() => setModalData(null)}
                race={modalData?.race!}
                raceResults={modalData?.results!}
                qualifyingResults={modalData?.quali!}
                drivers={selectedSeason?.drivers || []}
                teams={selectedSeason?.teams || []}
                settings={selectedSeason?.settings || fallbackSettings}
                customCountries={customCountries}
            />
             {history.length === 0 ? (
                    <p className="text-center text-slate-400 py-20">{t('history_noHistory')}</p>
                ) : (
                    <div>
                        <div className="mb-6">
                            <label htmlFor="season-select" className="block text-sm font-medium text-slate-400 mb-2">{t('history_selectSeason')}</label>
                            <select
                                id="season-select"
                                value={selectedYear || ''}
                                onChange={(e) => handleYearChange(parseInt(e.target.value, 10))}
                                className="w-full sm:w-auto px-4 py-2 bg-[#15141f] border border-slate-700 rounded-md focus:outline-none focus:ring-2 focus:ring-[#00e051] focus:border-[#00e051]"
                            >
                                {history.map(s => <option key={s.year} value={s.year} className="bg-[#1e1e2b]">{s.year}</option>)}
                            </select>
                        </div>

                        {selectedSeason && driverChampion && constructorChampion && (
                            <div>
                                <h3 className="text-2xl font-bold text-slate-300 mb-4">{t('history_seasonSummary', { year: selectedSeason.year })}</h3>
                                <div className="grid grid-cols-1 md:grid-cols-2 gap-6 mb-8">
                                    <div className="bg-slate-500/10 p-6 rounded-xl border border-slate-700 flex flex-col items-center text-center">
                                        <TrophyIcon className="w-12 h-12 text-yellow-400 mb-2"/>
                                        <h4 className="text-xl font-bold text-slate-300 mb-4">{t('driversChampion')}</h4>
                                        <ImageWithFallback src={driverChampion.photoUrl} alt={driverChampion.name} primaryColor={driverChampionTeam?.primaryColor || '#FFFFFF'} accentColor={driverChampionTeam?.accentColor || '#FFFFFF'} initials={getInitials(driverChampion.name)} type="driver" className="w-24 h-24 rounded-full object-cover mb-2 border-2 border-yellow-400"/>
                                        <p className="font-bold text-lg text-white">{driverChampion.name}</p>
                                        <p className="text-sm text-slate-400">{driverChampionTeam?.name}</p>
                                    </div>
                                    <div className="bg-slate-500/10 p-6 rounded-xl border border-slate-700 flex flex-col items-center text-center">
                                        <TrophyIcon className="w-12 h-12 text-yellow-400 mb-2"/>
                                        <h4 className="text-xl font-bold text-slate-300 mb-4">{t('constructorsChampion')}</h4>
                                        <ImageWithFallback src={constructorChampion.logoUrl} alt={constructorChampion.name} primaryColor={constructorChampion.primaryColor} accentColor={constructorChampion.accentColor} initials={getInitials(constructorChampion.name)} type="team" className="w-24 h-24 object-contain mb-2 p-2"/>
                                        <p className="font-bold text-lg" style={{ color: constructorChampion.primaryColor }}>{constructorChampion.name}</p>
                                    </div>
                                </div>

                                <div className="flex border-b border-slate-700 mb-4">
                                    <button onClick={() => setActiveTab('standings')} className={`px-4 py-2 font-bold uppercase text-sm ${activeTab === 'standings' ? 'border-b-2 border-[#00e051] text-white' : 'text-slate-400'}`}>{t('standings')}</button>
                                    <button onClick={() => setActiveTab('calendar')} className={`px-4 py-2 font-bold uppercase text-sm ${activeTab === 'calendar' ? 'border-b-2 border-[#00e051] text-white' : 'text-slate-400'}`}>{t('history_raceCalendar')}</button>
                                </div>
                                {activeTab === 'standings' && (
                                     <div className="grid grid-cols-1 lg:grid-cols-2 gap-8 animate-fade-in">
                                        <StandingsTable title={t('driversChampionship')} standings={selectedSeason.driverStandings} type="driver" seasonOver={true} drivers={selectedSeason.drivers} teams={selectedSeason.teams} customCountries={customCountries} onRowClick={() => {}} />
                                        <StandingsTable title={t('constructorsChampionship')} standings={selectedSeason.constructorStandings} type="constructor" seasonOver={true} drivers={selectedSeason.drivers} teams={selectedSeason.teams} customCountries={customCountries} onRowClick={() => {}} />
                                    </div>
                                )}
                                {activeTab === 'calendar' && (
                                    <div className="space-y-3 animate-fade-in">
                                        {selectedSeason.calendar.map((race, index) => {
                                            const raceResults = selectedSeason.allRaceResults[index];
                                            const podium = [1, 2, 3]
                                                .map(pos => {
                                                    const result = raceResults.find(r => r.position === pos);
                                                    if (!result) return null;
                                                    const driver = selectedSeason.drivers.find(d => d.id === result.driverId);
                                                    if (!driver) return null;
                                                    const team = selectedSeason.teams.find(t => t.id === driver.teamId);
                                                    return { ...result, driver, team };
                                                })
                                                .filter(Boolean) as ({ driver: Driver, team: Team } & RaceResult)[];

                                            return (
                                                <div key={index} className="bg-slate-500/10 p-4 rounded-lg">
                                                    <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center">
                                                        <p className="font-semibold text-slate-200 flex items-center gap-2 mb-2 sm:mb-0">
                                                            <CountryFlag countryCode={race.countryCode} customCountries={customCountries} className="w-6 h-auto rounded-sm" />
                                                            <span>{index + 1}. {race.name}</span>
                                                        </p>
                                                        <button onClick={() => handleViewResults(index)} className="px-4 py-1 bg-[#00e051] text-black font-bold text-sm rounded-md hover:bg-opacity-90 self-end sm:self-center">{t('history_viewResults')}</button>
                                                    </div>
                                                    {podium.length > 0 && (
                                                        <div className="mt-3 pt-3 border-t border-slate-700 flex flex-col sm:flex-row items-start sm:items-center gap-x-6 gap-y-2">
                                                            {podium.map(p => (
                                                                <div key={p.driver.id} className="flex items-center gap-2 text-sm">
                                                                    <span className={`font-black w-6 text-center ${p.position === 1 ? 'text-yellow-400' : 'text-slate-300'}`}>P{p.position}</span>
                                                                    <ImageWithFallback src={p.driver.photoUrl} alt={p.driver.name} primaryColor={p.team.primaryColor} accentColor={p.team.accentColor} initials={getInitials(p.driver.name)} type="driver" className="w-8 h-8 rounded-full object-cover" />
                                                                    <span className="text-slate-200 font-semibold">{p.driver.name}</span>
                                                                </div>
                                                            ))}
                                                        </div>
                                                    )}
                                                </div>
                                            );
                                        })}
                                    </div>
                                )}
                            </div>
                        )}
                    </div>
                )}
        </>
    );
};

export default HistoryScreen;

// FIX: Import 'useMemo' from 'react' to resolve 'Cannot find name' errors.
import React, { useState, useMemo } from 'react';
import { RaceState, Driver, Team, RaceResult, SeasonSettings, Race, QualifyingResult, DriverStanding, Country } from '../types';
import { LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip, Legend, ResponsiveContainer } from 'recharts';
import { useI18n } from '../i18n';
import { SCORING_SYSTEMS } from '../constants';
import { getCountryByCode } from '../utils';
import CountryFlag from './CountryFlag';

type ChartType = 'positions' | 'lapTimes' | 'gap' | 'championshipPosition' | 'championshipPoints' | 'seasonOverview';

interface ChartsViewProps {
    raceHistory: RaceState[];
    drivers: Driver[];
    teams: Team[];
    allRaceResults: RaceResult[][];
    allQualifyingResults: QualifyingResult[][];
    settings: SeasonSettings;
    calendar: Race[];
    driverStandings: DriverStanding[];
    customCountries?: Country[];
}

const ChartsView: React.FC<ChartsViewProps> = ({ raceHistory, drivers, teams, allRaceResults, allQualifyingResults, settings, calendar, driverStandings, customCountries = [] }) => {
    const { t } = useI18n();
    const [activeChart, setActiveChart] = useState<ChartType>(allRaceResults.length > 0 ? 'seasonOverview' : 'positions');

    const positionData = useMemo(() => {
        if (raceHistory.length <= 1) return [];
        return raceHistory.map(state => {
            const lapData: { lap: number; [key: string]: number } = { lap: state.currentLap };
            state.drivers.forEach(driverState => {
                const driver = drivers.find(d => d.id === driverState.driverId);
                if (driver) {
                    lapData[driver.name] = driverState.position > 0 ? driverState.position : drivers.length + 1;
                }
            });
            return lapData;
        });
    }, [raceHistory, drivers]);

    const lapTimeData = useMemo(() => {
        if (raceHistory.length <= 1) return [];
        return raceHistory.slice(1).map(state => {
            const lapData: { lap: number; [key: string]: number | undefined } = { lap: state.currentLap };
            state.drivers.forEach(ds => {
                const driver = drivers.find(d => d.id === ds.driverId);
                if (driver) {
                    lapData[driver.name] = ds.status !== 'DNF' && ds.lastLapTime > 0 ? parseFloat(ds.lastLapTime.toFixed(3)) : undefined;
                }
            });
            return lapData;
        });
    }, [raceHistory, drivers]);

    const gapData = useMemo(() => {
        if (raceHistory.length <= 1) return [];
        return raceHistory.slice(1).map(state => {
            const lapData: { lap: number; [key:string]: number | undefined } = { lap: state.currentLap };
            const leader = state.drivers.find(d => d.position === 1);
            if (leader) {
                state.drivers.forEach(ds => {
                    const driver = drivers.find(d => d.id === ds.driverId);
                    if (driver) {
                        lapData[driver.name] = ds.status !== 'DNF' ? parseFloat((ds.totalTime - leader.totalTime).toFixed(3)) : undefined;
                    }
                });
            }
            return lapData;
        });
    }, [raceHistory, drivers]);

    const championshipPositionData = useMemo(() => {
        if (!allRaceResults || allRaceResults.length === 0 || !settings) return [];

        let historicalStandings: { race: number; [key: string]: number }[] = [];
        let currentStandings = drivers.map(d => ({ driverId: d.id, points: 0 }));

        allRaceResults.forEach((raceResult, index) => {
            raceResult.forEach(result => {
                const standing = currentStandings.find(s => s.driverId === result.driverId);
                if (standing) standing.points += result.points;
            });
            const sortedStandings = [...currentStandings].sort((a, b) => b.points - a.points);
            const raceData: { race: number; [key: string]: number } = { race: index + 1 };
            sortedStandings.forEach((standing, posIndex) => {
                const driver = drivers.find(d => d.id === standing.driverId);
                if (driver) raceData[driver.name] = posIndex + 1;
            });
            historicalStandings.push(raceData);
        });
        return historicalStandings;
    }, [allRaceResults, drivers, settings]);

    const championshipPointsData = useMemo(() => {
        if (!allRaceResults || allRaceResults.length === 0) return [];
        let historicalPoints: { race: number; [key: string]: number }[] = [];
        let currentPoints = drivers.reduce((acc, d) => ({...acc, [d.name]: 0}), {} as {[key: string]: number});

        // Add initial state (0 points before race 1)
        historicalPoints.push({ race: 0, ...currentPoints });

        allRaceResults.forEach((raceResult, index) => {
            raceResult.forEach(result => {
                const driver = drivers.find(d => d.id === result.driverId);
                if (driver) currentPoints[driver.name] += result.points;
            });
            historicalPoints.push({ race: index + 1, ...currentPoints });
        });
        return historicalPoints;
    }, [allRaceResults, drivers]);


    const TabButton: React.FC<{ chartType: ChartType; label: string }> = ({ chartType, label }) => (
        <button onClick={() => setActiveChart(chartType)} className={`px-4 py-2 font-bold uppercase text-sm ${activeChart === chartType ? 'border-b-2 border-[#00e051] text-white' : 'text-slate-400'}`}>{label}</button>
    );

    const SeasonOverview = () => {
        const scoringSystem = SCORING_SYSTEMS.find(s => s.id === settings.scoringSystemId);
        const pointsPositions = scoringSystem ? scoringSystem.points.length : 10;

        const getCellClass = (result: RaceResult | undefined) => {
            if (!result) return 'bg-slate-700/50';
            if (result.position === 0) return 'bg-purple-800 text-purple-200';
            const pos = result.position;
            if (pos === 1) return 'bg-yellow-400 text-black';
            if (pos === 2) return 'bg-slate-400 text-black';
            if (pos === 3) return 'bg-orange-500 text-black';
            if (pos <= pointsPositions) return 'bg-green-700 text-green-100';
            return 'bg-blue-900 text-blue-200';
        };

        const getResultText = (result: RaceResult | undefined) => {
            if (!result) return '-';
            if (result.dnfReason) return 'Ret';
            if (result.position === 0) return 'NC';
            return result.position;
        };

        const races = calendar.slice(0, allRaceResults.length);

        return (
            <div className="bg-slate-500/10 rounded-lg p-2 sm:p-4 overflow-x-auto">
                <table className="w-full border-collapse min-w-[800px]">
                    <thead>
                        <tr className="border-b-2 border-slate-600">
                            <th className="p-2 text-left text-sm font-semibold text-slate-400">Pos.</th>
                            <th className="p-2 text-left text-sm font-semibold text-slate-400 min-w-[150px]">Driver</th>
                            {races.map((race, index) => (
                                <th key={index} className="p-1 sm:p-2 text-center text-sm font-semibold text-slate-400" title={race.name}>
                                    <div className="flex justify-center">
                                        <CountryFlag countryCode={race.countryCode} customCountries={customCountries} className="w-6 mb-1 rounded-sm" />
                                    </div>
                                    {race.countryCode}
                                </th>
                            ))}
                            <th className="p-2 text-right text-sm font-semibold text-slate-400">Points</th>
                        </tr>
                    </thead>
                    <tbody>
                        {driverStandings.map((standing, index) => {
                            const driver = drivers.find(d => d.id === standing.driverId);
                            if (!driver) return null;
                            const country = getCountryByCode(driver.nationality);

                            return (
                            <tr key={driver.id} className="border-b border-slate-800 last:border-0">
                                <td className="p-2 font-bold text-center">{index + 1}</td>
                                <td className="p-2 font-semibold whitespace-nowrap">
                                    <div className="flex items-center gap-2">
                                        <CountryFlag 
                                            countryCode={driver.nationality}
                                            customCountries={customCountries}
                                            alt={country?.name} 
                                            title={country?.name}
                                            className="w-5 h-auto rounded-sm"
                                        />
                                        <span>{driver.name}</span>
                                    </div>
                                </td>
                                {races.map((_, raceIndex) => {
                                    const result = allRaceResults[raceIndex]?.find(r => r.driverId === driver.id);
                                    const quali = allQualifyingResults[raceIndex]?.find(q => q.driverId === driver.id);
                                    const isPole = quali?.position === 1;
                                    const hasFastestLap = result?.fastestLap;

                                    return (
                                        <td key={raceIndex} className={`p-1 sm:p-2 font-black text-center text-sm ${getCellClass(result)}`}>
                                            <div className="flex items-center justify-center gap-0.5">
                                                <span>{getResultText(result)}</span>
                                                <div className="flex flex-col text-[8px] leading-tight font-bold">
                                                    {isPole && <span className="text-purple-400" title="Pole Position">P</span>}
                                                    {hasFastestLap && <span className="text-pink-400" title="Fastest Lap">F</span>}
                                                </div>
                                            </div>
                                        </td>
                                    );
                                })}
                                <td className="p-2 font-bold text-right text-lg">{standing.points}</td>
                            </tr>
                            );
                        })}
                    </tbody>
                </table>
            </div>
        );
    };

    const renderChart = () => {
        let data, yAxisLabel, yAxisReversed, yDomain: [any, any] | undefined, tooltipFormatter, xAxisKey, xAxisLabel;

        switch (activeChart) {
            case 'seasonOverview':
                return <SeasonOverview />;
            case 'lapTimes':
                data = lapTimeData; yAxisLabel = t('lapTime_seconds'); yAxisReversed = false; yDomain = ['dataMin - 1', 'dataMax + 1']; tooltipFormatter = (value: number) => `${value.toFixed(3)}s`; xAxisKey = 'lap'; xAxisLabel = t('lap');
                break;
            case 'gap':
                data = gapData; yAxisLabel = t('gap_seconds'); yAxisReversed = false; yDomain = [0, 'dataMax + 5']; tooltipFormatter = (value: number) => `+${value.toFixed(3)}s`; xAxisKey = 'lap'; xAxisLabel = t('lap');
                break;
            case 'championshipPosition':
                data = championshipPositionData; yAxisLabel = t('championshipPosition'); yAxisReversed = true; yDomain = [1, drivers.length]; tooltipFormatter = (value: number) => `P${value}`; xAxisKey = 'race'; xAxisLabel = t('race');
                break;
            case 'championshipPoints':
                data = championshipPointsData; yAxisLabel = t('points'); yAxisReversed = false; yDomain = [0, 'dataMax + 10']; tooltipFormatter = (value: number) => `${value} ${t('points')}`; xAxisKey = 'race'; xAxisLabel = t('race');
                break;
            case 'positions':
            default:
                data = positionData; yAxisLabel = t('position'); yAxisReversed = true; yDomain = [1, drivers.length]; tooltipFormatter = (value: number) => value > drivers.length ? 'DNF' : `P${value}`; xAxisKey = 'lap'; xAxisLabel = t('lap');
                break;
        }

        if (!data || data.length === 0) {
            return (
                <div className="text-center py-10 flex flex-col items-center justify-center bg-slate-500/10 rounded-lg min-h-[400px]">
                    <p className="text-slate-400 text-lg">{t('charts_noData')}</p>
                    <p className="text-slate-500">{t('charts_noDataHint')}</p>
                </div>
            );
        }

        const CustomTooltip = ({ active, payload, label }: any) => {
            if (active && payload && payload.length) {
                return (
                    <div className="p-2 bg-[#15141f] border border-slate-700 rounded-md shadow-lg">
                        <p className="font-bold text-slate-200">{`${xAxisLabel}: ${label}`}</p>
                        <ul className="text-sm">
                            {payload.sort((a: any, b: any) => yAxisReversed ? a.value - b.value : b.value - a.value).map((p: any) => (
                                <li key={p.name} style={{ color: p.color }}>
                                    {`${p.name}: ${tooltipFormatter(p.value)}`}
                                </li>
                            ))}
                        </ul>
                    </div>
                );
            }
            return null;
        };

        return (
            <div className="bg-slate-500/10 rounded-lg p-4 h-[60vh] min-h-[500px]">
                <ResponsiveContainer width="100%" height="100%">
                    <LineChart data={data} margin={{ top: 5, right: 20, left: 20, bottom: 20 }}>
                        <CartesianGrid strokeDasharray="3 3" stroke="#334155" />
                        <XAxis dataKey={xAxisKey} stroke="#94a3b8" label={{ value: xAxisLabel, position: 'insideBottom', offset: -10, fill: '#94a3b8' }} />
                        <YAxis stroke="#94a3b8" reversed={yAxisReversed} domain={yDomain} tickCount={yAxisReversed ? Math.min(drivers.length, 20) : undefined} interval={0} allowDecimals={false} label={{ value: yAxisLabel, angle: -90, position: 'insideLeft', fill: '#94a3b8' }} />
                        <Tooltip content={<CustomTooltip />} />
                        <Legend wrapperStyle={{fontSize: '12px', bottom: 0 }} />
                        {drivers.map(driver => {
                            const team = teams.find(t => t.id === driver.teamId);
                            return (<Line key={driver.id} type="monotone" dataKey={driver.name} stroke={team?.primaryColor || '#ffffff'} strokeWidth={2} dot={false} activeDot={{ r: 4 }} connectNulls={true} />);
                        })}
                    </LineChart>
                </ResponsiveContainer>
            </div>
        );
    };

    return (
        <div>
            <div className="flex border-b border-slate-700 mb-4 overflow-x-auto">
                {allRaceResults.length > 0 && <TabButton chartType="seasonOverview" label={t('charts_seasonOverview')} />}
                <TabButton chartType="positions" label={t('charts_positions')} />
                <TabButton chartType="lapTimes" label={t('charts_lapTimes')} />
                <TabButton chartType="gap" label={t('charts_gapToLeader')} />
                {allRaceResults.length > 0 && <TabButton chartType="championshipPosition" label={t('charts_championshipPosition')} />}
                {allRaceResults.length > 0 && <TabButton chartType="championshipPoints" label={t('charts_championshipPoints')} />}
            </div>
            {renderChart()}
        </div>
    );
};

export default ChartsView;

import React, { useState, useCallback, useEffect, useRef } from 'react';
import { AppState, SeasonSettings, RaceResult, DriverStanding, ConstructorStanding, Race, Team, Driver, QualifyingResult, RaceState, TyreCompound, LiveDriverState, EngineSupplier, SaveData, WeatherCondition, NewsArticle, AppSkin, QualifyingData, RegulationChangeProposal, SeasonHistory, IncidentType, Incident, Country } from './types';
import { DRIVERS, TEAMS, CALENDAR, SCORING_SYSTEMS, TYRE_COMPOUNDS, ENGINE_SUPPLIERS, DEFAULT_SKIN, DEFAULT_SKINS, PRIZE_MONEY } from './constants';
