const NewsPanel: React.FC<{ news: NewsArticle[], drivers: Driver[], teams: Team[] }> = ({ news, drivers, teams }) => {
    const { t } = useI18n();
    const [expandedArticleId, setExpandedArticleId] = useState<string | null>(null);

    useEffect(() => {
        if (news.length > 0) {
            setExpandedArticleId(news[news.length - 1].id);
        }
    }, [news]);

    const toggleArticle = (id: string) => {
        setExpandedArticleId(prevId => (prevId === id ? null : id));
    };

    const sortedNews = [...news].reverse();

    const entities = useMemo(() => {
        const allEntities = [
            ...drivers.map(d => {
                const team = teams.find(t => t.id === d.teamId);
                return { name: d.name, color: team?.primaryColor || '#FFFFFF', accent: team?.accentColor || '#FFFFFF' };
            }),
            ...teams.map(t => ({ name: t.name, color: t.primaryColor, accent: t.accentColor }))
        ];
        allEntities.sort((a, b) => b.name.length - a.name.length);
        return allEntities;
    }, [drivers, teams]);

    const renderHighlightedBody = (text: string) => {
        if (!text) return '';
        const regex = new RegExp(`(${entities.map(e => e.name.replace(/[-\/\\^$*+?.()|[\]{}]/g, '\\$&')).join('|')})`, 'g');
        const parts = text.split(regex);

        return parts.map((part, index) => {
            const entity = entities.find(e => e.name === part);
            if (entity) {
                const hex = entity.color.replace('#', '');
                if (hex.length < 6) return <span key={index}>{part}</span>;
                const r = parseInt(hex.substring(0, 2), 16);
                const g = parseInt(hex.substring(2, 4), 16);
                const b = parseInt(hex.substring(4, 6), 16);
                const brightness = (r * 299 + g * 587 + b * 114) / 1000;

                const style: React.CSSProperties = {
                    color: entity.color,
                    fontWeight: 'bold',
                    textShadow: brightness < 70 ? `0 0 8px ${entity.accent === '#000000' ? '#FFFFFF' : entity.accent}` : 'none',
                };
                return <span key={index} style={style}>{part}</span>;
            }
            return <React.Fragment key={index}>{part}</React.Fragment>;
        });
    };

    if (news.length === 0) {
        return (
            <div className="text-center py-10 h-full flex items-center justify-center">
                <p className="text-slate-400">{t('news_noNews')}</p>
            </div>
        )
    }

    const TRUNCATE_LENGTH = 250;

    return (
        <div className="space-y-4 overflow-y-auto h-full pr-2">
            {sortedNews.map(article => {
                const isExpanded = expandedArticleId === article.id;
                const isLong = article.body.length > TRUNCATE_LENGTH;

                const bodyContent = isLong && !isExpanded
                    ? `${article.body.substring(0, TRUNCATE_LENGTH)}...`
                    : article.body;

                return (
                    <div key={article.id} className="bg-slate-800/40 border border-slate-700/50 rounded-lg overflow-hidden p-4 animate-fade-in hover:bg-slate-800/60 transition-colors">
                        <p className="text-xs text-slate-400 uppercase mb-1">{article.date}</p>
                        <h4 className="font-bold text-lg text-slate-200 mb-2 leading-tight">{article.headline}</h4>
                        <p className="text-slate-300 text-sm whitespace-pre-line leading-relaxed">
                            {renderHighlightedBody(bodyContent)}
                        </p>
                        {isLong && (
                            <button
                                onClick={() => toggleArticle(article.id)}
                                className="text-xs font-bold mt-2 text-[#00e051] hover:text-green-300 transition-colors uppercase tracking-wider"
                            >
                                {isExpanded ? t('readLess') : t('readMore')}
                            </button>
                        )}
                    </div>
                );
            })}
        </div>
    );
};


interface SimulationScreenProps {
  settings: SeasonSettings;
  currentRaceIndex: number;
  calendar: Race[];
  drivers: Driver[];
  teams: Team[];
  engineSuppliers: EngineSupplier[];
  customCountries: Country[];
  setTeams: React.Dispatch<React.SetStateAction<Team[]>>;
  driverStandings: DriverStanding[];
  constructorStandings: ConstructorStanding[];
  lastRaceResults: RaceResult[] | null;
  allRaceResults: RaceResult[][];
  allQualifyingResults: QualifyingResult[][];
  qualifyingResults: QualifyingResult[] | null;
  qualifyingData: QualifyingData | null;
  news: NewsArticle[];
  history: SeasonHistory[];
  onSimulateQualifying: () => void;
  onSimulateWeekend: () => void;
  onSimulateSeason: () => void;
  onStopSeasonSim: () => void;
  isSeasonSimRunning: boolean;
  onStartRace: (strategies: { driverId: number; startingTyre: TyreCompound }[], startingWeather: WeatherCondition) => void;
  isLoading: boolean;
  error: string | null;
  onBackToMenu: () => void;
  onEndSeason: () => void;
  simulationStatus: 'idle' | 'qualifying' | 'pre-race' | 'race' | 'finished';
  raceState: RaceState | null;
  raceHistory: RaceState[];
  simulationSpeed: number;
  onSetSimulationSpeed: (speed: number) => void;
  isPaused: boolean;
  onPauseToggle: () => void;
  commentary: string;
  onSaveSimulation: () => void;
  determinedWeather: WeatherCondition | null;
}

const SimulationScreen: React.FC<SimulationScreenProps> = ({
  settings,
  currentRaceIndex,
  calendar,
  drivers,
  teams,
  engineSuppliers,
  customCountries,
  setTeams,
  driverStandings,
  constructorStandings,
  lastRaceResults,
  allRaceResults,
  allQualifyingResults,
  qualifyingResults,
  qualifyingData,
  news,
  history,
  onSimulateQualifying,
  onSimulateWeekend,
  onSimulateSeason,
  onStopSeasonSim,
  isSeasonSimRunning,
  onStartRace,
  isLoading,
  error,
  onBackToMenu,
  onEndSeason,
  simulationStatus,
  raceState,
  raceHistory,
  simulationSpeed,
  onSetSimulationSpeed,
  isPaused,
  onPauseToggle,
  commentary,
  onSaveSimulation,
  determinedWeather,
}) => {
  const { t } = useI18n();
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [activeContentKey, setActiveContentKey] = useState(simulationStatus);
  const [isFading, setIsFading] = useState(false);
  const [podiumData, setPodiumData] = useState<RaceResult[] | null>(null);
  const [activeView, setActiveView] = useState<'standings' | 'myTeam' | 'news' | 'charts' | 'history'>('standings');
  const [championData, setChampionData] = useState<{ driverChampion: { driver: Driver, team: Team }, constructorChampion: Team } | null>(null);
  const [selectedProfile, setSelectedProfile] = useState<{ id: number; type: 'driver' | 'constructor' } | null>(null);

  const seasonOver = currentRaceIndex >= calendar.length;
  const currentRace = calendar[currentRaceIndex];
  const isOwnerMode = settings.mode === 'owner';
  const playerTeam = teams.find(t => t.id === settings.playerTeamId);

    const handleOpenProfile = (id: number, type: 'driver' | 'constructor') => {
        setSelectedProfile({ id, type });
    };

    const handleCloseProfile = () => {
        setSelectedProfile(null);
    };

    const handleUpgradeFacility = (facility: keyof Team['facilities']) => {
        if (!playerTeam) return;

        const level = playerTeam.facilities[facility];
        const cost = (level + 1) * 2; // Example cost formula

        if (playerTeam.budget >= cost) {
            if (window.confirm(t('confirm_upgrade_facility', { name: t(`facility_${facility}`), cost, level: level + 1 }))) {
                setTeams(prevTeams => prevTeams.map(t => {
                    if (t.id === playerTeam.id) {
                        return {
                            ...t,
                            budget: t.budget - cost,
                            facilities: {
                                ...t.facilities,
                                [facility]: t.facilities[facility] + 1
                            }
                        };
                    }
                    return t;
                }));
            }
        } else {
            alert(t('error_insufficient_funds'));
        }
    };


  useEffect(() => {
    if (lastRaceResults && simulationStatus === 'finished') {
      setIsModalOpen(true);
      const topThree = lastRaceResults
        .filter(r => r.position > 0 && r.position <= 3)
        .sort((a, b) => a.position - b.position);
      setPodiumData(topThree);
    }
  }, [lastRaceResults, simulationStatus]);

    useEffect(() => {
        if (seasonOver && simulationStatus === 'finished' && !isModalOpen && !podiumData && !championData && driverStandings.length > 0) {
            const driverChampId = driverStandings[0].driverId;
            const driver = drivers.find(d => d.id === driverChampId)!;
            const team = teams.find(t => t.id === driver.teamId)!;
            const constructorChamp = teams.find(t => t.id === constructorStandings[0].teamId)!;

            setChampionData({
                driverChampion: { driver, team },
                constructorChampion: constructorChamp,
            });
        }
    }, [seasonOver, simulationStatus, isModalOpen, podiumData, driverStandings, constructorStandings, drivers, teams, championData]);


  useEffect(() => {
    if (simulationStatus !== activeContentKey) {
        setIsFading(true);
        const timer = setTimeout(() => {
            setActiveContentKey(simulationStatus);
            setIsFading(false);
        }, 300);
        return () => clearTimeout(timer);
    }
  }, [simulationStatus, activeContentKey]);

  const handlePodiumContinue = () => {
    setPodiumData(null);
  };

  const handleBackFromStrategy = () => {
      onSetSimulationSpeed(1);
      setActiveContentKey(lastRaceResults ? 'finished' : 'idle');
  };

  const renderIdleContent = () => {
      if (podiumData || championData) return null; 
      return (
        <div className="flex flex-col h-full overflow-hidden">
            {/* Nav Tabs */}
            <div className="flex border-b border-slate-700 mb-4 bg-[#15141f] sticky top-0 z-10">
                <button onClick={() => setActiveView('standings')} className={`px-4 py-3 font-bold uppercase text-sm border-b-2 transition-colors ${activeView === 'standings' ? 'border-[#00e051] text-white' : 'border-transparent text-slate-400 hover:text-slate-200'}`}>{t('standings')}</button>
                {isOwnerMode && <button onClick={() => setActiveView('myTeam')} className={`px-4 py-3 font-bold uppercase text-sm border-b-2 flex items-center gap-2 transition-colors ${activeView === 'myTeam' ? 'border-[#00e051] text-white' : 'border-transparent text-slate-400 hover:text-slate-200'}`}><UserIcon className="w-4 h-4" />{t('myTeam')}</button>}
                <button onClick={() => setActiveView('news')} className={`px-4 py-3 font-bold uppercase text-sm border-b-2 transition-colors ${activeView === 'news' ? 'border-[#00e051] text-white' : 'border-transparent text-slate-400 hover:text-slate-200'}`}>{t('news')}</button>
                <button onClick={() => setActiveView('charts')} className={`px-4 py-3 font-bold uppercase text-sm border-b-2 transition-colors ${activeView === 'charts' ? 'border-[#00e051] text-white' : 'border-transparent text-slate-400 hover:text-slate-200'}`}>{t('charts')}</button>
                {history.length > 0 && <button onClick={() => setActiveView('history')} className={`px-4 py-3 font-bold uppercase text-sm border-b-2 transition-colors ${activeView === 'history' ? 'border-[#00e051] text-white' : 'border-transparent text-slate-400 hover:text-slate-200'}`}>{t('history_title')}</button>}
            </div>

            {/* View Content Area - Scrollable */}
            <div className="flex-1 overflow-auto min-h-0">
                {activeView === 'standings' ? (
                     <div className="grid grid-cols-1 lg:grid-cols-2 gap-4 h-full">
                        <div className="flex flex-col h-full bg-[#1e1e2b]/50 border border-slate-700/50 rounded-xl overflow-hidden">
                            <StandingsTable title={t('driversChampionship')} standings={driverStandings} type="driver" seasonOver={seasonOver} drivers={drivers} teams={teams} customCountries={customCountries} onRowClick={handleOpenProfile} />
                        </div>
                        <div className="flex flex-col h-full bg-[#1e1e2b]/50 border border-slate-700/50 rounded-xl overflow-hidden">
                            <StandingsTable title={t('constructorsChampionship')} standings={constructorStandings} type="constructor" seasonOver={seasonOver} drivers={drivers} teams={teams} customCountries={customCountries} onRowClick={handleOpenProfile} />
                        </div>
                    </div>
                ) : activeView === 'myTeam' && isOwnerMode && playerTeam ? (
                    <div className="h-full overflow-y-auto">
                        <TeamManagementPanel 
                            team={playerTeam}
                            drivers={drivers.filter(d => d.teamId === playerTeam.id)}
                            engineSupplier={engineSuppliers.find(e => e.name === playerTeam.engineSupplier)!}
                            onUpgradeFacility={handleUpgradeFacility}
                        />
                    </div>
                ) : activeView === 'news' ? (
                    <NewsPanel news={news} drivers={drivers} teams={teams} />
                ) : activeView === 'charts' ? (
                    <div className="h-full overflow-y-auto">
                        <ChartsView
                            raceHistory={raceHistory}
                            drivers={drivers}
                            teams={teams}
                            allRaceResults={allRaceResults}
                            allQualifyingResults={allQualifyingResults}
                            settings={settings}
                            calendar={calendar}
                            driverStandings={driverStandings}
                            customCountries={customCountries}
                        />
                    </div>
                ) : activeView === 'history' ? (
                    <div className="h-full overflow-y-auto">
                        <HistoryScreen history={history} customCountries={customCountries} />
                    </div>
                ) : null}
            </div>
        </div>
      )
  };

  const renderContent = () => {
    if (simulationStatus === 'finished' && !isModalOpen && podiumData && podiumData.length > 0) {
      return (
        <Podium 
          results={podiumData}
          drivers={drivers}
          teams={teams}
          raceName={calendar[currentRaceIndex - 1]?.name || t('grandPrix')}
          onContinue={handlePodiumContinue}
        />
      );
    }

    if (seasonOver && championData) {
        return (
            <ChampionCelebration
                driverChampion={championData.driverChampion}
                constructorChampion={championData.constructorChampion}
                year={settings.startYear}
                onContinue={onEndSeason}
            />
        );
    }

    switch(activeContentKey) {
        case 'race':
            if (raceState) return <LiveRaceView race={currentRace} raceState={raceState} drivers={drivers} teams={teams} commentary={commentary} isPaused={isPaused} settings={settings} customCountries={customCountries} />;
            return null;
        case 'pre-race':
            return <PreRaceStrategyScreen
                qualifyingResults={qualifyingResults!}
                drivers={drivers}
                teams={teams}
                race={currentRace}
                onStartRace={onStartRace}
                weather={determinedWeather!}
                onBack={handleBackFromStrategy}
            />;
        case 'qualifying':
            return <QualifyingInProgressScreen
                qualifyingData={qualifyingData}
                drivers={drivers}
                teams={teams}
            />;
        case 'idle':
        case 'finished':
        default:
             return renderIdleContent();
    }
  }

  return (
    <div className="flex flex-col h-full gap-4">
      {lastRaceResults && qualifyingResults && simulationStatus === 'finished' && (
        <RaceResultModal
          isOpen={isModalOpen}
          onClose={() => setIsModalOpen(false)}
          raceResults={lastRaceResults}
          qualifyingResults={qualifyingResults}
          race={calendar[currentRaceIndex - 1]}
          drivers={drivers}
          teams={teams}
          settings={settings}
          customCountries={customCountries}
        />
      )}

      <ProfileModal
          isOpen={!!selectedProfile}
          onClose={handleCloseProfile}
          profileId={selectedProfile?.id}
          profileType={selectedProfile?.type}
          drivers={drivers}
          teams={teams}
          onSelectProfile={handleOpenProfile}
          allRaceResults={allRaceResults}
          allQualifyingResults={allQualifyingResults}
          customCountries={customCountries}
      />

      <div className="flex-shrink-0 p-4 bg-[#1e1e2b]/80 border border-slate-700 rounded-xl backdrop-blur-sm shadow-lg flex flex-col md:flex-row justify-between items-center gap-4">
        <div>
            <h2 className="text-xl font-bold text-slate-200 uppercase flex items-center gap-2">
               {!seasonOver && <CalendarIcon className="w-5 h-5 text-slate-400" />}
               <span>{seasonOver ? t('seasonFinished') : t('nextRace')}</span>
            </h2>
            <p className="text-lg font-semibold text-white">
                {seasonOver ? t('congratsChampions', { year: settings.startYear }) : currentRace?.name}
            </p>
           {currentRace && !seasonOver && (
             <div className="flex items-center gap-2 text-slate-400 mt-1 text-sm">
               <CountryFlag countryCode={currentRace.countryCode} customCountries={customCountries} className="w-4 h-auto rounded-sm" />
               <span>{t('raceInfo', { round: currentRaceIndex + 1, total: calendar.length, country: currentRace.country })}</span>
             </div>
           )}
        </div>
        <div className="flex flex-col sm:flex-row items-center gap-3">
            {['qualifying', 'race'].includes(simulationStatus) && !isSeasonSimRunning && (
              <SpeedControl currentSpeed={simulationSpeed} onSpeedChange={onSetSimulationSpeed} isPaused={isPaused} onPauseToggle={onPauseToggle} />
            )}
            {['idle', 'finished'].includes(simulationStatus) && !podiumData && !championData && (
                <div className="flex flex-wrap justify-center sm:justify-end items-center gap-3 w-full">
                    {!seasonOver && (
                      <>
                        <button onClick={onSaveSimulation} className="flex items-center justify-center gap-2 px-4 py-2 bg-blue-600/20 text-blue-200 border border-blue-600/50 font-bold uppercase text-xs rounded-lg hover:bg-blue-600/40 transition-colors">
                            <FloppyDiskIcon className="w-4 h-4" /><span>{t('save')}</span>
                        </button>

                        <div className="h-8 w-px bg-slate-700 hidden sm:block"></div>

                        <button onClick={onSimulateQualifying} disabled={isLoading} className="flex items-center justify-center gap-2 px-4 py-2 bg-[#e00601] text-white font-bold uppercase text-xs rounded-lg shadow-md hover:bg-opacity-90 disabled:bg-slate-600 disabled:cursor-not-allowed transition-all">
                            <StopwatchIcon className="w-4 h-4" /><span>{t('simulateQualifying')}</span>
                        </button>

                        <div className="flex gap-2">
                            <button onClick={onSimulateWeekend} disabled={isLoading} className="flex items-center justify-center gap-2 px-3 py-2 bg-slate-700 text-white font-bold uppercase text-xs rounded-lg hover:bg-slate-600 disabled:opacity-50 disabled:cursor-not-allowed transition-all" title={t('simulateRaceWeek')}>
                                <PlayIcon className="w-4 h-4" />
                            </button>
                            <button onClick={onSimulateSeason} disabled={isLoading} className="flex items-center justify-center gap-2 px-3 py-2 bg-slate-700 text-white font-bold uppercase text-xs rounded-lg hover:bg-slate-600 disabled:opacity-50 disabled:cursor-not-allowed transition-all" title={t('simulateSeason')}>
                                <ForwardIcon className="w-4 h-4" />
                            </button>
                        </div>
                      </>
                    )}
                    <button onClick={onBackToMenu} className="flex items-center justify-center gap-2 px-4 py-2 bg-slate-600/50 text-slate-300 font-bold uppercase text-xs rounded-lg hover:bg-slate-500/50 transition-colors">
                        <HomeIcon className="w-4 h-4" /><span>{t('backToMenu')}</span>
                    </button>
                </div>
            )}
        </div>
      </div>

       {isSeasonSimRunning && (
        <div className="p-3 bg-slate-900/80 border border-slate-700 text-slate-200 rounded-lg flex items-center justify-between animate-fade-in flex-shrink-0">
          <div className="flex items-center gap-3">
            <SpinnerIcon />
            <span className="font-bold text-sm">{t('simulatingSeason_progress', { round: currentRaceIndex + 1, total: calendar.length, raceName: currentRace?.name })}</span>
          </div>
          <button onClick={onStopSeasonSim} className="px-3 py-1 bg-red-600 text-white font-bold text-xs uppercase rounded hover:bg-red-500 transition-colors">{t('stop')}</button>
        </div>
       )}

       {error && (
        <div className="p-3 bg-[#e00601]/20 border border-[#e00601]/50 text-red-200 rounded-lg flex-shrink-0">
          <p className="text-sm"><span className="font-bold">{t('error')}:</span> {error}</p>
        </div>
      )}

      <div className={`flex-1 min-h-0 transition-all duration-300 ease-in-out ${isFading ? 'opacity-0 transform -translate-y-4' : 'opacity-100'}`}>
        {renderContent()}
      </div>

    </div>
  );
};

