                                        <button onClick={() => handleDeleteCustomCountry(country.code)} className="p-1.5 text-slate-500 hover:text-[#e00601] transition-colors rounded-full">
                                            <TrashIcon className="w-4 h-4"/>
                                        </button>
                                    </div>
                                ))}
                            </div>
                        </div>
                    </div>
                );
