import React, { useState, useEffect } from 'react';
import { Race, Driver, Team, RaceState, SeasonSettings, Country } from '../types';
import { getCountryFlagUrl, formatTime, getInitials } from '../utils';
import TyreCompoundIcon from './TyreCompoundIcon';
import LiveIcon from './icons/LiveIcon';
import MicrophoneIcon from './icons/MicrophoneIcon';
import PauseIcon from './icons/PauseIcon';
import RaceFlagOverlay from './RaceFlagOverlay';
import { useI18n } from '../i18n';
import ImageWithFallback from './ImageWithFallback';
import { SCORING_SYSTEMS } from '../constants';
import ExclamationTriangleIcon from './icons/ExclamationTriangleIcon';

interface LiveRaceViewProps {
    race: Race;
    raceState: RaceState;
    drivers: Driver[];
    teams: Team[];
    commentary: string;
    isPaused: boolean;
    settings: SeasonSettings;
    customCountries?: Country[];
}

const LiveRaceView: React.FC<LiveRaceViewProps> = ({ race, raceState, drivers, teams, commentary, isPaused, settings, customCountries = [] }) => {
    const { t } = useI18n();
    const [pulse, setPulse] = useState(false);
    const [trackedDriverId, setTrackedDriverId] = useState<number | null>(null);

    const scoringSystem = SCORING_SYSTEMS.find(s => s.id === settings.scoringSystemId);
    const pointsPositions = scoringSystem ? scoringSystem.points.length : 10;

    useEffect(() => {
        if (commentary) {
            setPulse(true);
            const timer = setTimeout(() => setPulse(false), 750);
            return () => clearTimeout(timer);
        }
    }, [commentary]);

    const colorizeCommentary = (comment: string): React.ReactNode => {
        if (!comment) {
            return <span className="text-slate-400">{t('commentary_waiting')}</span>;
        }

        const lapInfoMatch = comment.match(/^(\[.*?\])/);
        const lapInfo = lapInfoMatch ? lapInfoMatch[1] : '';
        const commentText = comment.replace(lapInfo, '').trim();

        const entities = [
            ...drivers.map(d => {
                const team = teams.find(t => t.id === d.teamId);
                return { name: d.name, color: team?.primaryColor || '#FFFFFF', accent: team?.accentColor || '#FFFFFF' };
            }),
            ...teams.map(t => ({ name: t.name, color: t.primaryColor, accent: t.accentColor }))
        ];

        entities.sort((a, b) => b.name.length - a.name.length);

        const regex = new RegExp(`(${entities.map(e => e.name.replace(/[-\/\\^$*+?.()|[\]{}]/g, '\\$&')).join('|')})`, 'g');

        const parts = commentText.split(regex);

        const renderedText = parts.map((part, index) => {
            const entity = entities.find(e => e.name === part);
            if (entity) {
                const hex = entity.color.replace('#', '');
                const r = parseInt(hex.substring(0, 2), 16);
                const g = parseInt(hex.substring(2, 4), 16);
                const b = parseInt(hex.substring(4, 6), 16);
                const brightness = (r * 299 + g * 587 + b * 114) / 1000;

                const style: React.CSSProperties = {
                    color: entity.color,
                    fontWeight: 'bold',
                    textShadow: brightness < 70 ? `0 0 8px ${entity.accent === '#000000' ? '#FFFFFF' : entity.accent}` : 'none',
                };
                return <span key={index} style={style}>{part}</span>;
            }
            return part;
        });

        return (
            <>
                <span className="text-xs text-slate-500 mr-2 font-mono">{lapInfo}</span>
                <span>{renderedText}</span>
            </>
        );
    };

    const sortedDrivers = [...raceState.drivers].sort((a, b) => {
        if (a.status === 'DNF' && b.status !== 'DNF') return 1;
        if (a.status !== 'DNF' && b.status === 'DNF') return -1;
        if (a.status === 'DNF' && b.status === 'DNF') return 0;
        return a.position - b.position;
    });

    const remainingLaps = raceState.totalLaps - raceState.currentLap;
    const remainingLapsText = remainingLaps === 1
        ? t('remaining_laps_singular')
        : t('remaining_laps_plural', { count: remainingLaps });

    const driverToTrackId = trackedDriverId ?? raceState.drivers.find(d => d.position === 1)?.driverId;
    const driverToTrackState = driverToTrackId ? raceState.drivers.find(d => d.driverId === driverToTrackId) : null;
    const driverToTrack = driverToTrackId ? drivers.find(d => d.id === driverToTrackId) : null;
    const teamOfTracked = driverToTrack ? teams.find(t => t.id === driverToTrack.teamId) : null;

    return (
        <div className="h-full flex flex-col lg:flex-row gap-4 animate-fade-in relative overflow-hidden">
            <RaceFlagOverlay flagStatus={raceState.flag} isSafetyCarDeployed={!!raceState.isSafetyCarDeployed} />

            {/* Left Panel: Standings - Takes ample space and scrolls */}
            <div className="flex-1 flex flex-col bg-[#15141f] rounded-xl overflow-hidden border border-slate-700/50 shadow-xl">
                <div className="bg-[#1e1e2b] p-3 text-xs font-bold text-slate-400 uppercase grid grid-cols-12 gap-2 border-b border-slate-700/50">
                    <div className="col-span-1 text-center">{t('pos')}</div>
                    <div className="col-span-5 sm:col-span-4">{t('driver')}</div>
                    <div className="col-span-1 text-center hidden sm:block">{t('pits')}</div>
                    <div className="col-span-2 text-right hidden sm:block">{t('lastLap')}</div>
                    <div className="col-span-2 text-right hidden sm:block">{t('gapAhead')}</div>
                    <div className="col-span-3 sm:col-span-2 text-right">{t('gapLeader')}</div>
                </div>
                <div className="flex-1 overflow-y-auto p-1 space-y-1">
                    {sortedDrivers.map(ds => {
                        const driver = drivers.find(d => d.id === ds.driverId)!;
                        const team = teams.find(t => t.id === driver.teamId)!;
                        const isDNF = ds.status === 'DNF';
                        const isTracked = ds.driverId === driverToTrackId;
                        const isInPoints = !isDNF && ds.position > 0 && ds.position <= pointsPositions;

                        return (
                            <div 
                                key={driver.id} 
                                onClick={() => setTrackedDriverId(ds.driverId)}
                                className={`grid grid-cols-12 gap-2 items-center p-2 rounded-lg text-sm cursor-pointer transition-all duration-150 border border-transparent ${
                                    isDNF ? 'bg-red-900/20 opacity-60' : 
                                    isTracked ? 'bg-slate-700 border-slate-500' : 
                                    isInPoints ? 'bg-[#00e051]/5 hover:bg-[#00e051]/10' :
                                    'bg-slate-800/20 hover:bg-slate-800/40'
                                }`}
                            >
                                <div className="col-span-1 text-center font-bold text-lg font-mono">{isDNF ? 'DNF' : ds.position}</div>
                                <div className="col-span-5 sm:col-span-4 flex items-center gap-2 border-l-4 pl-2" style={{borderColor: team.primaryColor}}>
                                    <ImageWithFallback src={driver.photoUrl} alt={driver.name} primaryColor={team.primaryColor} accentColor={team.accentColor} initials={getInitials(driver.name)} type="driver" className="w-6 h-6 rounded-full object-cover hidden sm:block"/>
                                    <span className={`font-semibold truncate ${isTracked ? 'text-white' : 'text-slate-200'}`}>{driver.name}</span>
                                    {ds.activeIncident && (
                                        <ExclamationTriangleIcon 
                                            className="w-4 h-4 text-yellow-400 flex-shrink-0 animate-pulse" 
                                            title={t(`incident_${ds.activeIncident.type}`)} 
                                        />
                                    )}
                                    <TyreCompoundIcon compound={ds.currentTyres.compound} size={14} className="ml-auto sm:ml-0" />
                                </div>
                                <div className="col-span-1 text-center font-mono text-slate-400 hidden sm:block">{ds.pitStops}</div>
                                <div className="col-span-2 text-right font-mono text-xs hidden sm:block">
                                    {isDNF ? '-' : ds.status === 'PITTING' ? <span className="font-bold text-blue-400 animate-pulse">{t('inPit')}</span> : formatTime(ds.lastLapTime)}
                                </div>
                                <div className="col-span-2 text-right font-mono text-xs text-slate-500 hidden sm:block">{isDNF ? '-' : ds.gapToAhead}</div>
                                <div className="col-span-3 sm:col-span-2 text-right font-mono font-bold text-slate-300">{isDNF ? '-' : ds.gapToLeader}</div>
                            </div>
                        );
                    })}
                </div>
            </div>

            {/* Right Panel: Race Info, Tracker & Commentary - Fixed Width on Desktop */}
            <div className="lg:w-[350px] flex flex-col gap-4 flex-shrink-0 h-full overflow-hidden">
                {/* Race Header */}
                <div className="bg-[#1e1e2b] p-4 rounded-xl border border-slate-700/50 shadow-lg text-center flex-shrink-0">
                    <div className="flex items-center justify-between mb-2">
                        <div className="flex items-center gap-2">
                            <LiveIcon className="h-5 w-auto text-red-500"/>
                            {isPaused && <span className="text-xs bg-yellow-500 text-black px-1.5 rounded font-bold">{t('paused')}</span>}
                        </div>
                        <p className="text-xs font-bold text-slate-500 uppercase tracking-widest">{race.name}</p>
                    </div>
                    <div className="flex items-baseline justify-center gap-1 my-2">
                        <span className="text-6xl font-black text-white tracking-tighter leading-none">{raceState.currentLap}</span>
                        <span className="text-lg font-bold text-slate-500">/ {raceState.totalLaps}</span>
                    </div>
                    {remainingLaps > 0 && (
                        <p className="text-xs text-[#00e051] font-mono border-t border-slate-700 pt-2 mt-2">
                            {remainingLapsText.toUpperCase()}
                        </p>
                    )}
                </div>

                {/* Driver Tracker */}
                {driverToTrack && driverToTrackState && teamOfTracked && (
                    <div className="bg-[#1e1e2b] rounded-xl border border-slate-700/50 shadow-lg overflow-hidden flex-shrink-0">
                        <div className="p-3 bg-gradient-to-r from-slate-800 to-[#1e1e2b] border-b border-slate-700 flex items-center justify-between">
                            <h4 className="font-bold text-xs uppercase tracking-wider text-slate-400">{t('driverTracker')}</h4>
                            <div className="h-2 w-2 rounded-full bg-green-500 animate-pulse"></div>
                        </div>
                        <div className="p-4">
                            <div className="flex items-center gap-4 mb-4">
                                <ImageWithFallback src={driverToTrack.photoUrl} alt={driverToTrack.name} primaryColor={teamOfTracked.primaryColor} accentColor={teamOfTracked.accentColor} initials={getInitials(driverToTrack.name)} type="driver" className="w-14 h-14 rounded-full object-cover ring-2 ring-offset-2 ring-offset-[#1e1e2b]" style={{ringColor: teamOfTracked.primaryColor}}/>
                                <div>
                                    <p className="font-black text-xl text-white leading-none">{driverToTrack.name}</p>
                                    <p className="text-xs font-bold text-slate-400 mt-1 uppercase">{teamOfTracked.name}</p>
                                </div>
                            </div>

                            <div className="grid grid-cols-3 gap-2 mb-4">
                                <div className="bg-[#15141f] p-2 rounded text-center">
                                    <p className="text-[10px] uppercase text-slate-500 mb-1">{t('pos')}</p>
                                    <p className="text-xl font-bold text-white">{driverToTrackState.status === 'DNF' ? 'RET' : `P${driverToTrackState.position}`}</p>
                                </div>
                                <div className="bg-[#15141f] p-2 rounded text-center">
                                    <p className="text-[10px] uppercase text-slate-500 mb-1">{t('tyre')}</p>
                                    <div className="flex justify-center"><TyreCompoundIcon compound={driverToTrackState.currentTyres.compound} size={20}/></div>
                                </div>
                                <div className="bg-[#15141f] p-2 rounded text-center">
                                    <p className="text-[10px] uppercase text-slate-500 mb-1">{t('wear')}</p>
                                    <p className={`text-xl font-bold ${driverToTrackState.currentTyres.wear > 70 ? 'text-red-500' : 'text-white'}`}>{driverToTrackState.currentTyres.wear.toFixed(0)}%</p>
                                </div>
                            </div>

                             <div className="space-y-1 text-xs font-mono bg-[#15141f] p-3 rounded border border-slate-800">
                                <div className="flex justify-between text-slate-400"><span>LAST</span> <span className="text-white">{formatTime(driverToTrackState.lastLapTime)}</span></div>
                                <div className="flex justify-between text-slate-400"><span>BEST</span> <span className="text-[#00e051]">{formatTime(driverToTrackState.bestLapTime)}</span></div>
                                <div className="flex justify-between text-slate-400 border-t border-slate-700 pt-1 mt-1"><span>GAP LDR</span> <span className="text-white">{driverToTrackState.gapToLeader}</span></div>
                            </div>
                        </div>
                    </div>
                )}

                {/* Commentary */}
                <div className="flex-1 bg-[#1e1e2b] rounded-xl border border-slate-700/50 shadow-lg overflow-hidden flex flex-col min-h-0">
                    <div className="p-3 bg-[#15141f] border-b border-slate-700 flex items-center gap-2">
                       <MicrophoneIcon className={`w-4 h-4 transition-transform duration-150 ${pulse ? 'scale-125 text-white' : 'text-slate-500'}`} />
                        <h4 className="font-bold text-xs uppercase tracking-wider text-slate-300">{t('liveCommentary')}</h4>
                    </div>
                    <div className="flex-1 overflow-y-auto p-4 flex flex-col justify-end bg-gradient-to-b from-[#1e1e2b] to-[#15141f]">
                        <p className="text-sm text-slate-200 leading-relaxed animate-fade-in border-l-2 border-[#00e051] pl-3 py-1">
                            {colorizeCommentary(commentary)}
                        </p>
                    </div>
                </div>
            </div>
        </div>
    );
};

