                setDrivers(prev => prev.filter(d => d.id !== driver.id));
                setModalState(null);
            },
        });
    };

    const handleAddTeam = () => {
        const newId = teams.length > 0 ? Math.max(...teams.map(t => t.id)) + 1 : 1;
