                                                    )}
                                                    <div className="flex gap-2">
                                                        <button onClick={() => handleRandomizeDriverStats(driver.id)} className="p-1.5 bg-slate-700 hover:bg-slate-600 rounded text-xs"><DiceIcon className="w-4 h-4 text-white" /></button>
                                                        <button onClick={() => handleRemoveDriver(driver)} className="p-1.5 bg-red-900/50 hover:bg-red-800 rounded text-xs"><TrashIcon className="w-4 h-4 text-red-300" /></button>
                                                    </div>
                                                </div>
                                            </div>
                                        )}
                                    </div>
                                )
                            })}
                        </div>
                    </div>
                );
            case 'teams':
                 return (
                    <div className="h-full flex flex-col">
                        <div className="p-4 bg-slate-900/50 rounded-lg flex justify-end mb-4 flex-shrink-0">
                            <button onClick={handleAddTeam} className="px-3 py-1.5 bg-[#00e051] text-black hover:bg-opacity-90 rounded text-xs font-bold flex items-center gap-2 transition-colors">
                                <PlusIcon className="w-4 h-4" /><span>{t('edit_addTeam')}</span>
                            </button>
                        </div>
                        <div className="overflow-y-auto pr-2 grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-3">
                            {teams.map(team => {
                                const id = `team-${team.id}`;
                                const isExpanded = expandedId === id;
                                return (
                                    <div key={id} className={`bg-slate-800/40 border border-slate-700/50 rounded-lg overflow-hidden transition-all duration-300 ${isExpanded ? 'col-span-1 md:col-span-2 lg:col-span-3 row-span-2 z-10 shadow-xl ring-1 ring-slate-600' : ''}`}>
                                        <div onClick={() => setExpandedId(isExpanded ? null : id)} className="w-full flex items-center p-3 text-left cursor-pointer hover:bg-white/5">
                                            <ImageWithFallback src={team.logoUrl} alt={team.name} primaryColor={team.primaryColor} accentColor={team.accentColor} initials={getInitials(team.name)} type="team" className="h-8 w-10 object-contain flex-shrink-0" />
                                            <p className="ml-3 flex-grow font-bold text-slate-200 text-sm truncate">{team.name}</p>
                                            {!isExpanded && (
                                                <button onClick={(e) => { e.stopPropagation(); handleRemoveTeam(team); }} className="p-1.5 text-slate-500 hover:text-[#e00601] transition-colors rounded-full ml-1"><TrashIcon className="w-4 h-4"/></button>
                                            )}
                                        </div>
                                        {isExpanded && (
                                            <div className="p-4 border-t border-slate-700/50 space-y-4 bg-[#15141f]">
                                                 <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                                                    <div>
                                                        <label className="text-xs text-slate-400 mb-1 block">{t('team')}</label>
                                                        <input type="text" value={team.name} onChange={(e) => handleTeamChange(team.id, 'name', e.target.value)} className="w-full bg-[#101018] p-2 rounded text-sm border border-slate-800 focus:outline-none focus:border-[#00e051]" />
                                                    </div>
                                                    <div>
                                                        <label className="text-xs text-slate-400 mb-1 block">{t('nationality')}</label>
                                                        <CountrySelector customCountries={customCountries} value={team.nationality} onChange={(e) => handleTeamChange(team.id, 'nationality', e.target.value)} className="w-full bg-[#101018] p-2 rounded text-sm border border-slate-800" />
                                                    </div>
                                                    <ImageUploader id={team.id} currentImage={team.logoUrl} onUpload={(e) => handleImageUpload(team.id, 'team', e)} onRemove={() => handleTeamChange(team.id, 'logoUrl', '')} type="team" />
                                                    <div>
                                                        <label className="text-xs text-slate-400 mb-1 block">{t('engine')}</label>
                                                        <select value={team.engineSupplier} onChange={(e) => handleTeamChange(team.id, 'engineSupplier', e.target.value)} className="w-full bg-[#101018] p-2 rounded text-sm border border-slate-800 focus:outline-none focus:border-[#00e051]">
                                                            {engineSuppliers.map(supplier => (<option key={supplier.name} value={supplier.name} className="bg-[#1e1e2b]">{supplier.name}</option>))}
                                                            <option value={team.name} className="bg-[#1e1e2b]">{t('edit_inHouse')}</option>
                                                        </select>
                                                    </div>
                                                 </div>
                                                <div className="grid grid-cols-3 sm:grid-cols-6 gap-2">
                                                    <EditableStatInput label="Aer" min={50} max={100} value={team.aerodynamics} onChange={(v) => handleTeamChange(team.id, 'aerodynamics', v)} />
                                                    <EditableStatInput label="Gea" min={50} max={100} value={team.gearbox} onChange={(v) => handleTeamChange(team.id, 'gearbox', v)} />
                                                    <EditableStatInput label="Brk" min={50} max={100} value={team.brakes} onChange={(v) => handleTeamChange(team.id, 'brakes', v)} />
                                                    <EditableStatInput label="Ele" min={50} max={100} value={team.electricalSystem} onChange={(v) => handleTeamChange(team.id, 'electricalSystem', v)} />
                                                    <EditableStatInput label="Str" min={50} max={100} value={team.steering} onChange={(v) => handleTeamChange(team.id, 'steering', v)} />
                                                    <EditableStatInput label="Rel" min={50} max={100} value={team.reliability} onChange={(v) => handleTeamChange(team.id, 'reliability', v)} />
                                                </div>
                                                <div className="grid grid-cols-2 gap-4">
                                                    <ColorInput label={t('edit_primaryColor')} value={team.primaryColor} onChange={(e) => handleTeamChange(team.id, 'primaryColor', e.target.value)} />
                                                    <ColorInput label={t('edit_accentColor')} value={team.accentColor} onChange={(e) => handleTeamChange(team.id, 'accentColor', e.target.value)} />
                                                </div>
                                                <div className="flex justify-end pt-2 border-t border-slate-800">
                                                    <button onClick={() => handleRemoveTeam(team)} className="px-3 py-1.5 bg-red-900/50 hover:bg-red-800 rounded text-xs font-bold flex items-center gap-2 text-red-200"><TrashIcon className="w-4 h-4" /> <span>{t('delete')}</span></button>
                                                </div>
                                            </div>
                                        )}
                                    </div>
                                )
                            })}
                        </div>
                    </div>
                );
            case 'calendar':
                return (
                     <div className="h-full flex flex-col">
                        <div className="p-4 bg-slate-900/50 rounded-lg flex justify-end mb-4 flex-shrink-0">
                            <button onClick={handleAddRace} className="px-3 py-1.5 bg-[#00e051] text-black hover:bg-opacity-90 rounded text-xs font-bold flex items-center gap-2 transition-colors">
                                <PlusIcon className="w-4 h-4" /><span>{t('edit_addRace')}</span>
                            </button>
                        </div>
                        <div className="overflow-y-auto pr-2 grid grid-cols-1 md:grid-cols-2 gap-3">
                            {calendar.map((race, index) => {
                                 const id = `race-${index}`;
                                 const isExpanded = expandedId === id;
                                const handleWeatherChanceChange = (type: 'Dry' | 'LightRain' | 'HeavyRain', value: string) => {
                                    const newChances = { ...race.weatherChances };
                                    const numValue = parseInt(value, 10);
                                    const validNum = isNaN(numValue) ? 0 : Math.max(0, Math.min(100, numValue));

                                    const otherSum = (type === 'Dry' ? 0 : newChances.Dry*100) + (type === 'LightRain' ? 0 : newChances.LightRain*100) + (type === 'HeavyRain' ? 0 : newChances.HeavyRain*100);
                                    if (validNum + otherSum > 100) return; // Prevent going over 100

                                    newChances[type] = validNum / 100;

                                    handleRaceChange(index, 'weatherChances', newChances);
                                };
                                return (
                                    <div key={index} className="bg-slate-800/40 border border-slate-700/50 rounded-lg overflow-hidden transition-all duration-300">
                                        <div onClick={() => setExpandedId(isExpanded ? null : id)} className="w-full flex items-center p-3 text-left cursor-pointer hover:bg-white/5">
                                            <span className="text-slate-500 font-mono text-xs w-6">{index + 1}</span>
                                            <p className="flex-grow font-bold text-slate-200 text-sm truncate">{race.name}</p>
                                            <div className="flex items-center gap-2">
                                                <CountryFlag countryCode={race.countryCode} customCountries={customCountries} className="w-5 h-auto rounded-sm opacity-70" />
                                                {!isExpanded && (
                                                    <button onClick={(e) => { e.stopPropagation(); handleRemoveRace(race, index); }} className="p-1.5 text-slate-500 hover:text-[#e00601] transition-colors rounded-full"><TrashIcon className="w-4 h-4"/></button>
                                                )}
                                            </div>
                                        </div>
                                        {isExpanded && (
                                            <div className="p-4 border-t border-slate-700/50 space-y-4 bg-[#15141f]">
                                                <div>
                                                    <label className="text-xs text-slate-400 mb-1 block">{t('edit_gpName')}</label>
                                                    <input type="text" value={race.name} onChange={(e) => handleRaceChange(index, 'name', e.target.value)} className="w-full bg-[#101018] p-2 rounded text-sm border border-slate-800 focus:outline-none focus:border-[#00e051]" />
                                                </div>
                                                <div className="grid grid-cols-2 gap-4">
                                                    <div>
                                                        <label className="text-xs text-slate-400 mb-1 block">{t('country')}</label>
                                                        <CountrySelector customCountries={customCountries} value={race.countryCode} onChange={(e) => handleRaceCountryChange(index, e.target.value)} className="w-full bg-[#101018] p-2 rounded text-sm border border-slate-800" />
                                                    </div>
                                                    <div>
                                                        <label className="text-xs text-slate-400 mb-1 block">{t('baseTime')}</label>
                                                        <input type="text" value={race.baseLapTime} onChange={(e) => handleRaceChange(index, 'baseLapTime', e.target.value)} className="w-full bg-[#101018] p-2 rounded text-sm border border-slate-800 focus:outline-none focus:border-[#00e051]" placeholder="1:30.252" />
                                                    </div>
                                                </div>
                                                <div className="flex gap-4 items-end">
                                                    <EditableStatInput className="w-20" label={t('laps')} min={1} max={200} value={race.laps} onChange={(v) => handleRaceChange(index, 'laps', v)} />
                                                    <div className="flex-1 p-2 bg-[#101018] rounded border border-slate-800 grid grid-cols-3 gap-2">
                                                        {['Dry', 'LightRain', 'HeavyRain'].map(type => (
                                                            <div key={type} className="text-center">
                                                                <label className="text-[9px] uppercase text-slate-500 block">{t(`weather_${type.toLowerCase()}` as any)}</label>
                                                                <input type="number" min="0" max="100" value={Math.round(race.weatherChances[type as keyof typeof race.weatherChances] * 100)} onChange={(e) => handleWeatherChanceChange(type as any, e.target.value)} className="w-full text-center bg-transparent text-xs font-mono text-slate-300 focus:outline-none" />
                                                            </div>
                                                        ))}
                                                    </div>
                                                </div>
                                                <div className="flex justify-end pt-2 border-t border-slate-800">
                                                    <button onClick={() => handleRemoveRace(race, index)} className="px-3 py-1.5 bg-red-900/50 hover:bg-red-800 rounded text-xs font-bold flex items-center gap-2 text-red-200"><TrashIcon className="w-4 h-4" /> <span>{t('delete')}</span></button>
                                                </div>
                                            </div>
                                        )}
                                    </div>
                                )
                            })}
                        </div>
                    </div>
                );
            case 'engines':
                return (
                    <div className="h-full flex flex-col">
                         <div className="p-4 bg-slate-900/50 rounded-lg flex justify-end mb-4 flex-shrink-0">
                            <button onClick={handleAddEngineSupplier} className="px-3 py-1.5 bg-[#00e051] text-black hover:bg-opacity-90 rounded text-xs font-bold flex items-center gap-2 transition-colors">
                                <PlusIcon className="w-4 h-4" /><span>{t('edit_addEngine')}</span>
                            </button>
                        </div>
                        <div className="overflow-y-auto pr-2 grid grid-cols-1 md:grid-cols-2 gap-4">
                            {engineSuppliers.map(supplier => (
                                <div key={supplier.name} className="p-4 bg-slate-800/40 border border-slate-700/50 rounded-lg">
                                    <div className="flex justify-between items-start mb-4">
                                        <div className="flex-1 mr-4">
                                            <label className="text-xs text-slate-400 mb-1 block">{t('edit_supplierName')}</label>
                                            <input type="text" value={supplier.name} onChange={(e) => handleEngineSupplierChange(supplier.name, 'name', e.target.value)} className="w-full bg-[#101018] p-2 rounded text-sm border border-slate-800 focus:outline-none focus:border-[#00e051]" />
                                        </div>
                                        <button onClick={() => handleRemoveEngineSupplier(supplier)} className="p-2 text-slate-500 hover:text-[#e00601] transition-colors"><TrashIcon className="w-5 h-5"/></button>
                                    </div>
                                    <EditableStatInput label={t('performance')} min={50} max={100} value={supplier.performance} onChange={(v) => handleEngineSupplierChange(supplier.name, 'performance', v)} />
                                </div>
                            ))}
                        </div>
                    </div>
                );
            case 'countries':
                return (
                    <div className="h-full flex flex-col">
                        <div className="p-4 bg-slate-900/50 border border-slate-700 rounded-lg mb-4 flex-shrink-0">
                            <h3 className="font-bold text-slate-200 text-sm mb-3 uppercase tracking-wider">{t('create_country')}</h3>
                            <div className="flex flex-col sm:flex-row gap-4 items-end">
                                <div className="flex-1 w-full">
                                    <label className="text-xs text-slate-400 mb-1 block">{t('country_name')}</label>
                                    <input 
                                        type="text" 
                                        value={newCountryName} 
                                        onChange={(e) => setNewCountryName(e.target.value)} 
                                        placeholder={t('country_name')}
                                        className="w-full bg-[#101018] p-2 rounded text-sm border border-slate-800 focus:outline-none focus:border-[#00e051]" 
                                    />
                                </div>
                                <div className="w-full sm:w-auto">
                                    <label className="text-xs text-slate-400 mb-1 block">{t('country_flag')}</label>
                                    <div className="flex items-center gap-2">
                                        <input ref={newCountryInputRef} type="file" accept="image/*" className="hidden" id="new-country-flag" />
                                        <label htmlFor="new-country-flag" className="cursor-pointer px-3 py-2 bg-slate-700 hover:bg-slate-600 rounded text-xs flex items-center justify-center gap-2 transition-colors border border-slate-600 text-slate-200">
                                            <CloudArrowUpIcon className="w-4 h-4" />
                                            <span>{t('edit_uploadImage')}</span>
                                        </label>
                                    </div>
                                </div>
                                <button 
                                    onClick={handleCreateCustomCountry}
                                    disabled={!newCountryName.trim()} 
                                    className="w-full sm:w-auto px-4 py-2 bg-[#00e051] text-black hover:bg-opacity-90 rounded text-sm font-bold flex items-center justify-center gap-2 transition-colors disabled:bg-slate-600 disabled:text-slate-400 disabled:cursor-not-allowed"
                                >
                                    <PlusIcon className="w-4 h-4" /><span>{t('create_country_btn')}</span>
                                </button>
                            </div>
                        </div>

                        <div className="flex-1 overflow-y-auto pr-2">
                            {customCountries.length === 0 && <p className="text-slate-500 text-center py-10 italic text-sm">{t('no_custom_countries')}</p>}
                            <div className="grid grid-cols-1 sm:grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-3">
                                {customCountries.map(country => (
                                    <div key={country.code} className="flex items-center justify-between p-3 bg-slate-800/40 border border-slate-700/50 rounded-lg">
                                        <div className="flex items-center gap-3">
                                            <CountryFlag countryCode={country.code} customCountries={customCountries} className="w-8 h-auto rounded-sm border border-slate-600" />
                                            <span className="font-bold text-slate-200 text-sm">{country.name}</span>
                                        </div>
                                        <button onClick={() => handleDeleteCustomCountry(country.code)} className="p-1.5 text-slate-500 hover:text-[#e00601] transition-colors rounded-full">
                                            <TrashIcon className="w-4 h-4"/>
                                        </button>
                                    </div>
                                ))}
                            </div>
                        </div>
                    </div>
                );
        }
    };

    return (
        <div className="h-full flex flex-col p-0">
             <PromptModal
                isOpen={!!modalState?.isOpen}
                title={modalState?.title || ''}
                message={modalState?.message}
                defaultValue={null}
                onConfirm={() => modalState?.onConfirm()}
                onCancel={() => setModalState(null)}
            />
            <input type="file" ref={importInputRef} onChange={handleImportDatabase} accept=".json" style={{display: 'none'}} />

            <div className="bg-[#1e1e2b]/95 border border-slate-700 rounded-xl backdrop-blur-md shadow-2xl flex flex-col h-full overflow-hidden">
                <div className="flex-shrink-0 flex flex-wrap justify-between items-center p-4 border-b border-slate-700 gap-4 bg-[#15141f]">
                    <h2 className="text-2xl font-black uppercase text-slate-200 tracking-wider">{isOffSeason ? t('offSeasonEditor') : t('editor')}</h2>
                    <div className="flex items-center gap-2 flex-wrap">
                         <button onClick={() => importInputRef.current?.click()} className="px-3 py-1.5 text-xs bg-slate-700 text-slate-300 font-bold uppercase rounded hover:bg-slate-600 flex items-center justify-center gap-2 transition-colors">
                            <CloudArrowUpIcon className="w-4 h-4" />
                            <span>{t('edit_importDatabase')}</span>
                        </button>
                        <button onClick={handleExportDatabase} className="px-3 py-1.5 text-xs bg-slate-700 text-slate-300 font-bold uppercase rounded hover:bg-slate-600 flex items-center justify-center gap-2 transition-colors">
                            <CloudArrowUpIcon className="w-4 h-4 -scale-y-100" />
                            <span>{t('edit_exportDatabase')}</span>
                        </button>
                        {isOffSeason ? (
                            <button onClick={onBackToMenu} className="px-4 py-1.5 bg-[#e00601] text-white font-bold text-xs uppercase rounded hover:bg-opacity-90 flex items-center justify-center gap-2 transition-colors shadow-lg shadow-red-900/20">
                                <CheckeredFlagIcon className="w-4 h-4" /><span>{t('startNextSeason')}</span>
                            </button>
                        ) : (
                             <button onClick={onBackToMenu} className="px-4 py-1.5 bg-slate-700 text-slate-200 font-bold text-xs uppercase rounded hover:bg-slate-600 flex items-center justify-center gap-2 transition-colors">
                                <HomeIcon className="w-4 h-4" /><span>{t('back')}</span>
                            </button>
                        )}
                    </div>
                </div>
                <div className="flex-shrink-0 flex overflow-x-auto border-b border-slate-700 bg-[#15141f] px-2">
                    <TabButton tab="drivers" label={t('drivers')} icon={<UserIcon className="w-4 h-4"/>} />
                    <TabButton tab="teams" label={t('teams')} icon={<UserGroupIcon className="w-4 h-4"/>} />
                    <TabButton tab="calendar" label={t('calendar')} icon={<CalendarIcon className="w-4 h-4"/>} />
                    <TabButton tab="engines" label={t('engines')} icon={<CogIcon className="w-4 h-4"/>} />
                    <TabButton tab="countries" label={t('countries')} icon={<FlagIcon className="w-4 h-4"/>} />
                </div>
                <div className="flex-1 overflow-hidden p-4 sm:p-6 bg-gradient-to-br from-[#1e1e2b] to-[#15141f]">
                    {renderContent()}
                </div>
            </div>
        </div>
    );
};

export default EditMenu;

// FIX: Import TranslationKey for type safety with i18n keys.
import { TranslationKey } from './i18n';

export enum AppState {
    MainMenu,
    Settings,
    Simulation,
    Edit,
    OffSeason,
    LoadGame,
    RegulationChanges,
    TeamOwnerSetup,
}

export interface Country {
    code: string;
    name: string;
    isCustom?: boolean;
    flagUrl?: string; // Base64 for custom countries
}

export interface Driver {
    id: number;
    name: string;
    teamId: number;
    // Skills (1-10)
    startSkill: number;
    concentration: number;
    overtaking: number;
    experience: number;
    speed: number;
    rainSkill: number;
    setupSkill: number;
    physical: number;
    // Potential (0.0 - 10.0)
    potential: number;
    age: number;
    nationality: string; // Country code e.g., 'GB'
    photoUrl?: string;
    salary: number; // Yearly salary
    contractEndsYear: number;
}

export interface Team {
    id: number;
    name: string;
    nationality: string; // Team nationality code
    aerodynamics: number; // 50-100
    gearbox: number; // 50-100
    brakes: number; // 50-100
    electricalSystem: number; // 50-100
    steering: number; // 50-100
    engineSupplier: string; // Name of supplier
    reliability: number; // Fiabilidade: 50-100
    primaryColor: string; // e.g., "#00D2BE" for Mercedes primary
    accentColor: string; // e.g., "#FFFFFF" for Mercedes accent
    logoUrl?: string;
    budget: number; // Team budget in millions
    facilities: {
        aero: number; // Level 1-20
        chassis: number; // Level 1-20
        powertrain: number; // Level 1-20
        reliability: number; // Level 1-20
    };
}

export type WeatherCondition = 'Dry' | 'LightRain' | 'HeavyRain';

export interface Race {
    name: string;
    country: string;
    countryCode: string;
    laps: number;
    baseLapTime: string; // format "1:30.252"
    weatherChances: {
        Dry: number; // 0.0 to 1.0
        LightRain: number;
        HeavyRain: number;
    };
}

export interface ScoringSystem {
    id: number;
    name: TranslationKey;
    points: number[]; // e.g., [25, 18, 15, ...]
}

export interface SeasonSettings {
    startYear: number;
    scoringSystemId: number;
    mode: 'spectator' | 'owner';
    playerTeamId: number | null;
}

export interface QualifyingResult {
    driverId: number;
    position: number;
    lapTime: string; // e.g., "1:28.123"
    lapTimeInSeconds?: number;
    eliminatedIn?: 'Q1' | 'Q2';
    status?: 'Qualified' | 'DNQ'; // Did not qualify (107% rule)
}

export interface QualifyingData {
    q1: QualifyingResult[];
    q2: QualifyingResult[];
    q3: QualifyingResult[];
}

export interface RaceResult {
    driverId: number;
    position: number; // 0 para DNF
    fastestLap: boolean;
    points: number;
    pitStops: number;
    bestLapTime: string;
    dnfReason?: string;
}

export interface DriverStanding {
    driverId: number;
    points: number;
}

export interface ConstructorStanding {
    teamId: number;
    points: number;
}

// Types for Live Simulation Engine
export enum TyreCompound {
    Soft = 'Soft',
    Medium = 'Medium',
    Hard = 'Hard',
    Intermediate = 'Intermediate',
    Wet = 'Wet',
}

export interface Tyre {
    compound: TyreCompound;
    wear: number; // 0-100
    age: number; // laps
}

export enum IncidentType {
    FrontWingDamage = 'FrontWingDamage',
    ElectronicGlitch = 'ElectronicGlitch',
    LockUp = 'LockUp',
    GearboxSyncIssue = 'GearboxSyncIssue',
}

export interface Incident {
    type: IncidentType;
    lapsRemaining: number;
    performancePenalty: number; // in seconds per lap
}

export interface LiveDriverState {
    driverId: number;
    position: number;
    totalTime: number; // in seconds
    lastLapTime: number; // in seconds
    bestLapTime: number; // in seconds
    gapToLeader: string;
    gapToAhead: string;
    currentTyres: Tyre;
    pitStops: number;
    status: 'RACING' | 'PITTING' | 'DNF';
    dnfReason?: string;
    activeIncident: Incident | null;
}

export interface RaceState {
    currentLap: number;
    totalLaps: number;
    drivers: LiveDriverState[];
    currentWeather: WeatherCondition;
    flag?: 'green' | 'yellow' | 'red' | 'checkered';
    isSafetyCarDeployed?: boolean;
    safetyCarLapsRemaining?: number;
    scWasDeployedThisLap?: boolean; // Used to bunch up cars only once
}

export interface EngineSupplier {
    name: string;
    performance: number; // 50-100
    cost: number; // Yearly cost in millions
}

export interface NewsArticle {
    id: string;
    raceIndex: number;
    headline: string;
    body: string;
    date: string;
}

