import React, { useState, useMemo, useRef, useEffect } from 'react';
import { Driver, Team, Race, EngineSupplier, Country } from '../types';
import { COUNTRIES } from '../constants';
import CountrySelector from './CountrySelector';
import TrashIcon from './icons/TrashIcon';
import HomeIcon from './icons/HomeIcon';
import UserIcon from './icons/UserIcon';
import UserGroupIcon from './icons/UserGroupIcon';
import CalendarIcon from './icons/CalendarIcon';
import PlusIcon from './icons/PlusIcon';
import CloudArrowUpIcon from './icons/CloudArrowUpIcon';
import DiceIcon from './icons/DiceIcon';
import CogIcon from './icons/CogIcon';
import CheckeredFlagIcon from './icons/CheckeredFlagIcon';
import FlagIcon from './icons/FlagIcon';
import { useI18n } from '../i18n';
import ImageWithFallback from './ImageWithFallback';
import { getInitials } from '../utils';
import PromptModal from './PromptModal';
import CountryFlag from './CountryFlag';

interface EditMenuProps {
    drivers: Driver[];
    teams: Team[];
    calendar: Race[];
    engineSuppliers: EngineSupplier[];
    customCountries: Country[];
    setDrivers: React.Dispatch<React.SetStateAction<Driver[]>>;
    setTeams: React.Dispatch<React.SetStateAction<Team[]>>;
    setCalendar: React.Dispatch<React.SetStateAction<Race[]>>;
    setEngineSuppliers: React.Dispatch<React.SetStateAction<EngineSupplier[]>>;
    setCustomCountries: (countries: Country[]) => void;
    onBackToMenu: () => void;
    isOffSeason?: boolean;
    hidePotential: boolean;
    setHidePotential: React.Dispatch<React.SetStateAction<boolean>>;
    onRandomizeAllPotentials: () => void;
}

type EditTab = 'drivers' | 'teams' | 'calendar' | 'engines' | 'countries';

// --- HELPER COMPONENTS ---

const EditableStatInput: React.FC<{
    label: string;
    value: number;
    onChange: (newValue: number) => void;
    min: number;
    max: number;
    step?: number;
    className?: string;
    isFloat?: boolean;
}> = ({ label, value, onChange, min, max, step = 1, className = '', isFloat = false }) => {
    const [displayValue, setDisplayValue] = useState(String(value));

    useEffect(() => {
        if (document.activeElement !== document.getElementById(label)) {
            setDisplayValue(String(value));
        }
    }, [value, label]);

    const handleBlur = () => {
        let num = isFloat ? parseFloat(displayValue) : parseInt(displayValue, 10);
        if (isNaN(num)) {
            num = min;
        }
        const clamped = Math.max(min, Math.min(max, num));
        const finalValue = isFloat ? parseFloat(clamped.toFixed(1)) : clamped;

        if (finalValue !== value) {
            onChange(finalValue);
        }
        setDisplayValue(String(finalValue));
    };

    return (
        <div className={className}>
            <label htmlFor={label} className="text-[10px] uppercase text-slate-500 mb-0.5 block font-bold">{label}</label>
            <input
                id={label} 
                type="number" 
                min={min} 
                max={max} 
                step={step}
                value={displayValue} 
                onChange={(e) => setDisplayValue(e.target.value)} 
                onBlur={handleBlur}
                className="w-full bg-[#101018] p-1.5 rounded text-xs border border-slate-800 focus:outline-none focus:border-[#00e051] text-center font-mono text-slate-200" 
            />
        </div>
    );
};

// --- MAIN COMPONENT ---

const EditMenu: React.FC<EditMenuProps> = ({
    drivers,
    teams,
    calendar,
    engineSuppliers,
    customCountries,
    setDrivers,
    setTeams,
    setCalendar,
    setEngineSuppliers,
    setCustomCountries,
    onBackToMenu,
    isOffSeason = false,
    hidePotential,
    setHidePotential,
    onRandomizeAllPotentials,
}) => {
    const { t } = useI18n();
    const [activeTab, setActiveTab] = useState<EditTab>('drivers');
    const [expandedId, setExpandedId] = useState<string | null>(null);
    const [modalState, setModalState] = useState<{
        isOpen: boolean;
        title: string;
        message: string;
        onConfirm: () => void;
    } | null>(null);
    const importInputRef = useRef<HTMLInputElement>(null);
    const newCountryInputRef = useRef<HTMLInputElement>(null);
    const [newCountryName, setNewCountryName] = useState('');

    const driverCountsByTeam = useMemo(() => {
        return teams.reduce((acc, team) => {
            acc[team.id] = drivers.filter(d => d.teamId === team.id).length;
            return acc;
        }, {} as Record<number, number>);
    }, [drivers, teams]);

    const isAnyTeamAvailable = useMemo(() => teams.some(t => (driverCountsByTeam[t.id] || 0) < 2), [teams, driverCountsByTeam]);

    const handleDriverChange = (id: number, field: keyof Driver, value: string | number) => {
        if (field === 'teamId') {
            const driver = drivers.find(d => d.id === id);
            if (driver && driver.teamId !== value) {
                const oldTeamDriverCount = driverCountsByTeam[driver.teamId];
                if (oldTeamDriverCount <= 1) {
                    alert(t('edit_error_lastDriver'));
                    return;
                }
            }
        }
        setDrivers(prev => prev.map(d => d.id === id ? { ...d, [field]: value } : d));
    };

    const handleTeamChange = (id: number, field: keyof Team, value: string | number) => {
        setTeams(prev => prev.map(t => t.id === id ? { ...t, [field]: value } : t));
    };

    const handleImageUpload = (id: number, type: 'driver' | 'team', e: React.ChangeEvent<HTMLInputElement>) => {
        const file = e.target.files?.[0];
        if (!file || !file.type.startsWith('image/')) return;

        const reader = new FileReader();
        reader.onload = (event) => {
            const dataUrl = event.target?.result as string;
            if (type === 'driver') {
                setDrivers(prev => prev.map(d => d.id === id ? { ...d, photoUrl: dataUrl } : d));
            } else {
                setTeams(prev => prev.map(t => t.id === id ? { ...t, logoUrl: dataUrl } : t));
            }
        };
        reader.readAsDataURL(file);
    };

    const handleRaceChange = (index: number, field: keyof Race, value: string | number | Race['weatherChances']) => {
        setCalendar(prev => prev.map((r, i) => {
            if (i !== index) return r;
            let updatedRace = { ...r };
            if (field === 'weatherChances') {
                updatedRace.weatherChances = value as Race['weatherChances'];
            } else if (field === 'laps') {
                const lapsNum = parseInt(String(value), 10);
                (updatedRace as any)[field] = isNaN(lapsNum) || lapsNum < 1 ? 1 : lapsNum;
            } else {
                (updatedRace as any)[field] = value;
            }
            return updatedRace;
        }));
    };

    const handleRaceCountryChange = (index: number, countryCode: string) => {
        const country = [...COUNTRIES, ...customCountries].find(c => c.code === countryCode);
        if (country) {
            setCalendar(prev => prev.map((r, i) =>
                i === index ? { ...r, country: country.name, countryCode: country.code } : r
            ));
        }
    };

    const handleRandomizeDriverStats = (id: number) => {
        setDrivers(prev => prev.map(d => {
            if (d.id === id) {
                return {
                    ...d,
                    startSkill: Math.floor(Math.random() * 10) + 1,
                    concentration: Math.floor(Math.random() * 10) + 1,
                    overtaking: Math.floor(Math.random() * 10) + 1,
                    experience: Math.floor(Math.random() * 10) + 1,
                    speed: Math.floor(Math.random() * 10) + 1,
                    rainSkill: Math.floor(Math.random() * 10) + 1,
                    setupSkill: Math.floor(Math.random() * 10) + 1,
                    physical: Math.floor(Math.random() * 10) + 1,
                    potential: !hidePotential ? parseFloat((1 + Math.random() * 9).toFixed(1)) : parseFloat((6.5 + (Math.random() - 0.5) * 7).toFixed(1)),
                };
            }
            return d;
        }));
    };

    const handleAddDriver = () => {
        const availableTeam = teams.find(t => (driverCountsByTeam[t.id] || 0) < 2);
        if (!availableTeam) {
            alert(t('edit_error_allTeamsFull'));
            return;
        }
        const newId = drivers.length > 0 ? Math.max(...drivers.map(d => d.id)) + 1 : 1;
        const newDriver: Driver = { id: newId, name: t('newDriver'), teamId: availableTeam.id, age: 25, nationality: 'BR', photoUrl: '', startSkill: 5, concentration: 5, overtaking: 5, experience: 5, speed: 5, rainSkill: 5, setupSkill: 5, physical: 5, potential: 7.5, salary: 1, contractEndsYear: new Date().getFullYear() + 1 };
        setDrivers(prev => [...prev, newDriver]);
    };

    const handleRemoveDriver = (driver: Driver) => {
        setModalState({
            isOpen: true,
            title: t('confirm_delete_driver_title'),
            message: t('confirm_delete_message', { name: driver.name }),
            onConfirm: () => {
                setDrivers(prev => prev.filter(d => d.id !== driver.id));
                setModalState(null);
            },
        });
    };

    const handleAddTeam = () => {
        const newId = teams.length > 0 ? Math.max(...teams.map(t => t.id)) + 1 : 1;
        const newTeam: Team = { id: newId, name: t('newTeam'), nationality: 'GB', aerodynamics: 70, gearbox: 70, brakes: 70, electricalSystem: 70, steering: 70, reliability: 70, engineSupplier: engineSuppliers[0]?.name || 'Custom', primaryColor: '#cccccc', accentColor: '#999999', logoUrl: '', budget: 100, facilities: { aero: 1, chassis: 1, powertrain: 1, reliability: 1 } };
        setTeams(prev => [...prev, newTeam]);
    };

    const handleRemoveTeam = (team: Team) => {
        setModalState({
            isOpen: true,
            title: t('confirm_delete_team_title'),
            message: t('confirm_delete_team_message', { name: team.name }),
            onConfirm: () => {
                setTeams(prev => prev.filter(t => t.id !== team.id));
                setDrivers(prev => prev.filter(d => d.teamId !== team.id));
                setModalState(null);
            },
        });
    };

    const handleAddRace = () => {
        const newRace: Race = { name: t('newRace'), country: 'Brasil', countryCode: 'BR', laps: 50, baseLapTime: "1:30.000", weatherChances: { Dry: 0.8, LightRain: 0.15, HeavyRain: 0.05 } };
        setCalendar(prev => [...prev, newRace]);
    };

    const handleRemoveRace = (race: Race, index: number) => {
        setModalState({
            isOpen: true,
            title: t('confirm_delete_race_title'),
            message: t('confirm_delete_message', { name: race.name }),
            onConfirm: () => {
                setCalendar(prev => prev.filter((_, i) => i !== index));
                setModalState(null);
            },
        });
    };

    const handleEngineSupplierChange = (originalName: string, field: keyof EngineSupplier, value: string | number) => {
        if (field === 'name' && typeof value === 'string' && value !== originalName && engineSuppliers.some(es => es.name === value)) { return; }
        setEngineSuppliers(prev => prev.map(es => es.name === originalName ? { ...es, [field]: value } : es));
        if (field === 'name' && typeof value === 'string' && originalName !== value) {
            setTeams(prevTeams => prevTeams.map(team => team.engineSupplier === originalName ? { ...team, engineSupplier: value } : team));
        }
    };

    const handleAddEngineSupplier = () => {
        const newEngine: EngineSupplier = { name: `${t('newEngine')} ${engineSuppliers.length + 1}`, performance: 75, cost: 10 };
        if (engineSuppliers.some(es => es.name === newEngine.name)) return;
        setEngineSuppliers(prev => [...prev, newEngine]);
    };

    const handleRemoveEngineSupplier = (supplier: EngineSupplier) => {
        setModalState({
            isOpen: true,
            title: t('confirm_delete_engine_title'),
            message: t('confirm_delete_message', { name: supplier.name }),
            onConfirm: () => {
                setEngineSuppliers(prev => prev.filter(es => es.name !== supplier.name));
                setTeams(prevTeams => prevTeams.map(team => {
                    if (team.engineSupplier === supplier.name) {
                        return { ...team, engineSupplier: team.name };
                    }
                    return team;
                }));
                setModalState(null);
            },
        });
    };

    const handleCreateCustomCountry = () => {
        if (!newCountryName.trim()) return;
        const newCountry: Country = {
            name: newCountryName,
            code: `CUST_${Date.now()}`,
            isCustom: true,
            flagUrl: undefined
        };
        if (newCountryInputRef.current?.files?.[0]) {
            const file = newCountryInputRef.current.files[0];
            const reader = new FileReader();
            reader.onload = (e) => {
                newCountry.flagUrl = e.target?.result as string;
                setCustomCountries([...customCountries, newCountry]);
                setNewCountryName('');
                if (newCountryInputRef.current) newCountryInputRef.current.value = '';
            };
            reader.readAsDataURL(file);
        } else {
            setCustomCountries([...customCountries, newCountry]);
            setNewCountryName('');
        }
    };

    const handleDeleteCustomCountry = (code: string) => {
        setModalState({
            isOpen: true,
            title: t('delete_country'),
            message: t('confirm_delete_country'),
            onConfirm: () => {
                setCustomCountries(customCountries.filter(c => c.code !== code));
                setModalState(null);
            }
        });
    };

    const handleExportDatabase = () => {
        try {
            const database = { drivers, teams, calendar, engineSuppliers, customCountries };
            const jsonString = JSON.stringify(database, null, 2);
            const blob = new Blob([jsonString], { type: 'application/json' });
            const url = URL.createObjectURL(blob);
            const link = document.createElement('a');
            link.href = url;
            link.download = `formula_racing_database_${new Date().toISOString().slice(0, 10)}.json`;
            document.body.appendChild(link);
            link.click();
            document.body.removeChild(link);
            URL.revokeObjectURL(url);
        } catch (e) {
            alert(t('export_error'));
        }
    };

    const handleImportDatabase = (event: React.ChangeEvent<HTMLInputElement>) => {
        const inputElement = event.target;
        const file = inputElement.files?.[0];
        if (!file) return;
        const reader = new FileReader();
        reader.onload = (e) => {
            try {
            const text = e.target?.result as string;
            if (!text) return;
            const data = JSON.parse(text);
            if (data.drivers) setDrivers(data.drivers);
            if (data.teams) setTeams(data.teams);
            if (data.calendar) setCalendar(data.calendar);
            if (data.engineSuppliers) setEngineSuppliers(data.engineSuppliers);
            if (data.customCountries) setCustomCountries(data.customCountries);
            alert('Importação concluída com sucesso!');
            } catch (err) {
            alert(`Erro na importação: ${err}`);
            } finally {
            if (inputElement) inputElement.value = '';
            }
        };
        reader.readAsText(file);
    };

    const handleRandomizeAllClick = () => {
        setModalState({
            isOpen: true,
            title: t('confirm_randomize_potential_title'),
            message: t('confirm_randomize_potential_message'),
            onConfirm: () => {
                onRandomizeAllPotentials();
                setModalState(null);
            },
        });
    }

    const TabButton: React.FC<{ tab: EditTab, label: string, icon: React.ReactNode }> = ({ tab, label, icon }) => (
        <button
            onClick={() => setActiveTab(tab)}
            className={`flex items-center justify-center gap-2 px-4 py-3 text-sm font-bold uppercase rounded-t-lg transition-all duration-300 border-b-2 ${activeTab === tab ? 'text-[#00e051] border-[#00e051]' : 'text-slate-400 border-transparent hover:text-slate-200'}`}
        >
            {icon}
            <span>{label}</span>
        </button>
    );

    const ColorInput: React.FC<{ label: string; value: string; onChange: (e: React.ChangeEvent<HTMLInputElement>) => void; }> = ({ label, value, onChange }) => (
        <div>
            <label className="text-[10px] uppercase text-slate-500 mb-0.5 block font-bold">{label}</label>
            <div className="flex items-center gap-2 bg-[#101018] p-1.5 rounded text-xs border border-slate-800 focus-within:border-[#00e051]">
                <input type="color" value={value} onChange={onChange} className="w-5 h-5 p-0 border-none bg-transparent cursor-pointer" />
                <input type="text" value={value} onChange={onChange} className="w-full bg-transparent outline-none font-mono text-slate-200" />
            </div>
        </div>
    );

    const ImageUploader: React.FC<{ id: string | number, currentImage: string | undefined, onUpload: (e: React.ChangeEvent<HTMLInputElement>) => void, onRemove: () => void, type: 'driver' | 'team' }> = ({ id, currentImage, onUpload, onRemove, type }) => (
         <div className="w-full">
            <label className="text-[10px] uppercase text-slate-500 mb-0.5 block font-bold">{type === 'driver' ? t('edit_driverPhoto') : t('edit_teamLogo')}</label>
            <div className="flex items-center gap-2">
                <input id={`${type}-upload-${id}`} type="file" accept="image/png, image/jpeg, image/webp" className="hidden" onChange={onUpload} />
                <label htmlFor={`${type}-upload-${id}`} className="flex-grow cursor-pointer p-1.5 bg-slate-700 hover:bg-slate-600 rounded text-center text-[10px] uppercase font-bold flex items-center justify-center gap-2 transition-colors border border-slate-600 text-slate-200">
                    <CloudArrowUpIcon className="w-3.5 h-3.5" />
                    <span>{currentImage ? t('edit_changeImage') : t('edit_uploadImage')}</span>
                </label>
                {currentImage && (<button onClick={onRemove} className="p-1.5 bg-[#e00601]/20 text-[#e00601] hover:bg-[#e00601]/40 rounded border border-[#e00601]/50" title={t('edit_removeImage')}><TrashIcon className="w-3.5 h-3.5"/></button>)}
            </div>
        </div>
    );

    const renderContent = () => {
        switch (activeTab) {
            case 'drivers':
                return (
                    <div className="h-full flex flex-col">
                        <div className="p-3 bg-slate-900/40 rounded-lg flex flex-col sm:flex-row items-center justify-between gap-4 mb-4 flex-shrink-0 border border-slate-800">
                            <div className="flex items-center gap-3">
                                <label htmlFor="hide-potential-toggle" className="font-bold text-slate-300 text-xs uppercase tracking-wider">{t('edit_hide_potential_label')}</label>
                                <label className="relative inline-flex items-center cursor-pointer">
                                    <input type="checkbox" id="hide-potential-toggle" className="sr-only peer" checked={hidePotential} onChange={(e) => setHidePotential(e.target.checked)} />
                                    <div className="w-8 h-4.5 bg-slate-700 rounded-full peer peer-focus:ring-2 peer-focus:ring-green-800 peer-checked:after:translate-x-full peer-checked:after:border-white after:content-[''] after:absolute after:top-[2px] after:left-[2px] after:bg-white after:border-gray-300 after:border after:rounded-full after:h-3.5 after:w-3.5 after:transition-all peer-checked:bg-green-600"></div>
                                </label>
                            </div>
                            <div className="flex gap-2">
                                <button onClick={handleRandomizeAllClick} className="px-3 py-1.5 bg-slate-700 hover:bg-slate-600 rounded text-[10px] uppercase font-black flex items-center gap-2 transition-colors text-slate-200">
                                    <DiceIcon className="w-3.5 h-3.5" />
                                    <span>{t('edit_randomize_potentials_button')}</span>
                                </button>
                                <button onClick={handleAddDriver} disabled={!isAnyTeamAvailable} className="px-3 py-1.5 bg-[#00e051] text-black hover:bg-opacity-90 rounded text-[10px] uppercase font-black flex items-center gap-2 transition-colors disabled:bg-slate-700 disabled:text-slate-500 disabled:cursor-not-allowed">
                                    <PlusIcon className="w-3.5 h-3.5" /><span>{t('edit_addDriver')}</span>
                                </button>
                            </div>
                        </div>
                        <div className="flex-1 overflow-y-auto pr-2 grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-3 content-start">
                            {drivers.map(driver => {
                                const id = `driver-${driver.id}`;
                                const isExpanded = expandedId === id;
                                const team = teams.find(t => t.id === driver.teamId);
                                return (
                                    <div key={id} className={`bg-slate-800/40 border border-slate-700/50 rounded-lg overflow-hidden transition-all duration-300 h-fit ${isExpanded ? 'col-span-1 md:col-span-2 lg:col-span-3 row-span-2 z-10 shadow-2xl ring-1 ring-slate-600' : ''}`}>
                                        <div onClick={() => setExpandedId(isExpanded ? null : id)} className="w-full flex items-center p-2 text-left cursor-pointer hover:bg-white/5 transition-colors">
                                            <ImageWithFallback src={driver.photoUrl} alt={driver.name} primaryColor={team?.primaryColor || '#334155'} accentColor={team?.accentColor || '#FFFFFF'} initials={getInitials(driver.name)} type="driver" className="w-8 h-8 rounded-full object-cover flex-shrink-0" />
                                            <div className="ml-2.5 flex-grow min-w-0">
                                                <p className="font-bold text-slate-200 text-xs truncate uppercase tracking-tight">{driver.name}</p>
                                                <p className="text-[10px] text-slate-500 truncate uppercase font-semibold">{team?.name || t('unknownTeam')}</p>
                                            </div>
                                            {!isExpanded && (
                                                <div className="flex items-center gap-1.5">
                                                    <CountryFlag countryCode={driver.nationality} customCountries={customCountries} className="w-4 opacity-60" />
                                                    <button onClick={(e) => { e.stopPropagation(); handleRemoveDriver(driver); }} className="p-1 text-slate-600 hover:text-[#e00601] transition-colors rounded-full"><TrashIcon className="w-3.5 h-3.5"/></button>
                                                </div>
                                            )}
                                        </div>
                                        {isExpanded && (
                                            <div className="p-4 border-t border-slate-700/50 space-y-4 bg-[#15141f]">
                                                <div className="flex gap-4">
                                                    <div className="flex-1 space-y-3">
                                                        <div>
                                                            <label className="text-[10px] uppercase text-slate-500 mb-0.5 block font-bold">{t('driver')}</label>
                                                            <input type="text" value={driver.name} onChange={(e) => handleDriverChange(driver.id, 'name', e.target.value)} className="w-full bg-[#101018] p-2 rounded text-sm border border-slate-800 focus:outline-none focus:border-[#00e051] text-slate-200" placeholder={t('driver')} />
                                                        </div>
                                                        <div>
                                                            <label className="text-[10px] uppercase text-slate-500 mb-0.5 block font-bold">{t('team')}</label>
                                                            <select value={driver.teamId} onChange={(e) => handleDriverChange(driver.id, 'teamId', parseInt(e.target.value, 10))} className="w-full bg-[#101018] p-2 rounded text-sm border border-slate-800 focus:outline-none focus:border-[#00e051] text-slate-200">
                                                                {teams.map(team => {
                                                                    const isFull = (driverCountsByTeam[team.id] || 0) >= 2;
                                                                    return (<option key={team.id} value={team.id} disabled={isFull && team.id !== driver.teamId} className="bg-[#1e1e2b]">{team.name}{isFull && team.id !== driver.teamId ? ` (${t('edit_teamFull_short')})` : ''}</option>);
                                                                })}
                                                            </select>
                                                        </div>
                                                        <div className="flex gap-3">
                                                            <EditableStatInput className="w-16" label={t('age')} min={16} max={50} value={driver.age} onChange={(v) => handleDriverChange(driver.id, 'age', v)} />
                                                            <div className="flex-1">
                                                                <label className="text-[10px] uppercase text-slate-500 mb-0.5 block font-bold">{t('nationality')}</label>
                                                                <CountrySelector customCountries={customCountries} value={driver.nationality} onChange={(e) => handleDriverChange(driver.id, 'nationality', e.target.value)} className="w-full bg-[#101018] p-1.5 rounded text-xs border border-slate-800 h-[26px] text-slate-200" />
                                                            </div>
                                                        </div>
                                                    </div>
                                                    <div className="w-24 flex flex-col items-center gap-3">
