                                                        <ImageUploader id={driver.id} currentImage={driver.photoUrl} onUpload={(e) => handleImageUpload(driver.id, 'driver', e)} onRemove={() => handleDriverChange(driver.id, 'photoUrl', '')} type="driver" />
                                                    </div>
                                                </div>

                                                <div className="grid grid-cols-4 gap-2">
                                                    <EditableStatInput label="Spd" min={1} max={10} value={driver.speed} onChange={(v) => handleDriverChange(driver.id, 'speed', v)} />
                                                    <EditableStatInput label="Ovr" min={1} max={10} value={driver.overtaking} onChange={(v) => handleDriverChange(driver.id, 'overtaking', v)} />
                                                    <EditableStatInput label="Con" min={1} max={10} value={driver.concentration} onChange={(v) => handleDriverChange(driver.id, 'concentration', v)} />
                                                    <EditableStatInput label="Sta" min={1} max={10} value={driver.startSkill} onChange={(v) => handleDriverChange(driver.id, 'startSkill', v)} />
                                                    <EditableStatInput label="Rai" min={1} max={10} value={driver.rainSkill} onChange={(v) => handleDriverChange(driver.id, 'rainSkill', v)} />
                                                    <EditableStatInput label="Set" min={1} max={10} value={driver.setupSkill} onChange={(v) => handleDriverChange(driver.id, 'setupSkill', v)} />
                                                    <EditableStatInput label="Exp" min={1} max={10} value={driver.experience} onChange={(v) => handleDriverChange(driver.id, 'experience', v)} />
                                                    <EditableStatInput label="Phy" min={1} max={10} value={driver.physical} onChange={(v) => handleDriverChange(driver.id, 'physical', v)} />
                                                </div>

                                                <div className="flex justify-between items-center pt-3 border-t border-slate-800">
                                                    {!hidePotential && (
                                                        <div className="flex items-center gap-2">
                                                            <span className="text-[10px] text-yellow-500 font-black uppercase tracking-wider">{t('skill_potential')}:</span>
                                                            <input 
                                                                type="number" min="1" max="10" step="0.1" 
                                                                value={driver.potential} 
                                                                onChange={(e) => handleDriverChange(driver.id, 'potential', parseFloat(e.target.value))}
                                                                className="w-10 bg-[#101018] p-1 rounded text-xs border border-slate-800 text-center font-mono text-slate-200"
                                                            />
                                                        </div>
                                                    )}
                                                    <div className="flex gap-2">
                                                        <button onClick={() => handleRandomizeDriverStats(driver.id)} className="p-1.5 bg-slate-800 hover:bg-slate-700 rounded transition-colors text-slate-400 hover:text-white" title={t('edit_randomizeTooltip')}><DiceIcon className="w-4 h-4" /></button>
                                                        <button onClick={() => handleRemoveDriver(driver)} className="p-1.5 bg-red-900/20 hover:bg-red-900/40 rounded transition-colors text-red-500" title={t('delete')}><TrashIcon className="w-4 h-4" /></button>
                                                    </div>
                                                </div>
                                            </div>
                                        )}
                                    </div>
                                )
                            })}
                        </div>
                    </div>
                );
            case 'teams':
                 return (
                    <div className="h-full flex flex-col">
                        <div className="p-3 bg-slate-900/40 rounded-lg flex justify-end mb-4 flex-shrink-0 border border-slate-800">
                            <button onClick={handleAddTeam} className="px-3 py-1.5 bg-[#00e051] text-black hover:bg-opacity-90 rounded text-[10px] uppercase font-black flex items-center gap-2 transition-colors">
                                <PlusIcon className="w-3.5 h-3.5" /><span>{t('edit_addTeam')}</span>
                            </button>
                        </div>
                        <div className="flex-1 overflow-y-auto pr-2 grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 xl:grid-cols-4 gap-3 content-start">
                            {teams.map(team => {
                                const id = `team-${team.id}`;
                                const isExpanded = expandedId === id;
                                return (
                                    <div key={id} className={`bg-slate-800/40 border border-slate-700/50 rounded-lg overflow-hidden transition-all duration-300 h-fit ${isExpanded ? 'col-span-1 md:col-span-2 lg:col-span-3 row-span-2 z-10 shadow-2xl ring-1 ring-slate-600' : ''}`}>
                                        <div onClick={() => setExpandedId(isExpanded ? null : id)} className="w-full flex items-center p-2 text-left cursor-pointer hover:bg-white/5 transition-colors">
                                            <ImageWithFallback src={team.logoUrl} alt={team.name} primaryColor={team.primaryColor} accentColor={team.accentColor} initials={getInitials(team.name)} type="team" className="h-6 w-8 object-contain flex-shrink-0" />
                                            <p className="ml-2.5 flex-grow font-bold text-slate-200 text-xs truncate uppercase tracking-tight">{team.name}</p>
                                            {!isExpanded && (
                                                <div className="flex items-center gap-1.5">
                                                    <CountryFlag countryCode={team.nationality} customCountries={customCountries} className="w-4 opacity-60" />
                                                    <button onClick={(e) => { e.stopPropagation(); handleRemoveTeam(team); }} className="p-1 text-slate-600 hover:text-[#e00601] transition-colors rounded-full ml-1"><TrashIcon className="w-3.5 h-3.5"/></button>
                                                </div>
                                            )}
                                        </div>
                                        {isExpanded && (
                                            <div className="p-4 border-t border-slate-700/50 space-y-4 bg-[#15141f]">
                                                 <div className="grid grid-cols-1 sm:grid-cols-2 gap-4">
                                                    <div>
                                                        <label className="text-[10px] uppercase text-slate-500 mb-0.5 block font-bold">{t('team')}</label>
                                                        <input type="text" value={team.name} onChange={(e) => handleTeamChange(team.id, 'name', e.target.value)} className="w-full bg-[#101018] p-2 rounded text-sm border border-slate-800 focus:outline-none focus:border-[#00e051] text-slate-200" />
                                                    </div>
                                                    <div>
                                                        <label className="text-[10px] uppercase text-slate-500 mb-0.5 block font-bold">{t('nationality')}</label>
                                                        <CountrySelector customCountries={customCountries} value={team.nationality} onChange={(e) => handleTeamChange(team.id, 'nationality', e.target.value)} className="w-full bg-[#101018] p-2 rounded text-sm border border-slate-800 text-slate-200" />
                                                    </div>
                                                    <ImageUploader id={team.id} currentImage={team.logoUrl} onUpload={(e) => handleImageUpload(team.id, 'team', e)} onRemove={() => handleTeamChange(team.id, 'logoUrl', '')} type="team" />
                                                    <div>
                                                        <label className="text-[10px] uppercase text-slate-500 mb-0.5 block font-bold">{t('engine')}</label>
                                                        <select value={team.engineSupplier} onChange={(e) => handleTeamChange(team.id, 'engineSupplier', e.target.value)} className="w-full bg-[#101018] p-2 rounded text-sm border border-slate-800 focus:outline-none focus:border-[#00e051] text-slate-200">
                                                            {engineSuppliers.map(supplier => (<option key={supplier.name} value={supplier.name} className="bg-[#1e1e2b]">{supplier.name}</option>))}
                                                            <option value={team.name} className="bg-[#1e1e2b]">{t('edit_inHouse')}</option>
                                                        </select>
                                                    </div>
                                                 </div>
                                                <div className="grid grid-cols-3 sm:grid-cols-6 gap-2">
                                                    <EditableStatInput label="Aer" min={50} max={100} value={team.aerodynamics} onChange={(v) => handleTeamChange(team.id, 'aerodynamics', v)} />
                                                    <EditableStatInput label="Gea" min={50} max={100} value={team.gearbox} onChange={(v) => handleTeamChange(team.id, 'gearbox', v)} />
                                                    <EditableStatInput label="Brk" min={50} max={100} value={team.brakes} onChange={(v) => handleTeamChange(team.id, 'brakes', v)} />
                                                    <EditableStatInput label="Ele" min={50} max={100} value={team.electricalSystem} onChange={(v) => handleTeamChange(team.id, 'electricalSystem', v)} />
                                                    <EditableStatInput label="Str" min={50} max={100} value={team.steering} onChange={(v) => handleTeamChange(team.id, 'steering', v)} />
                                                    <EditableStatInput label="Rel" min={50} max={100} value={team.reliability} onChange={(v) => handleTeamChange(team.id, 'reliability', v)} />
                                                </div>
                                                <div className="grid grid-cols-2 gap-4 pt-2">
                                                    <ColorInput label={t('edit_primaryColor')} value={team.primaryColor} onChange={(e) => handleTeamChange(team.id, 'primaryColor', e.target.value)} />
                                                    <ColorInput label={t('edit_accentColor')} value={team.accentColor} onChange={(e) => handleTeamChange(team.id, 'accentColor', e.target.value)} />
                                                </div>
                                                <div className="flex justify-end pt-3 border-t border-slate-800">
                                                    <button onClick={() => handleRemoveTeam(team)} className="px-3 py-1.5 bg-red-900/20 hover:bg-red-900/40 rounded text-[10px] font-black uppercase flex items-center gap-2 text-red-500 transition-colors"><TrashIcon className="w-3.5 h-3.5" /> <span>{t('delete')}</span></button>
                                                </div>
                                            </div>
                                        )}
                                    </div>
                                )
                            })}
                        </div>
                    </div>
                );
            case 'calendar':
                return (
                     <div className="h-full flex flex-col">
                        <div className="p-3 bg-slate-900/40 rounded-lg flex justify-end mb-4 flex-shrink-0 border border-slate-800">
                            <button onClick={handleAddRace} className="px-3 py-1.5 bg-[#00e051] text-black hover:bg-opacity-90 rounded text-[10px] uppercase font-black flex items-center gap-2 transition-colors">
                                <PlusIcon className="w-3.5 h-3.5" /><span>{t('edit_addRace')}</span>
                            </button>
                        </div>
                        <div className="flex-1 overflow-y-auto pr-2 grid grid-cols-1 md:grid-cols-2 gap-3 content-start">
                            {calendar.map((race, index) => {
                                 const id = `race-${index}`;
                                 const isExpanded = expandedId === id;
                                const handleWeatherChanceChange = (type: 'Dry' | 'LightRain' | 'HeavyRain', value: string) => {
                                    const newChances = { ...race.weatherChances };
                                    const numValue = parseInt(value, 10);
                                    const validNum = isNaN(numValue) ? 0 : Math.max(0, Math.min(100, numValue));
                                    const otherSum = (type === 'Dry' ? 0 : newChances.Dry*100) + (type === 'LightRain' ? 0 : newChances.LightRain*100) + (type === 'HeavyRain' ? 0 : newChances.HeavyRain*100);
                                    if (validNum + otherSum > 100) return;
                                    newChances[type] = validNum / 100;
                                    handleRaceChange(index, 'weatherChances', newChances);
                                };
                                return (
                                    <div key={index} className="bg-slate-800/40 border border-slate-700/50 rounded-lg overflow-hidden transition-all duration-300 h-fit">
                                        <div onClick={() => setExpandedId(isExpanded ? null : id)} className="w-full flex items-center p-2.5 text-left cursor-pointer hover:bg-white/5 transition-colors">
                                            <span className="text-slate-600 font-mono text-[10px] w-5 font-bold">{index + 1}</span>
                                            <p className="flex-grow font-bold text-slate-200 text-xs truncate uppercase tracking-tight">{race.name}</p>
                                            <div className="flex items-center gap-2">
                                                <CountryFlag countryCode={race.countryCode} customCountries={customCountries} className="w-4 opacity-50" />
                                                {!isExpanded && (
                                                    <button onClick={(e) => { e.stopPropagation(); handleRemoveRace(race, index); }} className="p-1 text-slate-600 hover:text-[#e00601] transition-colors rounded-full"><TrashIcon className="w-3.5 h-3.5"/></button>
                                                )}
                                            </div>
                                        </div>
                                        {isExpanded && (
                                            <div className="p-4 border-t border-slate-700/50 space-y-4 bg-[#15141f]">
                                                <div>
                                                    <label className="text-[10px] uppercase text-slate-500 mb-0.5 block font-bold">{t('edit_gpName')}</label>
                                                    <input type="text" value={race.name} onChange={(e) => handleRaceChange(index, 'name', e.target.value)} className="w-full bg-[#101018] p-2 rounded text-sm border border-slate-800 focus:outline-none focus:border-[#00e051] text-slate-200" />
                                                </div>
                                                <div className="grid grid-cols-2 gap-4">
                                                    <div>
                                                        <label className="text-[10px] uppercase text-slate-500 mb-0.5 block font-bold">{t('country')}</label>
                                                        <CountrySelector customCountries={customCountries} value={race.countryCode} onChange={(e) => handleRaceCountryChange(index, e.target.value)} className="w-full bg-[#101018] p-2 rounded text-sm border border-slate-800 text-slate-200" />
                                                    </div>
                                                    <div>
                                                        <label className="text-[10px] uppercase text-slate-500 mb-0.5 block font-bold">{t('baseTime')}</label>
                                                        <input type="text" value={race.baseLapTime} onChange={(e) => handleRaceChange(index, 'baseLapTime', e.target.value)} className="w-full bg-[#101018] p-2 rounded text-sm border border-slate-800 focus:outline-none focus:border-[#00e051] text-slate-200 font-mono" placeholder="1:30.252" />
                                                    </div>
                                                </div>
                                                <div className="flex gap-4 items-end">
                                                    <EditableStatInput className="w-16" label={t('laps')} min={1} max={200} value={race.laps} onChange={(v) => handleRaceChange(index, 'laps', v)} />
                                                    <div className="flex-1 p-2 bg-[#101018] rounded border border-slate-800 grid grid-cols-3 gap-3">
                                                        {['Dry', 'LightRain', 'HeavyRain'].map(type => (
                                                            <div key={type} className="text-center">
                                                                <label className="text-[8px] uppercase text-slate-600 block font-black mb-0.5">{t(`weather_${type.toLowerCase()}` as any)}</label>
                                                                <input type="number" min="0" max="100" value={Math.round(race.weatherChances[type as keyof typeof race.weatherChances] * 100)} onChange={(e) => handleWeatherChanceChange(type as any, e.target.value)} className="w-full text-center bg-transparent text-xs font-mono text-slate-200 focus:outline-none" />
                                                            </div>
                                                        ))}
                                                    </div>
                                                </div>
                                                <div className="flex justify-end pt-3 border-t border-slate-800">
                                                    <button onClick={() => handleRemoveRace(race, index)} className="px-3 py-1.5 bg-red-900/20 hover:bg-red-900/40 rounded text-[10px] font-black uppercase flex items-center gap-2 text-red-500 transition-colors"><TrashIcon className="w-3.5 h-3.5" /> <span>{t('delete')}</span></button>
                                                </div>
                                            </div>
                                        )}
                                    </div>
                                )
                            })}
                        </div>
                    </div>
                );
            case 'engines':
                return (
                    <div className="h-full flex flex-col">
                         <div className="p-3 bg-slate-900/40 rounded-lg flex justify-end mb-4 flex-shrink-0 border border-slate-800">
                            <button onClick={handleAddEngineSupplier} className="px-3 py-1.5 bg-[#00e051] text-black hover:bg-opacity-90 rounded text-[10px] uppercase font-black flex items-center gap-2 transition-colors">
                                <PlusIcon className="w-3.5 h-3.5" /><span>{t('edit_addEngine')}</span>
                            </button>
                        </div>
                        <div className="flex-1 overflow-y-auto pr-2 grid grid-cols-1 md:grid-cols-2 gap-4 content-start">
                            {engineSuppliers.map(supplier => (
                                <div key={supplier.name} className="p-3 bg-slate-800/40 border border-slate-700/50 rounded-lg">
                                    <div className="flex justify-between items-start mb-3">
                                        <div className="flex-1 mr-4">
                                            <label className="text-[10px] uppercase text-slate-500 mb-0.5 block font-bold">{t('edit_supplierName')}</label>
                                            <input type="text" value={supplier.name} onChange={(e) => handleEngineSupplierChange(supplier.name, 'name', e.target.value)} className="w-full bg-[#101018] p-2 rounded text-sm border border-slate-800 focus:outline-none focus:border-[#00e051] text-slate-200" />
                                        </div>
                                        <button onClick={() => handleRemoveEngineSupplier(supplier)} className="p-1.5 text-slate-600 hover:text-[#e00601] transition-colors"><TrashIcon className="w-4 h-4"/></button>
                                    </div>
                                    <EditableStatInput label={t('performance')} min={50} max={100} value={supplier.performance} onChange={(v) => handleEngineSupplierChange(supplier.name, 'performance', v)} />
                                </div>
                            ))}
                        </div>
                    </div>
                );
            case 'countries':
                return (
                    <div className="h-full flex flex-col">
                        <div className="p-4 bg-slate-900/40 border border-slate-800 rounded-lg mb-4 flex-shrink-0">
                            <h3 className="font-bold text-slate-300 text-[10px] mb-3 uppercase tracking-widest">{t('create_country')}</h3>
                            <div className="flex flex-col sm:flex-row gap-4 items-end">
                                <div className="flex-1 w-full">
                                    <label className="text-[10px] uppercase text-slate-500 mb-0.5 block font-bold">{t('country_name')}</label>
                                    <input 
                                        type="text" 
                                        value={newCountryName} 
                                        onChange={(e) => setNewCountryName(e.target.value)} 
                                        placeholder={t('country_name')}
                                        className="w-full bg-[#101018] p-2 rounded text-sm border border-slate-800 focus:outline-none focus:border-[#00e051] text-slate-200" 
                                    />
                                </div>
                                <div className="w-full sm:w-auto">
                                    <label className="text-[10px] uppercase text-slate-500 mb-0.5 block font-bold">{t('country_flag')}</label>
                                    <div className="flex items-center gap-2">
                                        <input ref={newCountryInputRef} type="file" accept="image/*" className="hidden" id="new-country-flag" />
                                        <label htmlFor="new-country-flag" className="cursor-pointer px-3 py-1.5 bg-slate-700 hover:bg-slate-600 rounded text-[10px] uppercase font-black flex items-center justify-center gap-2 transition-colors border border-slate-600 text-slate-200">
                                            <CloudArrowUpIcon className="w-3.5 h-3.5" />
                                            <span>{t('edit_uploadImage')}</span>
                                        </label>
                                    </div>
                                </div>
                                <button 
                                    onClick={handleCreateCustomCountry}
                                    disabled={!newCountryName.trim()} 
                                    className="w-full sm:w-auto px-4 py-2 bg-[#00e051] text-black hover:bg-opacity-90 rounded text-[10px] uppercase font-black flex items-center justify-center gap-2 transition-colors disabled:bg-slate-700 disabled:text-slate-500 disabled:cursor-not-allowed"
                                >
                                    <PlusIcon className="w-3.5 h-3.5" /><span>{t('create_country_btn')}</span>
                                </button>
                            </div>
                        </div>

                        <div className="flex-1 overflow-y-auto pr-2">
                            {customCountries.length === 0 && <p className="text-slate-500 text-center py-12 italic text-xs uppercase tracking-widest">{t('no_custom_countries')}</p>}
                            <div className="grid grid-cols-1 sm:grid-cols-2 md:grid-cols-3 lg:grid-cols-4 gap-3 content-start">
                                {customCountries.map(country => (
                                    <div key={country.code} className="flex items-center justify-between p-2.5 bg-slate-800/40 border border-slate-700/50 rounded-lg shadow-sm">
                                        <div className="flex items-center gap-3">
                                            <CountryFlag countryCode={country.code} customCountries={customCountries} className="w-6 h-auto rounded-sm border border-slate-600 shadow-sm" />
                                            <span className="font-bold text-slate-300 text-xs uppercase tracking-tight">{country.name}</span>
                                        </div>
                                        <button onClick={() => handleDeleteCustomCountry(country.code)} className="p-1.5 text-slate-600 hover:text-[#e00601] transition-colors rounded-full">
                                            <TrashIcon className="w-3.5 h-3.5"/>
                                        </button>
                                    </div>
                                ))}
                            </div>
                        </div>
                    </div>
                );
        }
    };

    return (
        <div className="h-full flex flex-col p-0">
             <PromptModal
                isOpen={!!modalState?.isOpen}
                title={modalState?.title || ''}
                message={modalState?.message}
                defaultValue={null}
                onConfirm={() => modalState?.onConfirm()}
                onCancel={() => setModalState(null)}
            />
            <input type="file" ref={importInputRef} onChange={handleImportDatabase} accept=".json" style={{display: 'none'}} />

            <div className="bg-[#1e1e2b]/95 border border-slate-700 rounded-xl backdrop-blur-md shadow-2xl flex flex-col h-full overflow-hidden">
                <div className="flex-shrink-0 flex flex-wrap justify-between items-center p-4 border-b border-slate-800 gap-4 bg-[#15141f]">
                    <h2 className="text-2xl font-black uppercase text-slate-200 tracking-wider leading-none">{isOffSeason ? t('offSeasonEditor') : t('editor')}</h2>
                    <div className="flex items-center gap-2 flex-wrap">
                         <button onClick={() => importInputRef.current?.click()} className="px-3 py-1.5 text-[10px] bg-slate-700 text-slate-300 font-black uppercase rounded hover:bg-slate-600 flex items-center justify-center gap-2 transition-colors border border-slate-600">
                            <CloudArrowUpIcon className="w-3.5 h-3.5" />
                            <span>{t('edit_importDatabase')}</span>
                        </button>
                        <button onClick={handleExportDatabase} className="px-3 py-1.5 text-[10px] bg-slate-700 text-slate-300 font-black uppercase rounded hover:bg-slate-600 flex items-center justify-center gap-2 transition-colors border border-slate-600">
                            <CloudArrowUpIcon className="w-3.5 h-3.5 -scale-y-100" />
                            <span>{t('edit_exportDatabase')}</span>
                        </button>
                        {isOffSeason ? (
                            <button onClick={onBackToMenu} className="px-4 py-1.5 bg-[#e00601] text-white font-black text-[10px] uppercase rounded hover:bg-opacity-90 flex items-center justify-center gap-2 transition-colors shadow-lg shadow-red-900/20">
                                <CheckeredFlagIcon className="w-3.5 h-3.5" /><span>{t('startNextSeason')}</span>
                            </button>
                        ) : (
                             <button onClick={onBackToMenu} className="px-4 py-1.5 bg-slate-700 text-slate-200 font-black text-[10px] uppercase rounded hover:bg-slate-600 flex items-center justify-center gap-2 transition-colors border border-slate-600">
                                <HomeIcon className="w-3.5 h-3.5" /><span>{t('back')}</span>
                            </button>
                        )}
                    </div>
                </div>
                <div className="flex-shrink-0 flex overflow-x-auto border-b border-slate-700 bg-[#15141f] px-2 scrollbar-hide">
                    <TabButton tab="drivers" label={t('drivers')} icon={<UserIcon className="w-4 h-4"/>} />
                    <TabButton tab="teams" label={t('teams')} icon={<UserGroupIcon className="w-4 h-4"/>} />
                    <TabButton tab="calendar" label={t('calendar')} icon={<CalendarIcon className="w-4 h-4"/>} />
                    <TabButton tab="engines" label={t('engines')} icon={<CogIcon className="w-4 h-4"/>} />
                    <TabButton tab="countries" label={t('countries')} icon={<FlagIcon className="w-4 h-4"/>} />
                </div>
                <div className="flex-1 overflow-hidden p-4 sm:p-5 bg-gradient-to-br from-[#1e1e2b] to-[#15141f]">
                    {renderContent()}
                </div>
            </div>
        </div>
    );
};

export default EditMenu;

import React, { useState, useEffect } from 'react';
import { Race, Driver, Team, RaceState, SeasonSettings, Country } from '../types';
import { formatTime, getInitials } from '../utils';
import TyreCompoundIcon from './TyreCompoundIcon';
import LiveIcon from './icons/LiveIcon';
import MicrophoneIcon from './icons/MicrophoneIcon';
import RaceFlagOverlay from './RaceFlagOverlay';
import { useI18n } from '../i18n';
import ImageWithFallback from './ImageWithFallback';
import { SCORING_SYSTEMS } from '../constants';
import ExclamationTriangleIcon from './icons/ExclamationTriangleIcon';

interface LiveRaceViewProps {
    race: Race;
    raceState: RaceState;
    drivers: Driver[];
    teams: Team[];
    commentary: string;
    isPaused: boolean;
    settings: SeasonSettings;
    customCountries?: Country[];
}

const LiveRaceView: React.FC<LiveRaceViewProps> = ({ race, raceState, drivers, teams, commentary, isPaused, settings, customCountries = [] }) => {
    const { t } = useI18n();
    const [pulse, setPulse] = useState(false);
    const [trackedDriverId, setTrackedDriverId] = useState<number | null>(null);

    const scoringSystem = SCORING_SYSTEMS.find(s => s.id === settings.scoringSystemId);
    const pointsPositions = scoringSystem ? scoringSystem.points.length : 10;

    useEffect(() => {
        if (commentary) {
            setPulse(true);
            const timer = setTimeout(() => setPulse(false), 750);
            return () => clearTimeout(timer);
        }
    }, [commentary]);

    const colorizeCommentary = (comment: string): React.ReactNode => {
        if (!comment) {
            return <span className="text-slate-500 uppercase text-[10px] font-bold tracking-widest">{t('commentary_waiting')}</span>;
        }

        const lapInfoMatch = comment.match(/^(\[.*?\])/);
        const lapInfo = lapInfoMatch ? lapInfoMatch[1] : '';
        const commentText = comment.replace(lapInfo, '').trim();

        const entities = [
            ...drivers.map(d => {
                const team = teams.find(t => t.id === d.teamId);
                return { name: d.name, color: team?.primaryColor || '#FFFFFF', accent: team?.accentColor || '#FFFFFF' };
            }),
            ...teams.map(t => ({ name: t.name, color: t.primaryColor, accent: t.accentColor }))
        ];

        entities.sort((a, b) => b.name.length - a.name.length);
        const regex = new RegExp(`(${entities.map(e => e.name.replace(/[-\/\\^$*+?.()|[\]{}]/g, '\\$&')).join('|')})`, 'g');
        const parts = commentText.split(regex);

        const renderedText = parts.map((part, index) => {
            const entity = entities.find(e => e.name === part);
            if (entity) {
                return <span key={index} className="font-black" style={{ color: entity.color }}>{part}</span>;
            }
            return part;
        });

        return (
            <div className="flex flex-col gap-1">
                <span className="text-[10px] text-slate-500 font-mono-racing font-bold">{lapInfo}</span>
                <span className="text-sm font-medium leading-relaxed text-slate-200">{renderedText}</span>
            </div>
        );
    };

    const sortedDrivers = [...raceState.drivers].sort((a, b) => {
        if (a.status === 'DNF' && b.status !== 'DNF') return 1;
        if (a.status !== 'DNF' && b.status === 'DNF') return -1;
        if (a.status === 'DNF' && b.status === 'DNF') return 0;
        return a.position - b.position;
    });

    const remainingLaps = raceState.totalLaps - raceState.currentLap;
    const driverToTrackId = trackedDriverId ?? raceState.drivers.find(d => d.position === 1)?.driverId;
    const driverToTrackState = driverToTrackId ? raceState.drivers.find(d => d.driverId === driverToTrackId) : null;
    const driverToTrack = driverToTrackId ? drivers.find(d => d.id === driverToTrackId) : null;
    const teamOfTracked = driverToTrack ? teams.find(t => t.id === driverToTrack.teamId) : null;

    return (
        <div className="h-full flex flex-col lg:flex-row gap-4 animate-fade-in relative overflow-hidden font-racing">
            <RaceFlagOverlay flagStatus={raceState.flag} isSafetyCarDeployed={!!raceState.isSafetyCarDeployed} />

            {/* STANDINGS LIST */}
            <div className="flex-1 flex flex-col glass rounded-xl overflow-hidden shadow-2xl carbon-pattern">
                <div className="bg-black/60 p-3 text-[10px] font-black text-slate-500 uppercase grid grid-cols-12 gap-2 border-b border-white/5 tracking-wider">
                    <div className="col-span-1 text-center">POS</div>
                    <div className="col-span-5 sm:col-span-4">DRIVER</div>
                    <div className="col-span-1 text-center hidden sm:block">PIT</div>
                    <div className="col-span-2 text-right hidden sm:block">LAST</div>
                    <div className="col-span-2 text-right hidden sm:block">GAP</div>
                    <div className="col-span-3 sm:col-span-2 text-right">LDR</div>
                </div>
                <div className="flex-1 overflow-y-auto p-1.5 space-y-1">
                    {sortedDrivers.map(ds => {
                        const driver = drivers.find(d => d.id === ds.driverId)!;
                        const team = teams.find(t => t.id === driver.teamId)!;
                        const isDNF = ds.status === 'DNF';
                        const isTracked = ds.driverId === driverToTrackId;
                        const isInPoints = !isDNF && ds.position > 0 && ds.position <= pointsPositions;

                        return (
                            <div 
                                key={driver.id} 
                                onClick={() => setTrackedDriverId(ds.driverId)}
                                className={`grid grid-cols-12 gap-2 items-center p-2.5 rounded-lg text-xs cursor-pointer transition-all duration-300 border ${
                                    isDNF ? 'bg-red-950/20 border-red-900/30 opacity-40 grayscale' : 
                                    isTracked ? 'bg-white/10 border-white/20 shadow-lg scale-[1.01]' : 
                                    isInPoints ? 'bg-white/5 border-white/5 hover:bg-white/10' :
                                    'bg-black/20 border-transparent hover:bg-white/5'
                                }`}
                            >
                                <div className={`col-span-1 text-center font-black text-sm italic ${isDNF ? 'text-red-500' : isTracked ? 'text-white' : 'text-slate-400'}`}>
                                    {isDNF ? 'DNF' : ds.position}
                                </div>
                                <div className="col-span-5 sm:col-span-4 flex items-center gap-2 border-l-[3px] pl-3" style={{borderColor: team.primaryColor}}>
                                    <div className="flex flex-col min-w-0">
                                        <span className={`font-black uppercase truncate tracking-tight ${isTracked ? 'text-white' : 'text-slate-200'}`}>{driver.name}</span>
                                        <div className="flex items-center gap-2 mt-0.5">
                                            <TyreCompoundIcon compound={ds.currentTyres.compound} size={12} />
                                            {ds.activeIncident && <ExclamationTriangleIcon className="w-3 h-3 text-yellow-400 animate-pulse" />}
                                        </div>
                                    </div>
                                </div>
                                <div className="col-span-1 text-center font-mono-racing font-bold text-slate-500 hidden sm:block">{ds.pitStops}</div>
                                <div className="col-span-2 text-right font-mono-racing text-[10px] hidden sm:block">
                                    {isDNF ? '---' : ds.status === 'PITTING' ? <span className="text-[#00ff85] animate-pulse">BOX</span> : formatTime(ds.lastLapTime)}
                                </div>
                                <div className="col-span-2 text-right font-mono-racing text-[10px] text-slate-500 hidden sm:block">{isDNF ? '---' : ds.gapToAhead}</div>
                                <div className="col-span-3 sm:col-span-2 text-right font-mono-racing font-black text-slate-200">{isDNF ? '---' : ds.gapToLeader}</div>
                            </div>
                        );
                    })}
                </div>
            </div>

            {/* BROADCAST PANEL */}
            <div className="lg:w-[380px] flex flex-col gap-4 flex-shrink-0 h-full overflow-hidden">
                {/* RACE OVERVIEW */}
                <div className="glass p-6 rounded-xl relative overflow-hidden flex-shrink-0 group">
                    <div className="absolute top-0 right-0 p-4 opacity-10 group-hover:opacity-20 transition-opacity">
                        <LiveIcon className="h-12 w-auto" />
                    </div>
                    <div className="flex items-center justify-between mb-4">
                        <p className="text-[10px] font-black text-slate-500 uppercase tracking-[0.2em]">{race.name}</p>
                        {isPaused && <span className="text-[10px] bg-yellow-500 text-black px-2 py-0.5 rounded font-black uppercase">Paused</span>}
                    </div>
                    <div className="flex items-end gap-3 mb-4">
                        <span className="text-7xl font-black text-white tracking-tighter leading-none">{raceState.currentLap}</span>
                        <div className="flex flex-col">
                            <span className="text-xl font-bold text-slate-500 mb-1 leading-none">/ {raceState.totalLaps}</span>
                            <span className="text-[10px] font-black text-red-600 uppercase tracking-widest">Lap</span>
                        </div>
                    </div>
                    {remainingLaps > 0 && (
                        <div className="h-1.5 w-full bg-white/5 rounded-full overflow-hidden">
                            <div className="h-full bg-red-600 transition-all duration-1000 ease-linear" style={{ width: `${(raceState.currentLap / raceState.totalLaps) * 100}%` }}></div>
                        </div>
                    )}
                </div>

                {/* TRACKED DRIVER DATA */}
                {driverToTrack && driverToTrackState && teamOfTracked && (
                    <div className="glass rounded-xl overflow-hidden flex-shrink-0 shadow-2xl">
                        <div className="px-4 py-3 bg-white/5 border-b border-white/5 flex items-center justify-between">
                            <h4 className="font-black text-[10px] uppercase tracking-widest text-slate-400">Telemetry Feed</h4>
                            <div className="h-1.5 w-1.5 rounded-full bg-[#00ff85] shadow-[0_0_10px_#00ff85] animate-pulse"></div>
                        </div>
                        <div className="p-5">
                            <div className="flex items-center gap-5 mb-6">
                                <ImageWithFallback 
                                    src={driverToTrack.photoUrl} 
                                    alt={driverToTrack.name} 
                                    primaryColor={teamOfTracked.primaryColor} 
                                    accentColor={teamOfTracked.accentColor} 
                                    initials={getInitials(driverToTrack.name)} 
                                    type="driver" 
                                    className="w-16 h-16 rounded-lg object-cover bg-slate-800 border-b-4" 
                                    style={{borderBottomColor: teamOfTracked.primaryColor}}
                                />
                                <div className="flex flex-col min-w-0">
                                    <p className="font-black text-2xl text-white leading-tight uppercase italic">{driverToTrack.name}</p>
                                    <p className="text-[10px] font-bold text-slate-500 uppercase tracking-wider">{teamOfTracked.name}</p>
                                </div>
                            </div>

                            <div className="grid grid-cols-3 gap-3 mb-6">
                                <div className="bg-black/30 p-3 rounded-lg border border-white/5 text-center">
                                    <p className="text-[9px] font-black uppercase text-slate-500 mb-1 tracking-widest">Position</p>
                                    <p className="text-2xl font-black text-white italic">{driverToTrackState.status === 'DNF' ? 'RET' : `P${driverToTrackState.position}`}</p>
                                </div>
                                <div className="bg-black/30 p-3 rounded-lg border border-white/5 text-center">
                                    <p className="text-[9px] font-black uppercase text-slate-500 mb-1 tracking-widest">Tyre</p>
                                    <div className="flex justify-center"><TyreCompoundIcon compound={driverToTrackState.currentTyres.compound} size={24}/></div>
                                </div>
                                <div className="bg-black/30 p-3 rounded-lg border border-white/5 text-center">
                                    <p className="text-[9px] font-black uppercase text-slate-500 mb-1 tracking-widest">Wear</p>
                                    <p className={`text-2xl font-black italic ${driverToTrackState.currentTyres.wear > 75 ? 'text-red-500' : 'text-white'}`}>{driverToTrackState.currentTyres.wear.toFixed(0)}%</p>
                                </div>
                            </div>

                             <div className="space-y-2 p-4 bg-black/40 rounded-lg font-mono-racing text-[11px] border border-white/5">
                                <div className="flex justify-between">
                                    <span className="text-slate-500 font-bold uppercase tracking-tighter">Last Lap</span>
                                    <span className="text-white font-black">{formatTime(driverToTrackState.lastLapTime)}</span>
                                </div>
                                <div className="flex justify-between">
                                    <span className="text-slate-500 font-bold uppercase tracking-tighter">Best Lap</span>
                                    <span className="text-[#00ff85] font-black">{formatTime(driverToTrackState.bestLapTime)}</span>
                                </div>
                                <div className="flex justify-between pt-2 border-t border-white/5">
                                    <span className="text-slate-500 font-bold uppercase tracking-tighter">Interval</span>
                                    <span className="text-slate-200 font-black">{driverToTrackState.gapToLeader}</span>
                                </div>
                            </div>
                        </div>
                    </div>
                )}

                {/* COMMENTARY FEED */}
                <div className="flex-1 glass rounded-xl overflow-hidden flex flex-col min-h-0 shadow-2xl">
                    <div className="px-4 py-3 bg-black/60 border-b border-white/5 flex items-center gap-2">
                       <MicrophoneIcon className={`w-3.5 h-3.5 transition-all duration-300 ${pulse ? 'scale-125 text-red-500' : 'text-slate-500'}`} />
                        <h4 className="font-black text-[10px] uppercase tracking-[0.25em] text-slate-300">Live Commentary</h4>
                    </div>
                    <div className="flex-1 overflow-y-auto p-5 flex flex-col justify-end">
                        <div className="animate-fade-in border-l-2 border-red-600 pl-4 py-1">
                            {colorizeCommentary(commentary)}
                        </div>
                    </div>
                </div>
            </div>
        </div>
    );
};

export default LiveRaceView;

import React, { useState, useEffect, useMemo } from 'react';
import { SeasonSettings, Race, DriverStanding, ConstructorStanding, RaceResult, Driver, Team, QualifyingResult, RaceState, TyreCompound, WeatherCondition, NewsArticle, QualifyingData, SeasonHistory, EngineSupplier, Country } from '../types';
import StandingsTable from './StandingsTable';
import RaceResultModal from './RaceResultModal';
import LiveRaceView from './LiveRaceView';
import PreRaceStrategyScreen from './PreRaceStrategyScreen';
import StopwatchIcon from './icons/StopwatchIcon';
import HomeIcon from './icons/HomeIcon';
import SpeedControl from './SpeedControl';
import Podium from './Podium';
import FloppyDiskIcon from './icons/FloppyDiskIcon';
import ChartsView from './ChartsView';
import ChampionCelebration from './ChampionCelebration';
import { useI18n } from '../i18n';
import ProfileModal from './ProfileModal';
import QualifyingInProgressScreen from './QualifyingInProgressScreen';
import SpinnerIcon from './icons/SpinnerIcon';
import PlayIcon from './icons/PlayIcon';
import ForwardIcon from './icons/ForwardIcon';
import HistoryScreen from './HistoryScreen';
import TeamManagementPanel from './TeamManagementPanel';
import UserIcon from './icons/UserIcon';
import CountryFlag from './CountryFlag';


const NewsPanel: React.FC<{ news: NewsArticle[], drivers: Driver[], teams: Team[] }> = ({ news, drivers, teams }) => {
    const { t } = useI18n();
    const [expandedArticleId, setExpandedArticleId] = useState<string | null>(null);

    useEffect(() => {
        if (news.length > 0) {
            setExpandedArticleId(news[news.length - 1].id);
        }
    }, [news]);

    const toggleArticle = (id: string) => {
        setExpandedArticleId(prevId => (prevId === id ? null : id));
    };

    const sortedNews = [...news].reverse();

    const entities = useMemo(() => {
        const allEntities = [
            ...drivers.map(d => {
                const team = teams.find(t => t.id === d.teamId);
                return { name: d.name, color: team?.primaryColor || '#FFFFFF', accent: team?.accentColor || '#FFFFFF' };
            }),
            ...teams.map(t => ({ name: t.name, color: t.primaryColor, accent: t.accentColor }))
        ];
        allEntities.sort((a, b) => b.name.length - a.name.length);
        return allEntities;
    }, [drivers, teams]);

    const renderHighlightedBody = (text: string) => {
        if (!text) return '';
        const regex = new RegExp(`(${entities.map(e => e.name.replace(/[-\/\\^$*+?.()|[\]{}]/g, '\\$&')).join('|')})`, 'g');
        const parts = text.split(regex);

        return parts.map((part, index) => {
            const entity = entities.find(e => e.name === part);
            if (entity) {
                return <span key={index} className="font-bold" style={{ color: entity.color }}>{part}</span>;
            }
            return <React.Fragment key={index}>{part}</React.Fragment>;
        });
    };

    if (news.length === 0) {
        return (
            <div className="text-center py-20 flex flex-col items-center justify-center animate-fade-in">
                <div className="w-16 h-16 bg-slate-800 rounded-full flex items-center justify-center mb-4">
                    <SpinnerIcon className="w-8 h-8 text-slate-600" />
                </div>
                <p className="text-slate-500 font-bold uppercase tracking-widest text-xs">{t('news_noNews')}</p>
            </div>
        )
    }

    const TRUNCATE_LENGTH = 250;

    return (
        <div className="grid grid-cols-1 md:grid-cols-2 gap-4 overflow-y-auto h-full pr-2 content-start pb-10">
            {sortedNews.map(article => {
                const isExpanded = expandedArticleId === article.id;
                const isLong = article.body.length > TRUNCATE_LENGTH;
                const bodyContent = isLong && !isExpanded ? `${article.body.substring(0, TRUNCATE_LENGTH)}...` : article.body;

                return (
                    <div key={article.id} className="glass overflow-hidden p-6 animate-fade-in hover:bg-white/5 transition-all duration-300 rounded-xl group border-l-4 border-l-red-600">
                        <div className="flex justify-between items-start mb-4">
                            <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest bg-white/5 px-2 py-1 rounded">{article.date}</span>
                        </div>
                        <h4 className="font-black text-xl text-white mb-4 leading-tight font-racing group-hover:text-red-500 transition-colors">{article.headline}</h4>
                        <p className="text-slate-400 text-sm leading-relaxed font-medium">
                            {renderHighlightedBody(bodyContent)}
                        </p>
                        {isLong && (
                            <button
                                onClick={() => toggleArticle(article.id)}
                                className="text-[10px] font-black mt-6 text-red-600 hover:text-red-400 transition-colors uppercase tracking-widest"
                            >
                                {isExpanded ? 'Read Less -' : 'Read More +'}
                            </button>
                        )}
                    </div>
                );
            })}
        </div>
    );
};


interface SimulationScreenProps {
  settings: SeasonSettings;
  currentRaceIndex: number;
  calendar: Race[];
  drivers: Driver[];
  teams: Team[];
  engineSuppliers: EngineSupplier[];
  customCountries: Country[];
  setTeams: React.Dispatch<React.SetStateAction<Team[]>>;
  driverStandings: DriverStanding[];
  constructorStandings: ConstructorStanding[];
  lastRaceResults: RaceResult[] | null;
  allRaceResults: RaceResult[][];
  allQualifyingResults: QualifyingResult[][];
  qualifyingResults: QualifyingResult[] | null;
  qualifyingData: QualifyingData | null;
  news: NewsArticle[];
  history: SeasonHistory[];
  onSimulateQualifying: () => void;
  onSimulateWeekend: () => void;
  onSimulateSeason: () => void;
  onStopSeasonSim: () => void;
  isSeasonSimRunning: boolean;
  onStartRace: (strategies: { driverId: number; startingTyre: TyreCompound }[], startingWeather: WeatherCondition) => void;
  isLoading: boolean;
  error: string | null;
  onBackToMenu: () => void;
  onEndSeason: () => void;
  simulationStatus: 'idle' | 'qualifying' | 'pre-race' | 'race' | 'finished';
  raceState: RaceState | null;
  raceHistory: RaceState[];
  simulationSpeed: number;
  onSetSimulationSpeed: (speed: number) => void;
  isPaused: boolean;
  onPauseToggle: () => void;
  commentary: string;
  onSaveSimulation: () => void;
  determinedWeather: WeatherCondition | null;
}

const SimulationScreen: React.FC<SimulationScreenProps> = ({
  settings,
  currentRaceIndex,
  calendar,
  drivers,
  teams,
  engineSuppliers,
  customCountries,
  setTeams,
  driverStandings,
  constructorStandings,
  lastRaceResults,
  allRaceResults,
  allQualifyingResults,
  qualifyingResults,
  qualifyingData,
  news,
  history,
  onSimulateQualifying,
  onSimulateWeekend,
  onSimulateSeason,
  onStopSeasonSim,
  isSeasonSimRunning,
  onStartRace,
  isLoading,
  error,
  onBackToMenu,
  onEndSeason,
  simulationStatus,
  raceState,
  raceHistory,
  simulationSpeed,
  onSetSimulationSpeed,
  isPaused,
  onPauseToggle,
  commentary,
  onSaveSimulation,
  determinedWeather,
}) => {
  const { t } = useI18n();
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [activeContentKey, setActiveContentKey] = useState(simulationStatus);
  const [isFading, setIsFading] = useState(false);
  const [podiumData, setPodiumData] = useState<RaceResult[] | null>(null);
  const [activeView, setActiveView] = useState<'standings' | 'myTeam' | 'news' | 'charts' | 'history'>('standings');
  const [championData, setChampionData] = useState<{ driverChampion: { driver: Driver, team: Team }, constructorChampion: Team } | null>(null);
  const [selectedProfile, setSelectedProfile] = useState<{ id: number; type: 'driver' | 'constructor' } | null>(null);

  const seasonOver = currentRaceIndex >= calendar.length;
  const currentRace = calendar[currentRaceIndex];
  const isOwnerMode = settings.mode === 'owner';
  const playerTeam = teams.find(t => t.id === settings.playerTeamId);

    const handleOpenProfile = (id: number, type: 'driver' | 'constructor') => {
        setSelectedProfile({ id, type });
    };

    const handleCloseProfile = () => {
        setSelectedProfile(null);
    };

    const handleUpgradeFacility = (facility: keyof Team['facilities']) => {
        if (!playerTeam) return;

        const level = playerTeam.facilities[facility];
        const cost = (level + 1) * 2;

        if (playerTeam.budget >= cost) {
            if (window.confirm(t('confirm_upgrade_facility', { name: t(`facility_${facility}`), cost, level: level + 1 }))) {
                setTeams(prevTeams => prevTeams.map(t => {
                    if (t.id === playerTeam.id) {
                        return {
                            ...t,
                            budget: t.budget - cost,
                            facilities: {
                                ...t.facilities,
                                [facility]: t.facilities[facility] + 1
                            }
                        };
                    }
                    return t;
                }));
            }
        } else {
            alert(t('error_insufficient_funds'));
        }
    };


  useEffect(() => {
    if (lastRaceResults && simulationStatus === 'finished') {
      setIsModalOpen(true);
      const topThree = lastRaceResults
        .filter(r => r.position > 0 && r.position <= 3)
        .sort((a, b) => a.position - b.position);
      setPodiumData(topThree);
    }
  }, [lastRaceResults, simulationStatus]);

    useEffect(() => {
        if (seasonOver && simulationStatus === 'finished' && !isModalOpen && !podiumData && !championData && driverStandings.length > 0) {
            const driverChampId = driverStandings[0].driverId;
            const driver = drivers.find(d => d.id === driverChampId)!;
            const team = teams.find(t => t.id === driver.teamId)!;
            const constructorChamp = teams.find(t => t.id === constructorStandings[0].teamId)!;

            setChampionData({
                driverChampion: { driver, team },
                constructorChampion: constructorChamp,
            });
        }
    }, [seasonOver, simulationStatus, isModalOpen, podiumData, driverStandings, constructorStandings, drivers, teams, championData]);


  useEffect(() => {
    if (simulationStatus !== activeContentKey) {
        setIsFading(true);
        const timer = setTimeout(() => {
            setActiveContentKey(simulationStatus);
            setIsFading(false);
        }, 300);
        return () => clearTimeout(timer);
    }
  }, [simulationStatus, activeContentKey]);

  const handlePodiumContinue = () => {
    setPodiumData(null);
  };

  const handleBackFromStrategy = () => {
      onSetSimulationSpeed(1);
      setActiveContentKey(lastRaceResults ? 'finished' : 'idle');
  };

  const renderIdleContent = () => {
      if (podiumData || championData) return null; 
      return (
        <div className="flex flex-col h-full overflow-hidden animate-fade-in">
            {/* Nav Tabs */}
            <div className="flex gap-2 mb-6 border-b border-white/5 sticky top-0 z-10">
                <button onClick={() => setActiveView('standings')} className={`px-4 py-3 font-black uppercase text-[10px] tracking-widest border-b-2 transition-all ${activeView === 'standings' ? 'border-red-600 text-white bg-white/5' : 'border-transparent text-slate-500 hover:text-slate-300'}`}>{t('standings')}</button>
                {isOwnerMode && <button onClick={() => setActiveView('myTeam')} className={`px-4 py-3 font-black uppercase text-[10px] tracking-widest border-b-2 flex items-center gap-2 transition-all ${activeView === 'myTeam' ? 'border-red-600 text-white bg-white/5' : 'border-transparent text-slate-500 hover:text-slate-300'}`}><UserIcon className="w-3.5 h-3.5" />{t('myTeam')}</button>}
                <button onClick={() => setActiveView('news')} className={`px-4 py-3 font-black uppercase text-[10px] tracking-widest border-b-2 transition-all ${activeView === 'news' ? 'border-red-600 text-white bg-white/5' : 'border-transparent text-slate-500 hover:text-slate-300'}`}>{t('news')}</button>
                <button onClick={() => setActiveView('charts')} className={`px-4 py-3 font-black uppercase text-[10px] tracking-widest border-b-2 transition-all ${activeView === 'charts' ? 'border-red-600 text-white bg-white/5' : 'border-transparent text-slate-500 hover:text-slate-300'}`}>{t('charts')}</button>
                {history.length > 0 && <button onClick={() => setActiveView('history')} className={`px-4 py-3 font-black uppercase text-[10px] tracking-widest border-b-2 transition-all ${activeView === 'history' ? 'border-red-600 text-white bg-white/5' : 'border-transparent text-slate-500 hover:text-slate-300'}`}>{t('history_title')}</button>}
            </div>

            <div className="flex-1 overflow-auto min-h-0">
                {activeView === 'standings' ? (
                     <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 h-full">
                        <div className="glass rounded-xl overflow-hidden carbon-pattern h-full">
                            <StandingsTable title={t('driversChampionship')} standings={driverStandings} type="driver" seasonOver={seasonOver} drivers={drivers} teams={teams} customCountries={customCountries} onRowClick={handleOpenProfile} />
                        </div>
                        <div className="glass rounded-xl overflow-hidden carbon-pattern h-full">
                            <StandingsTable title={t('constructorsChampionship')} standings={constructorStandings} type="constructor" seasonOver={seasonOver} drivers={drivers} teams={teams} customCountries={customCountries} onRowClick={handleOpenProfile} />
                        </div>
                    </div>
                ) : activeView === 'myTeam' && isOwnerMode && playerTeam ? (
                    <div className="h-full overflow-y-auto pr-2">
                        <TeamManagementPanel 
                            team={playerTeam}
                            drivers={drivers.filter(d => d.teamId === playerTeam.id)}
                            engineSupplier={engineSuppliers.find(e => e.name === playerTeam.engineSupplier)!}
                            onUpgradeFacility={handleUpgradeFacility}
                        />
                    </div>
                ) : activeView === 'news' ? (
                    <NewsPanel news={news} drivers={drivers} teams={teams} />
                ) : activeView === 'charts' ? (
                    <div className="h-full overflow-y-auto pr-2">
                        <ChartsView
                            raceHistory={raceHistory}
                            drivers={drivers}
                            teams={teams}
                            allRaceResults={allRaceResults}
                            allQualifyingResults={allQualifyingResults}
                            settings={settings}
                            calendar={calendar}
                            driverStandings={driverStandings}
                            customCountries={customCountries}
                        />
                    </div>
                ) : activeView === 'history' ? (
                    <div className="h-full overflow-y-auto pr-2">
                        <HistoryScreen history={history} customCountries={customCountries} />
                    </div>
                ) : null}
            </div>
        </div>
      )
  };

  const renderContent = () => {
    if (simulationStatus === 'finished' && !isModalOpen && podiumData && podiumData.length > 0) {
      return (
        <Podium 
          results={podiumData}
          drivers={drivers}
          teams={teams}
          raceName={calendar[currentRaceIndex - 1]?.name || t('grandPrix')}
          onContinue={handlePodiumContinue}
        />
      );
    }

    if (seasonOver && championData) {
        return (
            <ChampionCelebration
                driverChampion={championData.driverChampion}
                constructorChampion={championData.constructorChampion}
                year={settings.startYear}
                onContinue={onEndSeason}
            />
        );
    }

    switch(activeContentKey) {
        case 'race':
            if (raceState) return <LiveRaceView race={currentRace} raceState={raceState} drivers={drivers} teams={teams} commentary={commentary} isPaused={isPaused} settings={settings} customCountries={customCountries} />;
            return null;
        case 'pre-race':
            return <PreRaceStrategyScreen
                qualifyingResults={qualifyingResults!}
                drivers={drivers}
                teams={teams}
                race={currentRace}
                onStartRace={onStartRace}
                weather={determinedWeather!}
                onBack={handleBackFromStrategy}
            />;
        case 'qualifying':
            return <QualifyingInProgressScreen
                qualifyingData={qualifyingData}
                drivers={drivers}
                teams={teams}
            />;
        case 'idle':
        case 'finished':
        default:
             return renderIdleContent();
    }
  }

  return (
    <div className="flex flex-col h-full gap-6">
      {lastRaceResults && qualifyingResults && simulationStatus === 'finished' && (
        <RaceResultModal
          isOpen={isModalOpen}
          onClose={() => setIsModalOpen(false)}
          raceResults={lastRaceResults}
          qualifyingResults={qualifyingResults}
          race={calendar[currentRaceIndex - 1]}
          drivers={drivers}
          teams={teams}
          settings={settings}
          customCountries={customCountries}
        />
      )}

      <ProfileModal
          isOpen={!!selectedProfile}
          onClose={handleCloseProfile}
          profileId={selectedProfile?.id}
          profileType={selectedProfile?.type}
          drivers={drivers}
          teams={teams}
          onSelectProfile={handleOpenProfile}
          allRaceResults={allRaceResults}
          allQualifyingResults={allQualifyingResults}
          customCountries={customCountries}
      />

      <div className="flex-shrink-0 glass p-6 rounded-2xl flex flex-col md:flex-row justify-between items-center gap-6 shadow-2xl carbon-pattern border-l-4 border-l-red-600">
        <div className="flex items-center gap-6">
            {!seasonOver && currentRace && (
                <div className="relative">
                    <CountryFlag countryCode={currentRace.countryCode} customCountries={customCountries} className="w-16 h-12 rounded-lg object-cover shadow-xl grayscale-[0.5]" />
                    <div className="absolute -bottom-2 -right-2 bg-red-600 text-white font-black text-[10px] px-2 py-0.5 rounded italic">R{currentRaceIndex + 1}</div>
                </div>
            )}
            <div>
                <h2 className="text-[10px] font-black text-slate-500 uppercase tracking-[0.3em] mb-1 leading-none">
                   {seasonOver ? 'Championship Review' : 'Up Next'}
                </h2>
                <p className="text-2xl font-black text-white italic uppercase font-racing tracking-tight">
                    {seasonOver ? t('congratsChampions', { year: settings.startYear }) : currentRace?.name}
                </p>
                {!seasonOver && currentRace && (
                     <p className="text-[10px] font-black text-slate-400 mt-1 uppercase tracking-widest bg-white/5 inline-block px-2 py-0.5 rounded">
                        {currentRace.country} • {currentRace.laps} Laps • {currentRace.baseLapTime} Base
                     </p>
                )}
            </div>
        </div>
        <div className="flex items-center gap-4">
            {['qualifying', 'race'].includes(simulationStatus) && !isSeasonSimRunning && (
              <SpeedControl currentSpeed={simulationSpeed} onSpeedChange={onSetSimulationSpeed} isPaused={isPaused} onPauseToggle={onPauseToggle} />
            )}
            {['idle', 'finished'].includes(simulationStatus) && !podiumData && !championData && (
                <div className="flex items-center gap-3">
                    {!seasonOver && (
                      <>
                        <button onClick={onSaveSimulation} className="p-3 glass hover:bg-blue-600/20 text-blue-400 rounded-xl transition-all" title={t('save')}>
                            <FloppyDiskIcon className="w-5 h-5" />
                        </button>

                        <div className="h-10 w-px bg-white/10 mx-2"></div>

                        <div className="flex bg-black/40 p-1.5 rounded-xl border border-white/5">
                            <button 
                                onClick={onSimulateQualifying} 
                                disabled={isLoading} 
                                className="flex items-center gap-2 px-6 py-2 bg-red-600 text-white font-black text-xs uppercase rounded-lg hover:bg-red-500 disabled:bg-slate-800 disabled:text-slate-600 transition-all font-racing"
                            >
                                <StopwatchIcon className="w-4 h-4" /><span>{t('simulateQualifying')}</span>
                            </button>
                            <div className="w-px h-6 bg-white/10 mx-1.5 self-center"></div>
                            <button onClick={onSimulateWeekend} disabled={isLoading} className="p-2 text-slate-400 hover:text-white transition-all" title={t('simulateRaceWeek')}>
                                <PlayIcon className="w-5 h-5" />
                            </button>
                            <button onClick={onSimulateSeason} disabled={isLoading} className="p-2 text-slate-400 hover:text-white transition-all" title={t('simulateSeason')}>
                                <ForwardIcon className="w-5 h-5" />
                            </button>
                        </div>
                      </>
                    )}
                    <button onClick={onBackToMenu} className="p-3 glass hover:bg-white/10 text-slate-400 hover:text-white rounded-xl transition-all" title={t('backToMenu')}>
                        <HomeIcon className="w-5 h-5" />
                    </button>
                </div>
            )}
        </div>
      </div>

       {isSeasonSimRunning && (
        <div className="p-4 glass border-l-4 border-l-[#00ff85] flex items-center justify-between animate-fade-in rounded-xl flex-shrink-0">
          <div className="flex items-center gap-4">
            <SpinnerIcon className="w-5 h-5 text-[#00ff85]" />
            <div>
                <p className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Season Simulation Active</p>
                <p className="text-sm font-black text-white italic uppercase font-racing">{currentRace?.name}</p>
            </div>
          </div>
          <button onClick={onStopSeasonSim} className="px-4 py-2 bg-red-600/10 text-red-500 font-black text-[10px] uppercase rounded-lg hover:bg-red-600 hover:text-white transition-all tracking-widest">{t('stop')}</button>
        </div>
       )}

       {error && (
        <div className="p-4 bg-red-950/40 border border-red-900 text-red-400 rounded-xl flex-shrink-0 animate-fade-in flex items-center gap-3">
          <ExclamationTriangleIcon className="w-5 h-5" />
          <p className="text-sm font-bold uppercase tracking-tight">{error}</p>
        </div>
      )}

      <div className={`flex-1 min-h-0 transition-all duration-300 ease-in-out ${isFading ? 'opacity-0 transform -translate-y-4' : 'opacity-100'}`}>
        {renderContent()}
      </div>

    </div>
  );
};

export default SimulationScreen;

import React, { useState, useEffect, useMemo } from 'react';
import { SeasonSettings, Race, DriverStanding, ConstructorStanding, RaceResult, Driver, Team, QualifyingResult, RaceState, TyreCompound, WeatherCondition, NewsArticle, QualifyingData, SeasonHistory, EngineSupplier, Country } from '../types';
import StandingsTable from './StandingsTable';
import RaceResultModal from './RaceResultModal';
import LiveRaceView from './LiveRaceView';
import PreRaceStrategyScreen from './PreRaceStrategyScreen';
import StopwatchIcon from './icons/StopwatchIcon';
import HomeIcon from './icons/HomeIcon';
import SpeedControl from './SpeedControl';
import Podium from './Podium';
import FloppyDiskIcon from './icons/FloppyDiskIcon';
import ChartsView from './ChartsView';
import ChampionCelebration from './ChampionCelebration';
import { useI18n } from '../i18n';
import ProfileModal from './ProfileModal';
import QualifyingInProgressScreen from './QualifyingInProgressScreen';
import SpinnerIcon from './icons/SpinnerIcon';
import PlayIcon from './icons/PlayIcon';
import ForwardIcon from './icons/ForwardIcon';
import HistoryScreen from './HistoryScreen';
import TeamManagementPanel from './TeamManagementPanel';
import UserIcon from './icons/UserIcon';
import CountryFlag from './CountryFlag';
// FIX: Import missing ExclamationTriangleIcon.
import ExclamationTriangleIcon from './icons/ExclamationTriangleIcon';


const NewsPanel: React.FC<{ news: NewsArticle[], drivers: Driver[], teams: Team[] }> = ({ news, drivers, teams }) => {
    const { t } = useI18n();
    const [expandedArticleId, setExpandedArticleId] = useState<string | null>(null);

    useEffect(() => {
        if (news.length > 0) {
            setExpandedArticleId(news[news.length - 1].id);
        }
    }, [news]);

    const toggleArticle = (id: string) => {
        setExpandedArticleId(prevId => (prevId === id ? null : id));
    };

    const sortedNews = [...news].reverse();

    const entities = useMemo(() => {
        const allEntities = [
            ...drivers.map(d => {
                const team = teams.find(t => t.id === d.teamId);
                return { name: d.name, color: team?.primaryColor || '#FFFFFF', accent: team?.accentColor || '#FFFFFF' };
            }),
            ...teams.map(t => ({ name: t.name, color: t.primaryColor, accent: t.accentColor }))
        ];
        allEntities.sort((a, b) => b.name.length - a.name.length);
        return allEntities;
    }, [drivers, teams]);

    const renderHighlightedBody = (text: string) => {
        if (!text) return '';
        const regex = new RegExp(`(${entities.map(e => e.name.replace(/[-\/\\^$*+?.()|[\]{}]/g, '\\$&')).join('|')})`, 'g');
        const parts = text.split(regex);

        return parts.map((part, index) => {
            const entity = entities.find(e => e.name === part);
            if (entity) {
                return <span key={index} className="font-bold" style={{ color: entity.color }}>{part}</span>;
            }
            return <React.Fragment key={index}>{part}</React.Fragment>;
        });
    };

    if (news.length === 0) {
        return (
            <div className="text-center py-20 flex flex-col items-center justify-center animate-fade-in">
                <div className="w-16 h-16 bg-slate-800 rounded-full flex items-center justify-center mb-4">
                    <SpinnerIcon className="w-8 h-8 text-slate-600" />
                </div>
                <p className="text-slate-500 font-bold uppercase tracking-widest text-xs">{t('news_noNews')}</p>
            </div>
        )
    }

    const TRUNCATE_LENGTH = 250;

    return (
        <div className="grid grid-cols-1 md:grid-cols-2 gap-4 overflow-y-auto h-full pr-2 content-start pb-10">
            {sortedNews.map(article => {
                const isExpanded = expandedArticleId === article.id;
                const isLong = article.body.length > TRUNCATE_LENGTH;
                const bodyContent = isLong && !isExpanded ? `${article.body.substring(0, TRUNCATE_LENGTH)}...` : article.body;

                return (
                    <div key={article.id} className="glass overflow-hidden p-6 animate-fade-in hover:bg-white/5 transition-all duration-300 rounded-xl group border-l-4 border-l-red-600">
                        <div className="flex justify-between items-start mb-4">
                            <span className="text-[10px] font-black text-slate-500 uppercase tracking-widest bg-white/5 px-2 py-1 rounded">{article.date}</span>
                        </div>
                        <h4 className="font-black text-xl text-white mb-4 leading-tight font-racing group-hover:text-red-500 transition-colors">{article.headline}</h4>
                        <p className="text-slate-400 text-sm leading-relaxed font-medium">
                            {renderHighlightedBody(bodyContent)}
                        </p>
                        {isLong && (
                            <button
                                onClick={() => toggleArticle(article.id)}
                                className="text-[10px] font-black mt-6 text-red-600 hover:text-red-400 transition-colors uppercase tracking-widest"
                            >
                                {isExpanded ? 'Read Less -' : 'Read More +'}
                            </button>
                        )}
                    </div>
                );
            })}
        </div>
    );
};


interface SimulationScreenProps {
  settings: SeasonSettings;
  currentRaceIndex: number;
  calendar: Race[];
  drivers: Driver[];
  teams: Team[];
  engineSuppliers: EngineSupplier[];
  customCountries: Country[];
  setTeams: React.Dispatch<React.SetStateAction<Team[]>>;
  driverStandings: DriverStanding[];
  constructorStandings: ConstructorStanding[];
  lastRaceResults: RaceResult[] | null;
  allRaceResults: RaceResult[][];
  allQualifyingResults: QualifyingResult[][];
  qualifyingResults: QualifyingResult[] | null;
  qualifyingData: QualifyingData | null;
  news: NewsArticle[];
  history: SeasonHistory[];
  onSimulateQualifying: () => void;
  onSimulateWeekend: () => void;
  onSimulateSeason: () => void;
  onStopSeasonSim: () => void;
  isSeasonSimRunning: boolean;
  onStartRace: (strategies: { driverId: number; startingTyre: TyreCompound }[], startingWeather: WeatherCondition) => void;
  isLoading: boolean;
  error: string | null;
  onBackToMenu: () => void;
  onEndSeason: () => void;
  simulationStatus: 'idle' | 'qualifying' | 'pre-race' | 'race' | 'finished';
  raceState: RaceState | null;
  raceHistory: RaceState[];
  simulationSpeed: number;
  onSetSimulationSpeed: (speed: number) => void;
  isPaused: boolean;
  onPauseToggle: () => void;
  commentary: string;
  onSaveSimulation: () => void;
  determinedWeather: WeatherCondition | null;
}

const SimulationScreen: React.FC<SimulationScreenProps> = ({
  settings,
  currentRaceIndex,
  calendar,
  drivers,
  teams,
  engineSuppliers,
  customCountries,
  setTeams,
  driverStandings,
  constructorStandings,
  lastRaceResults,
  allRaceResults,
  allQualifyingResults,
  qualifyingResults,
  qualifyingData,
  news,
  history,
  onSimulateQualifying,
  onSimulateWeekend,
  onSimulateSeason,
  onStopSeasonSim,
  isSeasonSimRunning,
  onStartRace,
  isLoading,
  error,
  onBackToMenu,
  onEndSeason,
  simulationStatus,
  raceState,
  raceHistory,
  simulationSpeed,
  onSetSimulationSpeed,
  isPaused,
  onPauseToggle,
  commentary,
  onSaveSimulation,
  determinedWeather,
}) => {
  const { t } = useI18n();
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [activeContentKey, setActiveContentKey] = useState(simulationStatus);
  const [isFading, setIsFading] = useState(false);
  const [podiumData, setPodiumData] = useState<RaceResult[] | null>(null);
  const [activeView, setActiveView] = useState<'standings' | 'myTeam' | 'news' | 'charts' | 'history'>('standings');
  const [championData, setChampionData] = useState<{ driverChampion: { driver: Driver, team: Team }, constructorChampion: Team } | null>(null);
  const [selectedProfile, setSelectedProfile] = useState<{ id: number; type: 'driver' | 'constructor' } | null>(null);

  const seasonOver = currentRaceIndex >= calendar.length;
  const currentRace = calendar[currentRaceIndex];
  const isOwnerMode = settings.mode === 'owner';
  const playerTeam = teams.find(t => t.id === settings.playerTeamId);

    const handleOpenProfile = (id: number, type: 'driver' | 'constructor') => {
        setSelectedProfile({ id, type });
    };

    const handleCloseProfile = () => {
        setSelectedProfile(null);
    };

    const handleUpgradeFacility = (facility: keyof Team['facilities']) => {
        if (!playerTeam) return;

        const level = playerTeam.facilities[facility];
        const cost = (level + 1) * 2;

        if (playerTeam.budget >= cost) {
            if (window.confirm(t('confirm_upgrade_facility', { name: t(`facility_${facility}`), cost, level: level + 1 }))) {
                setTeams(prevTeams => prevTeams.map(t => {
                    if (t.id === playerTeam.id) {
                        return {
                            ...t,
                            budget: t.budget - cost,
                            facilities: {
                                ...t.facilities,
                                [facility]: t.facilities[facility] + 1
                            }
                        };
                    }
                    return t;
                }));
            }
        } else {
            alert(t('error_insufficient_funds'));
        }
    };


  useEffect(() => {
    if (lastRaceResults && simulationStatus === 'finished') {
      setIsModalOpen(true);
      const topThree = lastRaceResults
        .filter(r => r.position > 0 && r.position <= 3)
        .sort((a, b) => a.position - b.position);
      setPodiumData(topThree);
    }
  }, [lastRaceResults, simulationStatus]);

    useEffect(() => {
        if (seasonOver && simulationStatus === 'finished' && !isModalOpen && !podiumData && !championData && driverStandings.length > 0) {
            const driverChampId = driverStandings[0].driverId;
            const driver = drivers.find(d => d.id === driverChampId)!;
            const team = teams.find(t => t.id === driver.teamId)!;
            const constructorChamp = teams.find(t => t.id === constructorStandings[0].teamId)!;

            setChampionData({
                driverChampion: { driver, team },
                constructorChampion: constructorChamp,
            });
        }
    }, [seasonOver, simulationStatus, isModalOpen, podiumData, driverStandings, constructorStandings, drivers, teams, championData]);


  useEffect(() => {
    if (simulationStatus !== activeContentKey) {
        setIsFading(true);
        const timer = setTimeout(() => {
            setActiveContentKey(simulationStatus);
            setIsFading(false);
        }, 300);
        return () => clearTimeout(timer);
    }
  }, [simulationStatus, activeContentKey]);

  const handlePodiumContinue = () => {
    setPodiumData(null);
  };

  const handleBackFromStrategy = () => {
      onSetSimulationSpeed(1);
      setActiveContentKey(lastRaceResults ? 'finished' : 'idle');
  };

  const renderIdleContent = () => {
      if (podiumData || championData) return null; 
      return (
        <div className="flex flex-col h-full overflow-hidden animate-fade-in">
            {/* Nav Tabs */}
            <div className="flex gap-2 mb-6 border-b border-white/5 sticky top-0 z-10">
                <button onClick={() => setActiveView('standings')} className={`px-4 py-3 font-black uppercase text-[10px] tracking-widest border-b-2 transition-all ${activeView === 'standings' ? 'border-red-600 text-white bg-white/5' : 'border-transparent text-slate-500 hover:text-slate-300'}`}>{t('standings')}</button>
                {isOwnerMode && <button onClick={() => setActiveView('myTeam')} className={`px-4 py-3 font-black uppercase text-[10px] tracking-widest border-b-2 flex items-center gap-2 transition-all ${activeView === 'myTeam' ? 'border-red-600 text-white bg-white/5' : 'border-transparent text-slate-500 hover:text-slate-300'}`}><UserIcon className="w-3.5 h-3.5" />{t('myTeam')}</button>}
                <button onClick={() => setActiveView('news')} className={`px-4 py-3 font-black uppercase text-[10px] tracking-widest border-b-2 transition-all ${activeView === 'news' ? 'border-red-600 text-white bg-white/5' : 'border-transparent text-slate-500 hover:text-slate-300'}`}>{t('news')}</button>
                <button onClick={() => setActiveView('charts')} className={`px-4 py-3 font-black uppercase text-[10px] tracking-widest border-b-2 transition-all ${activeView === 'charts' ? 'border-red-600 text-white bg-white/5' : 'border-transparent text-slate-500 hover:text-slate-300'}`}>{t('charts')}</button>
                {history.length > 0 && <button onClick={() => setActiveView('history')} className={`px-4 py-3 font-black uppercase text-[10px] tracking-widest border-b-2 transition-all ${activeView === 'history' ? 'border-red-600 text-white bg-white/5' : 'border-transparent text-slate-500 hover:text-slate-300'}`}>{t('history_title')}</button>}
            </div>

            <div className="flex-1 overflow-auto min-h-0">
                {activeView === 'standings' ? (
                     <div className="grid grid-cols-1 lg:grid-cols-2 gap-6 h-full">
                        <div className="glass rounded-xl overflow-hidden carbon-pattern h-full">
                            <StandingsTable title={t('driversChampionship')} standings={driverStandings} type="driver" seasonOver={seasonOver} drivers={drivers} teams={teams} customCountries={customCountries} onRowClick={handleOpenProfile} />
                        </div>
                        <div className="glass rounded-xl overflow-hidden carbon-pattern h-full">
                            <StandingsTable title={t('constructorsChampionship')} standings={constructorStandings} type="constructor" seasonOver={seasonOver} drivers={drivers} teams={teams} customCountries={customCountries} onRowClick={handleOpenProfile} />
                        </div>
                    </div>
                ) : activeView === 'myTeam' && isOwnerMode && playerTeam ? (
                    <div className="h-full overflow-y-auto pr-2">
                        <TeamManagementPanel 
                            team={playerTeam}
                            drivers={drivers.filter(d => d.teamId === playerTeam.id)}
                            engineSupplier={engineSuppliers.find(e => e.name === playerTeam.engineSupplier)!}
                            onUpgradeFacility={handleUpgradeFacility}
                        />
                    </div>
                ) : activeView === 'news' ? (
                    <NewsPanel news={news} drivers={drivers} teams={teams} />
                ) : activeView === 'charts' ? (
                    <div className="h-full overflow-y-auto pr-2">
                        <ChartsView
                            raceHistory={raceHistory}
                            drivers={drivers}
                            teams={teams}
                            allRaceResults={allRaceResults}
                            allQualifyingResults={allQualifyingResults}
                            settings={settings}
                            calendar={calendar}
                            driverStandings={driverStandings}
                            customCountries={customCountries}
                        />
                    </div>
                ) : activeView === 'history' ? (
                    <div className="h-full overflow-y-auto pr-2">
                        <HistoryScreen history={history} customCountries={customCountries} />
                    </div>
                ) : null}
            </div>
        </div>
      )
  };

  const renderContent = () => {
    if (simulationStatus === 'finished' && !isModalOpen && podiumData && podiumData.length > 0) {
      return (
        <Podium 
          results={podiumData}
          drivers={drivers}
          teams={teams}
          raceName={calendar[currentRaceIndex - 1]?.name || t('grandPrix')}
          onContinue={handlePodiumContinue}
        />
      );
    }

    if (seasonOver && championData) {
        return (
            <ChampionCelebration
                driverChampion={championData.driverChampion}
                constructorChampion={championData.constructorChampion}
                year={settings.startYear}
                onContinue={onEndSeason}
            />
        );
    }

    switch(activeContentKey) {
        case 'race':
            if (raceState) return <LiveRaceView race={currentRace} raceState={raceState} drivers={drivers} teams={teams} commentary={commentary} isPaused={isPaused} settings={settings} customCountries={customCountries} />;
            return null;
        case 'pre-race':
            return <PreRaceStrategyScreen
                qualifyingResults={qualifyingResults!}
                drivers={drivers}
                teams={teams}
                race={currentRace}
                onStartRace={onStartRace}
                weather={determinedWeather!}
                onBack={handleBackFromStrategy}
            />;
        case 'qualifying':
            return <QualifyingInProgressScreen
                qualifyingData={qualifyingData}
                drivers={drivers}
                teams={teams}
            />;
        case 'idle':
        case 'finished':
        default:
             return renderIdleContent();
    }
  }

  return (
    <div className="flex flex-col h-full gap-6">
      {lastRaceResults && qualifyingResults && simulationStatus === 'finished' && (
        <RaceResultModal
          isOpen={isModalOpen}
          onClose={() => setIsModalOpen(false)}
          raceResults={lastRaceResults}
          qualifyingResults={qualifyingResults}
          race={calendar[currentRaceIndex - 1]}
          drivers={drivers}
          teams={teams}
          settings={settings}
          customCountries={customCountries}
        />
      )}

      <ProfileModal
          isOpen={!!selectedProfile}
          onClose={handleCloseProfile}
          profileId={selectedProfile?.id}
          profileType={selectedProfile?.type}
          drivers={drivers}
          teams={teams}
          onSelectProfile={handleOpenProfile}
          allRaceResults={allRaceResults}
          allQualifyingResults={allQualifyingResults}
          customCountries={customCountries}
      />

      <div className="flex-shrink-0 glass p-6 rounded-2xl flex flex-col md:flex-row justify-between items-center gap-6 shadow-2xl carbon-pattern border-l-4 border-l-red-600">
        <div className="flex items-center gap-6">
            {!seasonOver && currentRace && (
                <div className="relative">
                    <CountryFlag countryCode={currentRace.countryCode} customCountries={customCountries} className="w-16 h-12 rounded-lg object-cover shadow-xl grayscale-[0.5]" />
                    <div className="absolute -bottom-2 -right-2 bg-red-600 text-white font-black text-[10px] px-2 py-0.5 rounded italic">R{currentRaceIndex + 1}</div>
                </div>
            )}
            <div>
                <h2 className="text-[10px] font-black text-slate-500 uppercase tracking-[0.3em] mb-1 leading-none">
                   {seasonOver ? 'Championship Review' : 'Up Next'}
                </h2>
                <p className="text-2xl font-black text-white italic uppercase font-racing tracking-tight">
                    {seasonOver ? t('congratsChampions', { year: settings.startYear }) : currentRace?.name}
                </p>
                {!seasonOver && currentRace && (
                     <p className="text-[10px] font-black text-slate-400 mt-1 uppercase tracking-widest bg-white/5 inline-block px-2 py-0.5 rounded">
                        {currentRace.country} • {currentRace.laps} Laps • {currentRace.baseLapTime} Base
                     </p>
                )}
            </div>
        </div>
        <div className="flex items-center gap-4">
            {['qualifying', 'race'].includes(simulationStatus) && !isSeasonSimRunning && (
              <SpeedControl currentSpeed={simulationSpeed} onSpeedChange={onSetSimulationSpeed} isPaused={isPaused} onPauseToggle={onPauseToggle} />
            )}
            {['idle', 'finished'].includes(simulationStatus) && !podiumData && !championData && (
                <div className="flex items-center gap-3">
                    {!seasonOver && (
                      <>
                        <button onClick={onSaveSimulation} className="p-3 glass hover:bg-blue-600/20 text-blue-400 rounded-xl transition-all" title={t('save')}>
                            <FloppyDiskIcon className="w-5 h-5" />
                        </button>

                        <div className="h-10 w-px bg-white/10 mx-2"></div>

                        <div className="flex bg-black/40 p-1.5 rounded-xl border border-white/5">
                            <button 
                                onClick={onSimulateQualifying} 
                                disabled={isLoading} 
                                className="flex items-center gap-2 px-6 py-2 bg-red-600 text-white font-black text-xs uppercase rounded-lg hover:bg-red-500 disabled:bg-slate-800 disabled:text-slate-600 transition-all font-racing"
                            >
                                <StopwatchIcon className="w-4 h-4" /><span>{t('simulateQualifying')}</span>
                            </button>
                            <div className="w-px h-6 bg-white/10 mx-1.5 self-center"></div>
                            <button onClick={onSimulateWeekend} disabled={isLoading} className="p-2 text-slate-400 hover:text-white transition-all" title={t('simulateRaceWeek')}>
                                <PlayIcon className="w-5 h-5" />
                            </button>
                            <button onClick={onSimulateSeason} disabled={isLoading} className="p-2 text-slate-400 hover:text-white transition-all" title={t('simulateSeason')}>
                                <ForwardIcon className="w-5 h-5" />
                            </button>
                        </div>
                      </>
                    )}
                    <button onClick={onBackToMenu} className="p-3 glass hover:bg-white/10 text-slate-400 hover:text-white rounded-xl transition-all" title={t('backToMenu')}>
                        <HomeIcon className="w-5 h-5" />
                    </button>
                </div>
            )}
        </div>
      </div>

       {isSeasonSimRunning && (
        <div className="p-4 glass border-l-4 border-l-[#00ff85] flex items-center justify-between animate-fade-in rounded-xl flex-shrink-0">
          <div className="flex items-center gap-4">
            <SpinnerIcon className="w-5 h-5 text-[#00ff85]" />
            <div>
                <p className="text-[10px] font-black text-slate-500 uppercase tracking-widest">Season Simulation Active</p>
                <p className="text-sm font-black text-white italic uppercase font-racing">{currentRace?.name}</p>
            </div>
          </div>
          <button onClick={onStopSeasonSim} className="px-4 py-2 bg-red-600/10 text-red-500 font-black text-[10px] uppercase rounded-lg hover:bg-red-600 hover:text-white transition-all tracking-widest">{t('stop')}</button>
        </div>
       )}

       {error && (
        <div className="p-4 bg-red-950/40 border border-red-900 text-red-400 rounded-xl flex-shrink-0 animate-fade-in flex items-center gap-3">
          <ExclamationTriangleIcon className="w-5 h-5" />
          <p className="text-sm font-bold uppercase tracking-tight">{error}</p>
        </div>
      )}

      <div className={`flex-1 min-h-0 transition-all duration-300 ease-in-out ${isFading ? 'opacity-0 transform -translate-y-4' : 'opacity-100'}`}>
        {renderContent()}
      </div>

    </div>
  );
};

